INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('YTC_2015_consolidated', 'YTC', 2015, 'consolidated', 'Giao dịch với bên liên quan chủ yếu là lương thưởng cho ban lãnh đạo, không có giao dịch bất thường hay mua bán chênh lệch lớn.', 'Áp lực nợ vay ngắn hạn lớn với tổng nợ vay hơn 294 tỷ VNĐ, chủ yếu từ nhiều ngân hàng khác nhau. Khả năng thanh toán tức thời thấp (0.14 lần), cho thấy rủi ro thanh khoản cao. Tuy nhiên, công ty có khả năng tái tục các khoản vay.', 'Hàng tồn kho có dự phòng giảm giá 92.6 triệu VNĐ, cho thấy một phần hàng hóa có nguy cơ giảm giá, nhưng mức dự phòng không đáng kể so với tổng giá trị tồn kho. Dự án xây dựng dở dang đang triển khai, chưa có dấu hiệu ứ đọng.', 5, 'Công ty có doanh thu tăng trưởng (từ 454.6 tỷ năm 2014 lên 513.3 tỷ năm 2015) nhưng tỷ suất lợi nhuận sau thuế thấp (khoảng 2.3%). Nợ vay ngắn hạn cao, gây áp lực lên thanh khoản, nhưng dòng tiền từ hoạt động tài chính dương do vay mới lớn. Lợi nhuận sau thuế tăng từ 11.2 tỷ lên 11.8 tỷ VNĐ. Triển vọng trung bình, cần cải thiện quản lý nợ và nâng cao hiệu quả hoạt động.'),
('YSVN_2021_consolidated', 'YSVN', 2021, 'consolidated', 'Giao dịch với các bên liên quan chủ yếu là giao dịch dịch vụ chứng khoán bình thường và vay/trả vay với công ty mẹ. Không có giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Nợ vay ngắn hạn lớn (khoảng 1,960 tỷ VNĐ) nhưng chủ yếu bằng USD đã được phòng ngừa rủi ro tỷ giá. Tỷ lệ vốn khả dụng cao (1,074%) đảm bảo khả năng thanh toán. Công ty có tài sản thế chấp là tiền gửi có kỳ hạn cho khoản vay VNĐ.', 'Chi phí xây dựng cơ bản dở dang không lớn (khoảng 15.9 tỷ VNĐ), là đầu tư cho hệ thống và phần mềm, không có rủi ro ứ đọng hay dự án xây dựng dở dang.', 2, 'Công ty có kết quả kinh doanh tăng trưởng mạnh (lợi nhuận sau thuế tăng 186%), tỷ lệ vốn khả dụng cao, quản trị rủi ro tốt. Hoạt động kinh doanh chính (môi giới, cho vay ký quỹ) tăng trưởng ấn tượng. Tuy nhiên, phụ thuộc vào vốn vay ngắn hạn và biến động thị trường chứng khoán. Triển vọng tích cực.'),
('YSVN_2020_consolidated', 'YSVN', 2020, 'consolidated', 'Công ty có giao dịch với các bên liên quan trong tập đoàn Yuanta, bao gồm vay vốn từ công ty mẹ và mua bán chứng khoán với các công ty cùng tập đoàn. Các giao dịch này được thực hiện theo giá thị trường hoặc điều kiện thông thường, không có dấu hiệu bất thường rõ ràng. Tuy nhiên, việc phụ thuộc vào vay vốn từ công ty mẹ có thể tạo rủi ro nếu tập đoàn gặp khó khăn tài chính.', 'Nợ vay ngắn hạn chiếm tỷ trọng lớn trong tổng nợ (1.689 tỷ VND), chủ yếu phục vụ hoạt động cho vay ký quỹ. Có tài sản đảm bảo là chứng khoán ký quỹ (giá trị thị trường 7.795 tỷ VND), nhưng nếu thị trường suy giảm mạnh, giá trị tài sản đảm bảo có thể giảm, dẫn đến rủi ro. Công ty đã trích lập dự phòng 2,49 tỷ VND cho một khoản cho vay ký quỹ quá hạn.', 'Công ty không có hàng tồn kho vật chất. Chỉ có chi phí xây dựng cơ bản dở dang cho phần mềm và thiết bị (15,16 tỷ VND) đang trong quá trình hình thành tài sản, không có rủi ro tồn kho hay ứ đọng.', 3, 'Công ty TNHH Chứng khoán Yuanta Việt Nam có kết quả kinh doanh tăng trưởng mạnh năm 2020 với lợi nhuận sau thuế tăng gần 133% so với năm 2019, chủ yếu nhờ doanh thu phí môi giới tăng 46% và giảm chi phí thuế TNDN theo chính sách hỗ trợ COVID-19. Tỷ lệ an toàn tài chính cao (1.658% so với yêu cầu 180%). Cơ cấu vốn chủ sở hữu vững mạnh với vốn điều lệ 1.500 tỷ VND đã góp đủ. Tuy nhiên, công ty phụ thuộc lớn vào hoạt động cho vay ký quỹ và thị trường chứng khoán. Triển vọng đầu tư tích cực trong trung hạn nếu thị trường ổn định.'),
('YSVN_2023_consolidated', 'YSVN', 2023, 'consolidated', 'Công ty có giao dịch thương mại với nhiều công ty trong Tập đoàn Yuanta (Đài Loan), bao gồm môi giới mua/bán chứng khoán, tư vấn đầu tư, phí bảo lãnh, giao dịch phái sinh và chia sẻ chi phí phát triển ứng dụng. Giá trị giao dịch lớn nhất là môi giới bán chứng khoán với Yuanta HongKong (84.2 tỷ VND). Các giao dịch này mang tính chất thương mại thông thường trong hệ sinh thái tài chính Yuanta, không phát hiện dấu hiệu bất thường như cho vay không lãi suất hay mua bán chênh lệch giá bất thường. Tuy nhiên, công ty có sự phụ thuộc nhất định vào hệ sinh thái Tập đoàn Yuanta cho một phần doanh thu và chi phí công nghệ.', 'Nợ ngắn hạn chiếm tỷ trọng lớn (1,549 tỷ VND), trong đó vay USD từ ngân hàng nước ngoài chiếm 83% với lãi suất thả nổi 6-7.01%/năm. Công ty đã phòng ngừa rủi ro tỷ giá toàn bộ dư nợ USD bằng hợp đồng hoán đổi ngoại tệ với ngân hàng trong nước. Chi phí lãi vay tăng 45% so với năm trước (từ 59.6 tỷ lên 86.3 tỷ VND) phản ánh mặt bằng lãi suất tăng trên thị trường. Tỷ lệ nợ vay/vốn chủ sở hữu ở mức 0.52, trong tầm kiểm soát. Giá trị thị trường tài sản đảm bảo cho cho vay ký quỹ đạt 10,695 tỷ VND, tỷ lệ bao phủ nợ cho vay ký quỹ đạt ~3.5 lần.', 'Công ty là công ty chứng khoán, không có hàng tồn kho truyền thống (nguyên vật liệu, thành phẩm, bất động sản). Chi phí xây dựng cơ bản dở dang chỉ 404 triệu VND (0.01% tổng tài sản), chủ yếu cho dự án phần mềm vi tính, giá trị không đáng kể và không có rủi ro ứ đọng.', 3, 'Công ty TNHH Chứng khoán Yuanta Việt Nam là công ty con (94.1% vốn) của Yuanta Securities Asia Financial Services thuộc Tập đoàn Tài chính Yuanta (Đài Loan). Công ty có vị thế tài chính vững mạnh với vốn điều lệ 2,500 tỷ VND, tổng vốn chủ sở hữu 3,001 tỷ VND và tỷ lệ vốn khả dụng đạt 1,155% (cao gấp 6.4 lần yêu cầu tối thiểu 180% theo Thông tư 91/2020/TT-BTC). Lợi nhuận sau thuế đạt 120.9 tỷ VND, giảm nhẹ 5% so với năm trước do ảnh hưởng tiêu cực của thị trường chứng khoán suy giảm. Doanh thu phí môi giới giảm 22%, doanh thu cho vay ký quỹ giảm 21%, trong khi chi phí lãi vay tăng 45%. Công ty duy trì biên lợi nhuận hoạt động tốt (~50%) và dự phòng suy giảm cho vay ký quỹ chỉ 2.5 tỷ VND trên dư nợ 3,056 tỷ VND cho thấy chất lượng tín dụng tốt. Rủi ro chính là sự phụ thuộc vào diễn biến thị trường chứng khoán và xu hướng lãi suất.'),
('YSVN_2019_consolidated', 'YSVN', 2019, 'consolidated', 'Các giao dịch với bên liên quan bao gồm vay vốn từ công ty mẹ và giao dịch chứng khoán với các công ty cùng tập đoàn. Các giao dịch này được thực hiện theo điều kiện thị trường và không có dấu hiệu bất thường.', 'Nợ vay ngắn hạn tăng mạnh từ 459 tỷ lên 925 tỷ VND,主要用于 hoạt động cho vay ký quỹ. Công ty có tài sản đảm bảo là chứng khoán, nhưng áp lực trả nợ cao do nợ ngắn hạn chiếm tỷ trọng lớn.', 'Công ty chỉ có chi phí xây dựng cơ bản dở dang cho cải tạo văn phòng và phần mềm, rủi ro thấp.', 3, 'Công ty có kết quả kinh doanh tích cực năm 2019 với lợi nhuận sau thuế tăng mạnh. Tuy nhiên, nợ vay tăng cao và phụ thuộc vào ngắn hạn có thể gây rủi ro thanh khoản. Triển vọng phụ thuộc vào thị trường chứng khoán và hiệu quả quản lý rủi ro.'),
('YTC_2024_consolidated', 'YTC', 2024, 'consolidated', 'Công ty có mạng lưới giao dịch phức tạp với nhiều bên liên quan thuộc hệ sinh thái Sài Gòn 3 Group. Đáng lưu ý: (1) Khoản vay ngắn hạn 11,6 tỷ VNĐ từ Công ty TNHH Đầu tư Sài Gòn 3 Capital (công ty con của cổ đông lớn Sài Gòn 3 Group); (2) Nhận góp vốn hơn 69,5 tỷ VNĐ từ các bên liên quan (Sài Gòn 3 Capital, Dược Sài Gòn, Quản lý quỹ Thành Công); (3) Khoản phải thu lớn từ Công ty CP Dược phẩm Duy Tân (hơn 32 tỷ VNĐ phí ủy thác và lãi trả chậm) đã quá hạn nhiều năm, Công ty đã khởi kiện và thắng kiện nhưng Duy Tân đề nghị khoanh nợ, chưa có khả năng thanh toán khoản lãi phạt bổ sung 25,4 tỷ VNĐ; (4) Ban Tổng Giám đốc tạm ứng hơn 14,4 tỷ VNĐ; (5) Công ty TNHH Venus HCMC nhận khoản vay 5 tỷ VNĐ với lãi suất 9-9,5%/năm.', 'Áp lực nợ vay đã giảm đáng kể. Nợ ngắn hạn giảm từ 175,1 tỷ VNĐ xuống 127,4 tỷ VNĐ. Nợ dài hạn đã trả hết (từ 27,6 tỷ VNĐ về 0). Dòng tiền kinh doanh dương 22,5 tỷ VNĐ đủ để trang trải. Tài sản thế chấp bao gồm tiền gửi có kỳ hạn, quyền đòi nợ luân chuyển, hàng tồn kho và tài sản cố định. Tuy nhiên, chi phí lãi vay vẫn ở mức 10,2 tỷ VNĐ/năm và tỷ lệ nợ ngắn hạn/tổng tài sản vẫn ở mức 12,4%.', 'Hàng tồn kho tăng mạnh từ 75,9 tỷ VNĐ lên 106,7 tỷ VNĐ (tăng 40,7%). Dự phòng giảm giá hàng tồn kho tăng từ 1,4 tỷ lên 3,7 tỷ VNĐ, cho thấy một phần hàng hóa có nguy cơ giảm giá trị. Dự án xây dựng dở dang tại 181 Nguyễn Đình Chiều tăng từ 15,9 tỷ lên 88,7 tỷ VNĐ - mức đầu tư lớn cần theo dõi tiến độ và hiệu quả. Hàng tồn kho và quyền đòi nợ đã được thế chấp cho các khoản vay.', 6, 'Công ty YTC có sự phục hồi tích cực trong năm 2024 với doanh thu thuần đạt 693,6 tỷ VNĐ (tăng 24,6%) và lợi nhuận sau thuế 9,6 tỷ VNĐ (tăng 46,3%). Công ty đã tăng vốn thành công lên 95,48 tỷ VNĐ và trả hết nợ dài hạn, giảm mạnh nợ ngắn hạn. Tuy nhiên, tồn tại một số rủi ro: (1) Mạng lưới giao dịch phức tạp với hệ sinh thái Sài Gòn 3 Group; (2) Khoản phải thu khó đòi lớn từ Công ty CP Dược phẩm Duy Tân; (3) Dự án xây dựng lớn 88,7 tỷ VNĐ cần giám sát; (4) Hàng tồn kho tăng mạnh; (5) Biên lợi nhuận gộp còn mỏng (12,7%). Công ty có triển vọng tích cực về ngắn hạn nhờ tăng vốn và giảm đòn bẩy tài chính, nhưng cần theo dõi sát các khoản phải thu và hiệu quả dự án xây dựng.'),
('YSVN_2025_consolidated', 'YSVN', 2025, 'consolidated', 'Công ty có các giao dịch với các bên liên quan trong tập đoàn Yuanta bao gồm môi giới chứng khoán, tư vấn tài chính, tư vấn đầu tư, phí bảo lãnh, giao dịch phái sinh và chi phí phát triển ứng dụng. Các giao dịch này mang tính chất nghiệp vụ thông thường của công ty chứng khoán và được thực hiện theo giá thị trường. Không phát hiện giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn. Tổng giá trị giao dịch môi giới với Yuanta Securities (Thailand) ở mức lớn (hơn 2.017 tỷ VNĐ mua/bán), phản ánh mối quan hệ kinh doanh mật thiết trong tập đoàn. Các giao dịch với công ty mẹ (Yuanta Securities Asia Financial Services) chỉ giới hạn ở phí bảo lãnh (212 tỷ VNĐ). Nhìn chung, rủi ro giao dịch bên liên quan ở mức thấp do tính minh bạch và quy mô giao dịch hợp lý.', 'Công ty có tổng nợ vay ngắn hạn 3.093 tỷ VNĐ, tăng 42% so với năm trước (2.177 tỷ VNĐ), chủ yếu phục vụ cho hoạt động cho vay ký quỹ. Toàn bộ nợ vay là ngắn hạn, tạo rủi ro tái cấp vốn đáng kể. Chi phí lãi vay tăng 22% lên 145,8 tỷ VNĐ. Công ty vay bằng cả VNĐ và USD (77 triệu USD), đã phòng ngừa rủi ro tỷ giá bằng hợp đồng hoán đổi ngoại tệ. Tỷ lệ nợ/vốn chủ sở hữu đạt 0,95. Tuy nhiên, biên lãi từ hoạt động cho vay ký quỹ vẫn dương (lãi cho vay 441 tỷ VNĐ so với chi phí lãi vay 146 tỷ VNĐ), cho thấy mô hình kinh doanh hiệu quả. Tài sản đảm bảo cho vay ký quỹ đạt 16.745 tỷ VNĐ, gấp hơn 3 lần dư nợ. Tỷ lệ vốn khả dụng đạt 1.368%,远远超过 yêu cầu tối thiểu 180%. Công ty có khoản vay quá hạn nhỏ (2,49 tỷ VNĐ) đã trích lập đủ dự phòng.', 'Là công ty chứng khoán, Công ty không có hàng tồn kho truyền thống (nguyên vật liệu, thành phẩm). Chi phí xây dựng cơ bản dở dang (phần mềm vi tính trị giá 362,55 triệu VNĐ tại cuối năm 2024) đã hoàn thành và chuyển giao trong năm 2025, số dư cuối năm bằng 0. Rủi ro chính liên quan đến tài sản là rủi ro từ các khoản cho vay ký quỹ (5.313 tỷ VNĐ), trong đó có 2,49 tỷ VNĐ quá hạn và đã trích lập dự phòng đầy đủ. Tổng tài sản đảm bảo cho cho vay ký quỹ đạt 16.745 tỷ VNĐ, gấp 3,15 lần dư nợ, đảm bảo mức độ an toàn cao cho các khoản cho vay.', 2, 'Công ty TNHH Chứng khoán Yuanta Việt Nam hoạt động dưới sự kiểm soát của Yuanta Financial Holding (Đài Loan) - một tập đoàn tài chính lớn. Kết quả kinh doanh 2025 tăng trưởng tích cực: lợi nhuận sau thuế đạt 125,6 tỷ VNĐ (tăng 2,7%), doanh thu phí môi giới tăng 20%, doanh thu cho vay ký quỹ tăng 14%. Công ty duy trì tỷ lệ an toàn tài chính vượt trội (1.368%, yêu cầu tối thiểu 180%). Vốn điều lệ 2.500 tỷ VNĐ đã góp đủ. Tuy nhiên, nợ ngắn hạn tăng mạnh 42% và chi phí lãi vay tăng 22% cần được theo dõi trong bối cảnh lãi suất biến động. Công ty có cơ cấu cổ đông rõ ràng (Yuanta Asia 94,1%, Yuanta HongKong 5,9%), hệ thống quản trị minh bạch với đầy đủ HĐTV, Ban Kiểm soát và Ban Tổng Giám đốc. Triển vọng tăng trưởng tích cực cùng sự phục hồi của thị trường chứng khoán Việt Nam.'),
('YTC_2023_consolidated', 'YTC', 2023, 'consolidated', 'Doanh nghiệp có mạng lưới giao dịch bên liên quan phức tạp với nhiều công ty liên kết qua thành viên Hội đồng quản trị và cổ đông lớn. Đáng chú ý: (1) Cho vay dài hạn 27,6 tỷ VND từ Công ty TNHH Đầu tư Sài Gòn 3 Capital (cổ đông 19,83%) để tài trợ dự án bất động sản với lãi suất ''quy định từng thời điểm'' - không rõ ràng; (2) Mua hàng hóa trị giá 4,6 tỷ VND từ Công ty TNHH MTV Dược Sài Gòn (cổ đông 29%); (3) Giao dịch mua bán với Công ty Cổ phần Bông Bạch Tuyết (cùng thành viên HĐQT); (4) Chủ tịch HĐQT Nguyễn Khánh Linh kiêm Chủ tịch Công ty TNHH Bạch Tuyết Kotton. Mặc dù chưa phát hiện giao dịch bất thường rõ ràng, mức độ liên kết chồng chéo đòi hỏi sự giám sát chặt chẽ.', 'Áp lực nợ vay rất lớn: Tổng nợ phải trả chiếm 95,8% tổng tài sản (901 tỷ/940 tỷ VND), vốn chủ sở hữu chỉ 39 tỷ VND. Nợ ngắn hạn chiếm 873,5 tỷ VND, phần lớn là vay ngân hàng với hạn mức ngắn (06-09 tháng) đòi hỏi liên tục đáo hạn và tái tục. Tài sản thế chấp bao gồm tiền gửi có kỳ hạn, quyền đòi nợ luân chuyển, hàng tồn kho và tài sản cố định. Công ty cũng nhận bảo lãnh từ Sài Gòn 3 Group và Sài Gòn 3 Capital cho khoản vay tại Vietcombank. Chi phí lãi vay năm nay là 15,65 tỷ VND. Dù công ty khẳng định có khả năng trả nợ, tỷ lệ đòn bẩy tài chính cực cao tạo rủi ro đáng kể.', 'Hàng tồn kho giảm từ 105,2 tỷ xuống 77,3 tỷ VND (giảm 26,5%), cho thấy tốc độ quay vòng hàng hóa tốt. Dự phòng giảm giá hàng tồn kho ở mức 1,45 tỷ VND (tương đương 1,9% giá trị tồn kho), đã giảm so với đầu năm. Hàng tồn kho chủ yếu là dược phẩm và thiết bị y tế - mặt hàng có nhu cầu ổn định. Dự án xây dựng dở dang 181 Nguyễn Đình Chiều tăng mạnh từ 3,7 tỷ lên 15,9 tỷ VND, đang trong giai đoạn đầu tư tích cực. Rủi ro tồn kho ở mức trung bình.', 6, 'Công ty CP Xuất nhập khẩu Y tế TP.HCM (YTC) hoạt động trong lĩnh vực phân phối dược phẩm và thiết bị y tế có nhu cầu ổn định. Năm 2023, doanh thu thuần giảm 18,2% xuống 556,4 tỷ VND, lợi nhuận sau thuế giảm mạnh 79,5% xuống 6,57 tỷ VND chủ yếu do chi phí bán hàng tăng 32,6% và giảm trừ doanh thu cao. Điểm đáng lo ngại nhất là tỷ lệ đòn bẩy tài chính cực kỳ cao (nợ phải trả/tổng tài sản = 95,8%), kết hợp với mạng lưới giao dịch bên liên quan phức tạp xoay quanh nhóm Sài Gòn 3. Công ty có kế hoạch chào bán 6,468 triệu cổ phiếu ra công chúng (tăng hơn gấp đôi số cổ phiếu hiện tại) để tăng vốn chủ sở hữu, đây là tín hiệu tích cực nhằm giảm đòn bẩy tài chính. Tuy nhiên, nhà đầu tư cần theo dõi sát tiến độ tăng vốn và hiệu quả quản lý dòng tiền trong bối cảnh áp lực nợ vay lớn.'),
('YTC_2021_consolidated', 'YTC', 2021, 'consolidated', 'Công ty có nhiều giao dịch với bên liên quan bao gồm cổ đông lớn (Công ty TNHH MTV Dược Sài Gòn 29%, Công ty TNHH Đầu tư Sài Gòn 3 Capital 19.83%). Đáng chú ý: (1) Công ty vay 6.5 tỷ VNĐ từ Sài Gòn 3 Capital (cổ đông 19.83%) không có tài sản đảm bảo, lãi suất 7.4%/năm - mức lãi suất ưu đãi so với thị trường; (2) Tổng Giám đốc Phan Minh Trung có khoản tạm ứng cá nhân 1.52 tỷ VNĐ; (3) Có giao dịch mua bán hàng hóa với Công ty CP Dược phẩm Quận 3 và Công ty CP Bông Bạch Tuyết (cùng Chủ tịch HĐQT). Tuy nhiên, giá giao dịch được ghi nhận là ''giá thỏa thuận'' và khối lượng giao dịch không quá lớn so với tổng doanh thu.', 'Tổng nợ vay ngắn hạn 219.5 tỷ VNĐ và nợ dài hạn 782 triệu VNĐ. Áp lực nợ vay đáng kể với phần lớn là vay ngắn hạn (thời hạn tối đa 6-9 tháng), yêu cầu xoay vòng vốn liên tục. Phần lớn khoản vay được đảm bảo bằng tiền gửi có kỳ hạn, quyền đòi nợ luân chuyển, hàng tồn kho và tài sản cố định. Công ty không có nợ quá hạn. Chi phí lãi vay trong năm là 15.2 tỷ VNĐ (giảm từ 23.8 tỷ năm trước). Dòng tiền từ hoạt động kinh doanh dương 3.76 tỷ VNĐ (cải thiện mạnh từ -42.8 tỷ năm trước). Công ty có nợ tiềm tàng về thuế nhà thầu đang khiếu nại.', 'Hàng tồn kho giảm từ 152.9 tỷ xuống 125.5 tỷ VNĐ (giá gốc), dự phòng giảm giá 3.7 tỷ VNĐ. Hàng tồn kho chủ yếu là hàng hóa dược phẩm và trang thiết bị y tế - ngành có nhu cầu ổn định. Hàng tồn kho luân chuyển đã được dùng làm tài sản đảm bảo cho vay ngân hàng. Chi phí xây dựng cơ bản dở dang tăng mạnh từ 358 triệu lên 2.74 tỷ VNĐ do đầu tư xây dựng công trình tại trụ sở chính và các công trình khác. Dự án xây dựng có tỷ trọng nhỏ trong tổng tài sản, rủi ro thấp.', 6, 'Công ty CP Xuất nhập khẩu Y tế TP.HCM (YTECO) có kết quả kinh doanh phục hồi mạnh năm 2021 với lợi nhuận sau thuế 10.66 tỷ VNĐ (so với lỗ 12.01 tỷ năm 2020). Doanh thu thuần ổn định 604.3 tỷ VNĐ với biên lợi nhuận gộp 8.7%. Công ty nhận được ý kiến kiểm toán ngoại trừ do: (1) một số khoản công nợ chưa được kiểm tra, đối chiếu đầy đủ; (2) khoản nợ tiềm tàng về tiền thuê đất bổ sung 14.45 tỷ VNĐ chưa ghi nhận chi phí. Công ty đang khiếu nại Cục thuế. Nợ vay chủ yếu ngắn hạn đòi hỏi quản lý dòng tiền chặt chẽ. Ban lãnh đạo đã thay đổi đáng kể trong năm 2021 với nhiều nhân sự mới. Công ty có mối quan hệ với nhiều bên liên quan, bao gồm cả cổ đông lớn và Chủ tịch HĐQT, nhưng quy mô giao dịch ở mức hợp lý.'),
('YTC_2020_consolidated', 'YTC', 2020, 'consolidated', 'Công ty có phát sinh giao dịch với các bên liên quan gồm Công ty Cổ phần Dược phẩm Quận 3 (công ty có liên quan với thành viên HĐQT) với doanh số bán 30,3 tỷ VND trong năm 2020, bao gồm chiết khấu thương mại 3,46 tỷ VND và hàng bán bị trả lại 336 triệu VND. Công ty cũng mua hàng từ Công ty TNHH MTV Dược Sài Gòn (cổ đông 29% vốn) với giá trị 390 triệu VND và từ Công ty Cổ phần Bông Bạch Tuyết (cùng Chủ tịch HĐQT) với giá trị 108 triệu VND. Các giao dịch này được thực hiện theo giá thỏa thuận, tuy nhiên cần lưu ý về tính độc lập của các giao dịch do mối quan hệ liên kết. Nợ phải thu từ Công ty Cổ phần Dược phẩm Quận 3 là 25,7 tỷ VND (tăng so với năm trước 22,9 tỷ VND), trong đó có 18,9 tỷ VND là nợ quá hạn từ 1-3 năm.', 'Tổng nợ phải trả của Công ty là 982 tỷ VND, chiếm 98,6% tổng tài sản (995,5 tỷ VND). Nợ ngắn hạn chiếm phần lớn (980,8 tỷ VND). Công ty có nhiều khoản vay ngân hàng ngắn hạn từ nhiều ngân hàng khác nhau với tổng giá trị 221,6 tỷ VND. Đáng chú ý, một số khoản nợ phải trả khác đang trong quá trình kiểm tra, đối chiếu với giá trị 45,7 tỷ VND (upas L/C), 264,2 tỷ VND (ứng trước hàng ủy thác). Công ty đã thế chấp nhiều tài sản bao gồm tiền gửi có kỳ hạn, quyền đòi nợ luân chuyển và hàng tồn kho luân chuyển cho các khoản vay. Nợ ngắn hạn vượt tài sản ngắn hạn 41,8 tỷ VND cho thấy áp lực thanh toán rất lớn. Công ty vẫn khẳng định có khả năng trả được các khoản vay ngắn hạn và nợ thuê tài chính dài hạn.', 'Tổng hàng tồn kho cuối năm 2020 là 152,9 tỷ VND (tăng 49% so với đầu năm 102,6 tỷ VND). Dự phòng giảm giá hàng tồn kho tăng mạnh từ 1,37 tỷ VND lên 4,12 tỷ VND do trích lập bổ sung 2,75 tỷ VND. Hàng hóa chủ yếu là dược phẩm và trang thiết bị y tế. Việc hàng tồn kho tăng mạnh trong khi doanh thu giảm và hàng bán bị trả lại tăng (38,6 tỷ VND năm 2020 so với 7,6 tỷ VND năm 2019) cho thấy rủi ro ứ đọng hàng hóa. Một phần hàng tồn kho đã được thế chấp cho các khoản vay ngân hàng.', 8, 'Công ty Xuất nhập khẩu Y tế TP.HCM (YTECO) đang trong tình trạng tài chính khó khăn nghiêm trọng với khoản lỗ lũy kế 40,1 tỷ VND và nợ ngắn hạn vượt tài sản ngắn hạn 41,8 tỷ VND. Kiểm toán viên đã đưa ra ý kiến kiểm toán ngoại trừ do nhiều khoản công nợ chưa được kiểm tra, đối chiếu (tổng giá trị trên 167 tỷ VND). Công ty có sự thay đổi lớn trong ban lãnh đạo năm 2020 với nhiều vị trí chủ chốt được bổ nhiệm mới. Tuy nhiên, một số điểm tích cực bao gồm: doanh thu thuần tăng 17,4% (566 tỷ VND so với 482 tỷ VND), tỷ lệ lợi nhuận gộp vẫn dương (8,6%), và công ty đang triển khai các phương án thu hồi nợ, tái cơ cấu hoạt động. Hội đồng quản trị đang xem xét tăng vốn điều lệ và thương lượng gia hạn nợ vay. Rủi ro hoạt động liên tục là trọng yếu nhưng công ty vẫn lập BCTC trên cơ sở giả định hoạt động liên tục.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('YTC_2018_consolidated', 'YTC', 2018, 'consolidated', 'Giao dịch với bên liên quan chủ yếu là thù lao cho Ban Tổng Giám đốc, HĐQT và Ban Kiểm soát, không có giao dịch mua bán, vay mượn hay đầu tư bất thường với các bên liên quan được trình bày chi tiết. Rủi ro liên quan thấp.', 'Áp lực nợ vay là rất lớn với tỷ lệ nợ phải trả trên tổng nguồn vốn là 92.6% (cuối năm 2018). Công ty chủ yếu vay ngắn hạn (trên 344 tỷ VNĐ) từ nhiều ngân hàng để bổ sung vốn kinh doanh luân chuyển. Các khoản vay này thường được đảm bảo bằng quyền đòi nợ luân chuyển và hàng tồn kho luân chuyển, một khoản vay dài hạn để xây dựng kho được đảm bảo bằng chính tài sản hình thành từ vốn vay. Công ty cho rằng rủi ro tập trung trả nợ là thấp và có thể tái tục các khoản vay đáo hạn.', 'Hàng tồn kho chủ yếu là hàng hóa mua bán (dược phẩm, thiết bị y tế) với giá trị lớn (trên 103 tỷ VNĐ), đã trích lập dự phòng giảm giá gần 1.23 tỷ VNĐ. Hàng hóa này được dùng để đảm bảo cho các khoản vay. Có một số dự án xây dựng dở dang (như kho Thủ Đức, nhà 76 Sương Nguyệt Ánh) với giá trị không lớn. Rủi ro tồn kho ở mức trung bình, tập trung vào khả năng tiêu thụ hàng hóa mua bán.', 4, 'Công ty có kết quả kinh doanh tăng trưởng tốt (doanh thu thuần tăng 7%, lợi nhuận sau thuế tăng 7.3%), nhưng sử dụng đòn bẩy tài chính rất cao (hơn 92% là nợ vay). Dòng tiền từ hoạt động kinh doanh năm 2018 bị âm (-32.8 tỷ) do tăng mạnh các khoản phải thu và giảm hàng tồn kho. Công ty có đủ tài sản ngắn hạn để thanh toán nợ ngắn hạn (hệ số thanh toán hiện hành 1.04). Tuy nhiên, việc phụ thuộc lớn vào nợ vay ngân hàng ngắn hạn là một rủi ro tiềm ẩn. Triển vọng phụ thuộc vào hiệu quả quản lý vốn lưu động và duy trì mối quan hệ với các ngân hàng cho vay.'),
('YTC_2017_consolidated', 'YTC', 2017, 'consolidated', 'Giao dịch với bên liên quan chủ yếu là lương thưởng cho ban lãnh đạo, không có giao dịch bất thường lớn như cho vay không lãi suất hay mua bán chênh lệch.', 'Tỷ lệ nợ phải trả/tổng nguồn vốn đạt 93%, áp lực nợ vay cao. Nợ ngắn hạn chiếm phần lớn, khả năng thanh toán tức thời thấp (0.15 lần). Công ty có tài sản thế chấp là ô tô, hàng tồn kho và quyền đổi nợ.', 'Hàng tồn kho giảm so với đầu năm, có trích lập dự phòng giảm giá. Dự án xây dựng cơ bản dở dang đã giảm mạnh từ 34 tỷ xuống còn 2.9 tỷ, cho thấy tiến độ triển khai.', 4, 'Công ty có biên lợi nhuận gộp ổn định khoảng 16.6%, nhưng áp lực nợ vay lớn với tỷ lệ đòn bẩy cao. Tuy nhiên, Công ty có dòng tiền hoạt động kinh doanh dương và khả năng tiếp tục hoạt động. Triển vọng phụ thuộc vào khả năng quản lý nợ và duy trì doanh thu.'),
('YTC_2025_consolidated', 'YTC', 2025, 'consolidated', 'Công ty có nhiều giao dịch với bên liên quan, đáng chú ý nhất là khoản vay dài hạn 31,2 tỷ VND từ Công ty TNHH Đầu tư Sài Gòn 3 Capital (công ty liên quan qua cổ đông lớn SGI Holdings) với lãi suất thị trường. Tổng Giám đốc có khoản tạm ứng lớn 16,79 tỷ VND. Có khoản phải thu cuối kỳ 1,14 tỷ VND từ các bên liên quan. Các giao dịch bán hàng cho bên liên quan khoảng 2,5 tỷ VND theo giá thỏa thuận. Có thành viên Ban kiểm soát kiêm nhiệm ở nhiều công ty liên quan.', 'Tổng nợ vay tăng mạnh 67,7% so với đầu năm (từ 144,6 tỷ lên 244,8 tỷ VND). Nợ ngắn hạn chiếm tỷ trọng lớn (87,2% tổng nợ vay). Lãi suất vay ngắn hạn dao động 4,8%-7,3%/năm. Công ty đã thế chấp quyền sử dụng đất, TSCĐ (29,6 tỷ VND), tiền gửi có kỳ hạn (51,2 tỷ VND) tại 4 ngân hàng, quyền đòi nợ lưu chuyển và hàng hóa lưu chuyển. Khoản vay dài hạn 31,2 tỷ VND từ Công ty TNHH Đầu tư Sài Gòn 3 Capital đáo hạn năm 2035.', 'Tổng hàng tồn kho tăng 10,6% so với đầu năm (từ 110,4 tỷ lên 122,2 tỷ VND). Dự phòng giảm giá hàng tồn kho tăng mạnh 161% (từ 3,7 tỷ lên 9,7 tỷ VND), tỷ lệ dự phòng/giá gốc hàng hóa tăng từ 4,1% lên 10%. Hàng hóa lưu chuyển đã được thế chấp tại ngân hàng. Dự án xây dựng dở dang chỉ còn 630 triệu VND (giảm 99,3%) do tòa nhà 181 Nguyễn Đình Chiều đã hoàn thành và chuyển sang bất động sản đầu tư cho thuê.', 5, 'Công ty có nền tảng kinh doanh dược phẩm, trang thiết bị y tế vững chắc với tăng trưởng doanh thu thuần 32% và lợi nhuận sau thuế 33% trong năm 2025. Tỷ suất lợi nhuận gộp đạt 11,35%. BĐS đầu tư (tòa nhà văn phòng và kho 181 Nguyễn Đình Chiều, giá trị 153,7 tỷ VND) đã hoàn thành và bắt đầu cho thuê nhưng chưa tạo ra lợi nhuận (chi phí khấu hao vượt thu nhập cho thuê). Áp lực nợ vay tăng 67,7% so với đầu năm nhưng vẫn trong tầm kiểm soát. Rủi ro chính: (1) khoản phải thu lớn từ Công ty Dược phẩm Duy Tân đang trong quá trình kiện tụng với khả năng thu hồi thấp; (2) dự phòng giảm giá hàng tồn kho tăng mạnh; (3) nhiều giao dịch với bên liên quan. Công ty có dòng tiền từ hoạt động kinh doanh âm (-33 tỷ VND) do tăng trưởng nhanh về quy mô.'),
('YTC_2016_consolidated', 'YTC', 2016, 'consolidated', 'Không có giao dịch bất thường với các bên liên quan. Chỉ có thu nhập từ tiền lương và thù lao cho ban lãnh đạo, không có giao dịch mua bán, cho vay hay đầu tư đáng ngờ.', 'Nợ vay cao với tỷ lệ nợ trên vốn chủ sở hữu là 91%, chủ yếu là nợ ngắn hạn (277 tỷ VND). Công ty có áp lực thanh toán lớn, nhưng có tài sản thế chấp như xe ô tô, quyền đòi nợ và hàng tồn kho. Khả năng thanh toán hiện hành 1.06 lần, vừa đủ.', 'Hàng tồn kho chủ yếu là hàng hóa với dự phòng giảm giá nhỏ (453 triệu VND). Dự án xây dựng cơ bản dở dang có giá trị 34 tỷ VND, không có dấu hiệu ứ đọng lớn.', 5, 'Công ty hoạt động trong lĩnh vực dược phẩm và thiết bị y tế, doanh thu ổn định trên 530 tỷ VND, lợi nhuận gộp khoảng 16%. Tuy nhiên, cơ cấu vốn bất lợi với nợ vay cao, chủ yếu nợ ngắn hạn, tạo áp lực tài chính. Dòng tiền từ hoạt động kinh doanh dương, nhưng đầu tư lớn vào tài sản dài hạn. Triển vọng phụ thuộc vào quản lý nợ, luân chuyển hàng tồn kho và thị trường y tế.'),
('YEG_2025_consolidated', 'YEG', 2025, 'consolidated', 'Doanh nghiệp có nhiều giao dịch với bên liên quan, đặc biệt là cho vay và vay với lãi suất cao (ví dụ 14%/năm từ Encapital Holdings). Các giao dịch này có thể tiềm ẩn rủi ro lợi ích và cần được giám sát chặt chẽ để tránh xung đột lợi ích hoặc dòng tiền không minh bạch.', 'Tổng nợ vay lớn (khoảng 341 tỷ VNĐ), áp lực trả nợ ngắn hạn cao với nhiều khoản vay đáo hạn trong năm 2026. Công ty có tài sản thế chấp chủ yếu là quyền sử dụng đất và tiền gửi, nhưng biên lợi nhuận gộp giảm có thể ảnh hưởng đến khả năng thanh toán.', 'Hàng tồn kho dở dang tăng mạnh từ 40 tỷ lên 97 tỷ VNĐ, chủ yếu do chi phí chương trình truyền hình đang sản xuất. Điều này cho thấy rủi ro ứ đọng vốn và khả năng chậm tiến độ hoặc hiệu quả sản xuất không đạt kỳ vọng.', 8, 'Sức khỏe tài chính của Tập đoàn Yeah1 đang đối mặt với nhiều thách thức: lợi nhuận sau thuế giảm 36,86% do biên lợi nhuận quảng cáo sụt giảm và chi phí đầu tư tăng. Nợ vay lớn và giao dịch bên liên quan phức tạp đặt ra rủi ro về quản trị. Tuy nhiên, công ty có doanh thu tăng mạnh và đang tái cơ cấu danh mục đầu tư. Triển vọng phụ thuộc vào khả năng cải thiện biên lợi nhuận và quản lý dòng tiền hiệu quả.'),
('YEG_2025_parent', 'YEG', 2025, 'parent', 'Doanh nghiệp có mạng lưới giao dịch bên liên quan phức tạp với các công ty con và liên kết, bao gồm cho vay, nhận vay, mua bán dịch vụ và bản quyền. Các khoản vay cho bên liên quan thường là tín chấp với lãi suất từ 8-10.5%/năm, cho thấy có ưu đãi hoặc rủi ro tín dụng. Giá trị giao dịch rất lớn, đặc biệt với 1Production và Y1N, đòi hỏi sự kiểm soát nội bộ chặt chẽ để tránh lạm dụng.', 'Công ty có nợ vay ngân hàng cả ngắn và dài hạn, phần lớn được thế chấp bằng quyền sử dụng đất và tiền gửi ngân hàng, cho thấy áp lực tài sản đảm bảo. Ngoài ra, còn vay từ các công ty con/liên kết. Tổng nợ phải trả giảm so với đầu năm nhưng vẫn ở mức đáng kể. Áp lực trả nợ ngắn hạn tồn tại với các khoản vay đáo hạn trong 2026.', 'Hàng tồn kho chủ yếu là chi phí sản xuất chương trình dở dang (trị giá lớn ~69 tỷ VND), là tài sản đặc thù trong ngành truyền thông. Rủi ro nằm ở việc các chương trình này có thể không bán được hoặc bị ứ đọng nếu thị hiếu khán giả thay đổi. Tuy nhiên, đây là hoạt động kinh doanh chính nên được coi là rủi ro kinh doanh bình thường.', 7, 'Công ty có kết quả kinh doanh riêng lỗ nặng năm 2025 (-141.7 tỷ VND) do chi phí tài chính lớn từ thoái vốn Giga1. Dù vậy, dòng tiền hoạt động kinh doanh vẫn dương (170.6 tỷ VND) và công ty đã phát hành thêm cổ phiếu tăng vốn mạnh. Nợ vay có tài sản đảm bảo nhưng áp lực thanh toán ngắn hạn vẫn tồn tại. Mạng lưới giao dịch bên liên quan phức tạp là rủi ro quản trị chính. Triển vọng phụ thuộc vào khả năng cải thiện biên lợi nhuận quảng cáo và quản lý hiệu quả chi phí đầu tư vào nội dung và người dùng.'),
('YEG_2024_consolidated', 'YEG', 2024, 'consolidated', 'Doanh nghiệp có nhiều giao dịch với các bên liên quan, bao gồm cho vay, mua bán dịch vụ và bản quyền. Một số khoản cho vay không lãi suất hoặc lãi suất thấp, có thể tiềm ẩn rủi ro xung đột lợi ích. Giao dịch với các công ty có liên quan đến ban lãnh đạo diễn ra phức tạp, cần giám sát chặt chẽ.', 'Áp lực nợ vay ngắn hạn cao với tỷ lệ nợ vay trên vốn chủ sở hữu lớn. Một số khoản vay đã quá hạn thanh toán, gây rủi ro thanh khoản. Công ty dựa nhiều vào vay tín chấp và thế chấp bằng tài sản của bên thứ ba, tăng rủi ro tài chính.', 'Hàng tồn kho bao gồm chương trình và dự án đang sản xuất dở dang, có nguy cơ bị ứ đọng hoặc vượt quá chi phí. Tuy nhiên, không có dự phòng giảm giá hàng tồn kho cuối kỳ, cho thấy có thể đánh giá lại giá trị trong tương lai.', 7, 'Công ty có sự tăng trưởng doanh thu mạnh mẽ nhờ hoạt động quảng cáo và truyền thông, cải thiện đáng kể lợi nhuận. Tuy nhiên, cơ cấu tài chính đòn bẩy cao, nợ ngắn hạn lớn và giao dịch bên liên quan phức tạp tạo rủi ro quản trị. Triển vọng phụ thuộc vào khả năng kiểm soát nợ và tối ưu hóa các khoản đầu tư.'),
('YEG_2023_parent', 'YEG', 2023, 'parent', 'Doanh nghiệp có mạng lưới giao dịch bên liên quan rất rộng lớn với các công ty con, công ty liên kết, các thành viên HĐQT và Ban Tổng Giám đốc. Các giao dịch bao gồm cho vay, vay nợ, mua bán hàng hóa/dịch vụ với lãi suất từ 8% đến 11%/năm, chủ yếu là tín chấp. Điều này tiềm ẩn rủi ro về xung đột lợi ích, giao dịch không theo giá thị trường và quản lý dòng tiền phức tạp trong nội bộ tập đoàn.', 'Áp lực nợ vay ở mức trung bình với tổng nợ vay khoảng 117,3 tỷ VND, trong đó nợ ngắn hạn chiếm tỷ trọng cao (khoảng 19%). Công ty vay từ ngân hàng có tài sản thế chấp, còn lại đa phần là vay tín chấp từ bên liên quan. Khả năng thanh toán phụ thuộc vào dòng tiền từ hoạt động kinh doanh và các khoản phải thu lớn từ cho vay.', 'Hàng tồn kho chủ yếu là chi phí mua quyền sử dụng bản quyền từ công ty con STV với giá trị 18,4 tỷ VND, không có dự phòng giảm giá. Rủi ro tồn kho ở mức trung bình, phụ thuộc vào khả năng chuyển nhượng lại cho đối tác. Dự án xây dựng dở dang (phần mềm DMS) có giá trị 5 tỷ VND, tiến độ triển khai chưa rõ ràng.', 6, 'Yeah1 Group có sự tăng trưởng mạnh về doanh thu và lợi nhuận trong năm 2023 (doanh thu thuần tăng 316%, lợi nhuận sau thuế tăng 439%). Công ty thực hiện nhiều thương vụ đầu tư, góp vốn vào các công ty con/liên kết, đặc biệt trong lĩnh vực nội dung số và truyền thông. Tuy nhiên, cấu trúc tài chính phức tạp với mạng lưới giao dịch bên liên quan dày đặc, tỷ lệ nợ vay tín chấp cao, và sự phụ thuộc vào dòng tiền cho vay nội bộ là những rủi ro đáng chú ý. Công ty cần cải thiện minh bạch trong quản trị và giảm thiểu rủi ro từ các giao dịch liên kết.'),
('YEG_2024_parent', 'YEG', 2024, 'parent', 'Doanh nghiệp có mạng lưới giao dịch bên liên quan rất rộng lớn và phức tạp với hơn 20 công ty con trực tiếp/gián tiếp và nhiều cá nhân liên quan. Các giao dịch bao gồm cho vay nội bộ (tổng phải thu cho vay ngắn hạn với bên liên quan: 22.155.000.000 VND), mua bán bản quyền nội dung số qua lại, nhờ thu hộ/chi hộ, và vay ngược lại từ các công ty con. Tổng phải trả người bán cho bên liên quan lên đến 114.255.270.516 VND. Có một số khoản cho vay đã quá hạn thanh toán (cho Ontrending, cho STV). Đặc biệt, Công ty vay cá nhân với lãi suất thấp (8%/năm) từ người thân của thành viên HĐQT, và nhiều giao dịch tín chấp với công ty con, tạo rủi ro về tính minh bạch và công bằng.', 'Công ty có đòn bẩy tài chính cao với tổng nợ vay 382.992.511.844 VND, trong đó nợ ngắn hạn chiếm áp đảo (352.728.722.237 VND so với nợ dài hạn 30.263.789.607 VND). Nợ vay cá nhân chiếm tỷ trọng lớn (237.669.150.000 VND) với thời hạn ngắn, tạo áp lực trả nợ lớn. Nợ tăng mạnh từ 117.376.743.317 VND đầu năm lên 382.992.511.844 VND cuối năm. Chi phí lãi vay năm 2024 là 22.527.924.238 VND. Tuy nhiên, dòng tiền hoạt động kinh doanh dương mạnh (148.917.714.291 VND) giúp cải thiện khả năng thanh toán. Tài sản thế chấp chủ yếu là quyền sử dụng đất của bên liên quan và bên thứ ba.', 'Hàng tồn kho giảm mạnh từ 18.471.428.571 VND xuống chỉ còn 501.439.034 VND, cho thấy Công ty đã thanh lý hoặc tiêu thụ hầu hết hàng tồn kho trong năm. Dự án xây dựng dở dang bao gồm dự án phần mềm DMS (5 tỷ VND, giữ nguyên) và chương trình phim ngắn đang sản xuất (5,5 tỷ VND, phát sinh mới). Rủi ro tồn kho thấp do giá trị nhỏ, nhưng tài sản cố định vô hình là bản quyền chương trình phim ngắn tăng rất mạnh (từ 76,5 tỷ lên 136,7 tỷ VND), cần theo dõi khả năng sinh lời từ các nội dung này.', 6, 'Yeah1 Group Corporation có năm 2024 với sự thay đổi mạnh mẽ về cơ cấu. Lợi nhuận sau thuế hợp nhất tăng 362,2% (từ 26,5 tỷ lên 122,6 tỷ VND) nhờ doanh thu quảng cáo tăng gấp 4 lần. Tuy nhiên, lợi nhuận riêng của công ty mẹ lại giảm 55,5% (từ 52,1 tỷ xuống 23,2 tỷ VND) do chi phí quản lý tăng mạnh. Công ty thực hiện M&A tích cực - mua thêm cổ phần Netlink, Edigital và thoái vốn khỏi nhiều công ty con (STV, YES, YAG, AppNews, Ana, Care). Nợ vay tăng gần 3,3 lần, chủ yếu từ vay cá nhân ngắn hạn, cho thấy chiến lược tăng trưởng dựa vào đòn bẩy tài chính cao. Tỷ lệ gross margin riêng chỉ khoảng 13,5% cho thấy biên lợi nhuận gộp mỏng. Mạng lưới giao dịch bên liên quan phức tạp với nhiều khoản cho vay tín chấp nội bộ và giao dịch qua lại. Triển vọng phụ thuộc vào khả năng khai thác hiệu quả các khoản đầu tư mới và quản lý dòng tiền trả nợ.'),
('YEG_2023_consolidated', 'YEG', 2023, 'consolidated', 'Nhóm Công ty có nhiều giao dịch trọng yếu với các bên liên quan, bao gồm cho vay, mua bán bản quyền nội dung số, cung cấp dịch vụ. Một số khoản vay cho các công ty liên kết (như Tera Group, Công ty Cổ phần Truyền thông Power, Công ty Cổ phần Phúc hợp Truyền thông T.H) với giá trị lớn và lãi suất từ 10% - 11%/năm, tín chấp. Ngoài ra, có giao dịch mua bán bản quyền nội dung số lớn với Công ty Cổ phần Tera Group (90.427 tỷ VND) và Công ty Cổ phần Yeah1 Edigital (48.556 tỷ VND). Các giao dịch này có thể tiềm ẩn rủi ro về giá chuyển nhượng, tính thanh khoản và chất lượng tài sản.', 'Tổng nợ vay (ngắn hạn và dài hạn) cuối kỳ là 210.367 tỷ VND, tăng mạnh so với đầu năm (95.318 tỷ VND). Nợ ngắn hạn chiếm tỷ trọng lớn (171.353 tỷ VND). Công ty có vay từ nhiều nguồn khác nhau (ngân hàng, tổ chức khác, cá nhân, bên liên quan) với lãi suất dao động từ 6% - 15%/năm. Các khoản vay ngắn hạn đáo hạn trong năm 2024 tạo áp lực trả nợ đáng kể. Mặc dù Công ty có tài sản thế chấp cho một số khoản vay ngân hàng, nhưng phần lớn các khoản vay khác là tín chấp.', 'Hàng tồn kho cuối kỳ giảm so với đầu kỳ, nhưng vẫn ở mức cao (29.169 tỷ VND giá trị thuần). Dự phòng giảm giá hàng tồn kho lớn (34.556 tỷ VND). Công ty có các khoản chi phí xây dựng cơ bản dở dang (13.367 tỷ VND) và các dự án phát triển dở dang, cho thấy một phần vốn bị ứ đọng vào các dự án chưa hoàn thành, có thể tiềm ẩn rủi ro về tiến độ và hiệu quả.', 7, 'Yeah1 Group đang trong giai đoạn mở rộng mạnh mẽ thông qua phát hành cổ phiếu tăng vốn (tăng vốn từ 313 tỷ lên 1.314 tỷ VND) và vay nợ. Doanh thu thuần tăng 31% nhưng lợi nhuận sau thuế chỉ tăng nhẹ. Áp lực nợ vay ngắn hạn rất lớn, dòng tiền hoạt động kinh doanh âm. Công ty có nhiều giao dịch phức tạp và giá trị lớn với các bên liên quan, đòi hỏi sự thận trọng trong đánh giá. Tuy nhiên, Công ty cũng có những khoản đầu tư chiến lược vào công ty liên kết và bản quyền nội dung số có tiềm năng tăng trưởng. Sức khỏe tài chính của Công ty phụ thuộc lớn vào khả năng quản lý dòng tiền, kiểm soát chi phí và hiệu quả của các khoản đầu tư chiến lược.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('YEG_2022_consolidated', 'YEG', 2022, 'consolidated', 'Tập đoàn có nhiều giao dịch với các bên liên quan bao gồm các công ty liên kết và cá nhân trong Ban Tổng Giám đốc, với các khoản tạm ứng, cho vay và mua bán dịch vụ. Các giao dịch này cần được theo dõi chặt chẽ để đảm bảo tính công bằng và minh bạch, tránh rủi ro xung đột lợi ích.', 'Áp lực nợ vay ngắn hạn là đáng kể (94.3 tỷ VND) với lãi suất cao (8-12%/năm), trong khi dòng tiền hoạt động kinh doanh âm. Tập đoàn phụ thuộc vào việc huy động vốn vay mới và thoái vốn để thanh toán nợ đến hạn, tạo rủi ro thanh khoản.', 'Tồn kho có dự phòng giảm giá lớn (59.9 tỷ VND) so với giá gốc (75.4 tỷ VND), chủ yếu cho hàng hóa và chương trình, cho thấy nguy cơ ứ đọng và lỗi thời. Dự án xây dựng dở dang (22.5 tỷ VND) vẫn đang triển khai, cần giám sát tiến độ và hiệu quả.', 7, 'Yeah1 Group trải qua giai đoạn tái cơ cấu mạnh với nhiều hoạt động thoái vốn, hợp nhất và đầu tư mới trong năm 2022. Mặc dù lợi nhuận sau thuế công ty mẹ tăng so với năm trước (do ghi nhận lãi thoái vốn), lợi nhuận hợp nhất giảm. Sức khỏe tài chính đối mặt với thách thức về nợ ngắn hạn cao, dòng tiền kinh doanh âm, và tỷ lệ dự phòng lớn trên tồn kho và phải thu. Triển vọng phụ thuộc vào khả năng quản lý dòng tiền, thành công của các dự án mới và hiệu quả hoạt động kinh doanh cốt lõi sau tái cơ cấu.'),
('YEG_2021_consolidated', 'YEG', 2021, 'consolidated', 'Tập đoàn có nhiều giao dịch với bên liên quan, bao gồm cho vay, tạm ứng cho các cá nhân trong Ban lãnh đạo và công ty liên kết. Một số khoản vay không rõ lãi suất, có thể gây rủi ro về tính công bằng và minh bạch. Cần kiểm tra xem các giao dịch này có được thực hiện theo giá thị trường hay không.', 'Áp lực nợ vay ngắn hạn cao với tổng nợ ngắn hạn hơn 130 tỷ VND, trong khi tiền mặt chỉ 4.3 tỷ VND. Một số khoản vay được đảm bảo bằng tiền gửi ngân hàng, giảm rủi ro, nhưng nợ vay bên thứ ba với lãi suất biến động có thể tăng chi phí tài chính. Nợ dài hạn 71 tỷ VND chủ yếu từ FPT Investment, cần theo dõi khả năng trả nợ.', 'Hàng tồn kho có dự phòng giảm giá lớn (65 tỷ VND trên tổng giá gốc 96 tỷ VND), cho thấy rủi ro hàng tồn kho lỗi thời hoặc chậm lưu chuyển. Dự án xây dựng dở dang 5 tỷ VND đang triển khai, có thể bị ứ đọng nếu dự án không hoàn thành đúng tiến độ.', 7, 'Tập đoàn đang trong quá trình tái cơ cấu mạnh mẽ với việc thoái vốn nhiều công ty con, dẫn đến doanh thu tài chính lớn nhưng hoạt động kinh doanh cốt lõi vẫn thua lỗ. Điểm rủi ro quản trị cao do giao dịch bên liên quan phức tạp và thay đổi nhân sự cấp cao. Triển vọng đầu tư thận trọng, cần theo dõi khả năng chuyển đổi mô hình kinh doanh và cải thiện dòng tiền.'),
('YEG_2021_parent', 'YEG', 2021, 'parent', 'Doanh nghiệp có nhiều giao dịch lớn với các bên liên quan, đặc biệt là cho vay không lãi suất cho công ty con và ban lãnh đạo (tạm ứng). Điều này tiềm ẩn rủi ro về quản trị, dòng tiền và khả năng thu hồi. Giao dịch chuyển nhượng vốn con với lợi nhuận lớn cần được xem xét kỹ.', 'Nợ vay ngắn hạn ở mức 21,8 tỷ VNĐ, áp lực nợ ở mức trung bình. Công ty đang lỗ nặng, dòng tiền kinh doanh dương nhưng chủ yếu từ hoạt động thoái vốn và tài chính. Tài sản thế chấp không được nêu rõ.', 'Công ty không có hàng tồn kho truyền thống, nhưng có chi phí xây dựng cơ bản dở dang (dự án phần mềm) khoảng 5 tỷ VNĐ. Rủi ro dự án bị ứ đọng hoặc không mang lại lợi ích kinh tế nếu triển khai chậm.', 7, 'Công ty đang trong giai đoạn tái cơ cấu mạnh, thoái vốn nhiều công ty con để cắt lỗ và tối ưu hóa danh mục. Tuy nhiên, hoạt động kinh doanh cốt lõi (cho thuê mặt bằng, dịch vụ) suy giảm, lợi nhuận gộp rất thấp. Dòng tiền kinh doanh dương chủ yếu nhờ thoái vốn. Rủi ro quản trị cao do giao dịch bên liên quan phức tạp. Triển vọng phụ thuộc vào khả năng hồi phục hoạt động kinh doanh và quản lý rủi ro.'),
('YEG_2020_parent', 'YEG', 2020, 'parent', 'Doanh nghiệp có nhiều giao dịch với bên liên quan, bao gồm cho vay không lãi suất, mua bán nội bộ với công ty con và các khoản tạm ứng lớn cho ban lãnh đạo, cần giám sát chặt chẽ để tránh xung đột lợi ích.', 'Nợ vay ngắn hạn chỉ 9 tỷ đồng từ công ty con với lãi suất 9%/năm, không có tài sản đảm bảo, áp lực nợ thấp.', 'Có dự án xây dựng cơ bản dở dang gần 9.2 tỷ đồng liên quan đến phần mềm, không có hàng tồn kho truyền thống, rủi ro thấp.', 7, 'Công ty lỗ nặng trong năm 2020 (lỗ sau thuế riêng 70.6 tỷ đồng), nhưng đã cải thiện so với năm 2019. Nợ vay thấp, dòng tiền hoạt động kinh doanh dương. Tuy nhiên, có nhiều giao dịch với bên liên quan phức tạp và khoản đầu tư vào công ty con lớn. Triển vọng phụ thuộc vào khả năng hồi phục mảng kinh doanh truyền thông và quản lý hiệu quả các khoản đầu tư.'),
('YEG_2020_consolidated', 'YEG', 2020, 'consolidated', 'Tập đoàn có nhiều giao dịch với các bên liên quan bao gồm công ty liên kết, công ty thuộc sở hữu của cổ đông và các cá nhân quản lý chủ chốt. Các giao dịch bao gồm doanh thu, mua dịch vụ, chi hộ và tạm ứng. Mặc dù có giao dịch lớn, không có bằng chứng rõ ràng về giao dịch bất thường như cho vay không lãi suất, nhưng cần theo dõi các khoản tạm ứng lớn cho cá nhân.', 'Tập đoàn có nợ ngắn hạn từ các ngân hàng và công ty với lãi suất từ 7.4% đến 7.6%/năm, một số khoản vay tín chấp và một số có thế chấp bằng tài khoản tiền gửi. Nợ dài hạn 70 tỷ VND từ Công ty Cổ phần Đầu tư FPT. Áp lực nợ vay trung bình, khả năng thanh toán cần được đánh giá dựa trên dòng tiền.', 'Hàng tồn kho bao gồm hàng hóa, chương trình truyền hình và phim đang sản xuất, với dự phòng giảm giá tăng từ 21.5 tỷ lên 34.1 tỷ VND. Các dự án xây dựng dở dang có giá trị 9.5 tỷ VND, cho thấy hoạt động đầu tư nhưng cần đánh giá tiến độ và khả năng hoàn thành.', 7, 'Công ty lỗ sau thuế TNDN hợp nhất năm 2020 giảm 52.98% so với năm 2019, đạt -179.9 tỷ VND. Doanh thu thuần giảm, giá vốn cao dẫn đến lợi nhuận gộp thấp. Có nhiều giao dịch với bên liên quan và nợ vay, đặt ra rủi ro về quản trị và tài chính. Điểm rủi ro quản trị ở mức cao do giao dịch phức tạp với các bên liên quan và cơ cấu nợ. Triển vọng đầu tư thận trọng do thách thức từ đại dịch COVID-19 và cạnh tranh.'),
('YEG_2022_parent', 'YEG', 2022, 'parent', 'Doanh nghiệp có nhiều giao dịch với các bên liên quan, bao gồm cho vay, mua bán hàng hóa, tuy nhiên không phát hiện giao dịch bất thường rõ ràng như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Nợ vay chủ yếu là ngắn hạn với lãi suất hợp lý (6%-8%), không có tài sản đảm bảo, tổng nợ vay khoảng 43,2 tỷ VNĐ, áp lực thanh toán nợ tồn tại nhưng trong tầm kiểm soát.', 'Không có hàng tồn kho truyền thống, chỉ có chi phí xây dựng cơ bản dở dang cho dự án phần mềm, rủi ro thấp.', 5, 'Tình hình tài chính riêng của Công ty cải thiện so với năm trước với lợi nhuận sau thuế dương 9,66 tỷ VNĐ, doanh thu tăng 37%, lợi nhuận gộp tăng mạnh. Tuy nhiên, nợ vay ngắn hạn tăng gấp đôi. Công ty có nhiều giao dịch với các bên liên quan nhưng không có dấu hiệu bất thường. Triển vọng trung bình, cần theo dõi khả năng thanh toán nợ và hiệu quả hoạt động kinh doanh.'),
('YEG_2018_consolidated', 'YEG', 2018, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là mua bán dịch vụ, cho vay và tạm ứng, không có dấu hiệu bất thường về giá hay điều kiện đặc biệt. Tuy nhiên, tập đoàn cần kiểm soát chặt chẽ các khoản tạm ứng và cho vay để tránh rủi ro.', 'Nợ vay ngắn hạn lớn, với nhiều khoản vay ngân hàng có tài sản đảm bảo. Công ty có đủ tài sản thế chấp và dòng tiền từ hoạt động kinh doanh để đáp ứng nghĩa vụ nợ, nhưng áp lực trả nợ ngắn hạn vẫn đáng kể.', 'Hàng tồn kho bao gồm bản quyền phim và chương trình truyền hình, có rủi ro giảm giá do thay đổi thị hiếu. Tập đoàn đã lập dự phòng giảm giá, nhưng cần tiếp tục đánh giá định kỳ.', 5, 'Tập đoàn Yeah1 có tăng trưởng mạnh về doanh thu và lợi nhuận trong năm 2018, nhưng nợ vay tăng nhanh và tài sản chủ yếu là tài sản vô hình. Công ty cần cải thiện quản trị dòng tiền và đa dạng hóa nguồn thu để giảm rủi ro.'),
('YEG_2019_parent', 'YEG', 2019, 'parent', 'Công ty có nhiều giao dịch với các bên liên quan bao gồm công ty con, cổ đông và ban lãnh đạo, với các khoản cho vay không lãi suất hoặc lãi suất thấp, tạm ứng lớn cho cá nhân, điều này có thể gây rủi ro về xung đột lợi ích và quản trị doanh nghiệp.', 'Công ty không có nợ vay ngắn hạn và dài hạn tại cuối năm 2019, áp lực nợ vay thấp.', 'Công ty không có hàng tồn kho, rủi ro tồn kho thấp.', 6, 'Công ty có tình hình tài chính ổn định với lợi nhuận sau thuế dương, nhưng doanh thu giảm mạnh so với năm trước. Các giao dịch bên liên quan phức tạp có thể ảnh hưởng đến quản trị. Công ty không có nợ vay và hàng tồn kho, nhưng đầu tư vào công ty con lớn. Triển vọng đầu tư phụ thuộc vào hiệu quả hoạt động của các công ty con.'),
('YEG_2017_consolidated', 'YEG', 2017, 'consolidated', 'Công ty có giao dịch đáng kể với các bên liên quan, đặc biệt là Phó Tổng Giám đốc Tài chính (Ông Võ Thái Phong) với khoản vay dài hạn 35.8 tỷ VND (lãi suất 10%/năm, có tài sản đảm bảo) và các khoản phải thu khác. Công ty cũng cho Công ty CP Dịch vụ Thương mại Việt Nam Trực tuyến (công ty do thành viên Ban Giám đốc kiểm soát) mượn 24.4 tỷ VND. Các giao dịch này cần được giám sát chặt chẽ để đảm bảo tính minh bạch và công bằng.', 'Nợ ngắn hạn ở mức cao (67.47 tỷ VND), trong đó vay ngân hàng chiếm tỷ trọng lớn với lãi suất dao động 3-12%/năm. Công ty có lịch sử phát hành và mua lại trái phiếu chuyển đổi lớn trong năm (113.78 tỷ VND). Áp lực trả nợ và lãi vay (16.18 tỷ VND trong năm) là đáng kể, được thể hiện qua dòng tiền hoạt động tài chính dương lớn nhưng chủ yếu do vay mới bù trả nợ cũ. Tài sản đảm bảo chủ yếu là tiền gửi, bất động sản và quyền thu nợ từ khách hàng.', 'Hàng tồn kho tăng mạnh (từ 48.6 tỷ lên 74.9 tỷ VND), chủ yếu do chi phí sản xuất kinh doanh dở dang tăng vọt (58.5 tỷ VND). Dự phòng giảm giá hàng tồn kho chỉ có 477.5 triệu VND trên tổng giá trị. Rủi ro nằm ở tiến độ và khả năng tiêu thụ của các chương trình, dự án dở dang này.', 4, 'Yeah1 Group tăng trưởng mạnh về doanh thu và lợi nhuận (doanh thu thuần tăng 49%, lợi nhuận sau thuế cổ đông Công ty mẹ tăng 265%) trong năm 2017, chủ yếu nhờ các thương vụ mua bán sáp nhập (M&A) lớn. Tuy nhiên, công ty phải huy động vốn lớn (phát hành cổ phiếu, vay nợ) để tài trợ cho các thương vụ này, dẫn đến nợ vay tăng cao và cấu trúc tài sản có phần rủi ro hơn (tài sản dồn vào lợi thế thương mại lớn, hàng tồn kho dở dang). Dòng tiền kinh doanh cơ bản yếu, trong khi dòng tiền đầu tư và tài chính biến động mạnh. Công ty cần quản lý hiệu quả dòng tiền và rủi ro nợ vay trong thời gian tới để duy trì đà tăng trưởng.'),
('YEG_2017_parent', 'YEG', 2017, 'parent', 'Công ty có giao dịch với bên liên quan rất lớn và phức tạp, bao gồm nhiều công ty con và cổ đông lớn. Giao dịch bao gồm doanh thu bán hàng/dịch vụ, mua hàng hóa/dịch vụ, cho vay không lãi suất, và góp vốn. Đáng chú ý, có khoản cho bên liên quan vay không lãi suất (2.536.778.834 VND ngắn hạn). Điều này cho thấy mức độ phụ thuộc cao và có thể có rủi ro về xung đột lợi ích hoặc giao dịch không theo giá thị trường.', 'Công ty có cấu trúc nợ vay khá phức tạp với cả nợ ngắn hạn và dài hạn, bao gồm cả trái phiếu chuyển đổi đã được mua lại trong năm. Tổng nợ phải trả chiếm tỷ trọng lớn trong tổng nguồn vốn. Các khoản vay ngắn hạn được đảm bảo bằng tài sản cố định, khoản phải thu khách hàng và tiền gửi ngân hàng. Công ty chịu áp lực trả nợ cả gốc và lãi (13.568.689.832 VND lãi vay trong năm), nhưng dòng tiền từ hoạt động kinh doanh trong năm lại âm (-14.259.968.180 VND), cho thấy rủi ro thanh khoản.', 'Giá trị hàng tồn kho giảm mạnh từ 22.363.211.349 VND (2016) xuống 13.900.813.659 VND (2017). Dự phòng giảm giá hàng tồn kho không đổi (477.545.455 VND). Các khoản chi phí xây dựng cơ bản dở dang (115.475.000 VND) rất nhỏ và phần lớn đã bị xóa số, cho thấy không có dự án xây dựng lớn bị ứ đọng. Tuy nhiên, sự sụt giảm giá trị tồn kho có thể phản ánh doanh thu bán hàng giảm hoặc khó khăn trong kinh doanh.', 7, 'Năm 2017, Công ty ghi nhận doanh thu thuần giảm mạnh (125.794.879.631 VND so với 265.778.720.462 VND năm 2016) nhưng lợi nhuận sau thuế lại tăng (32.280.851.090 VND). Sự tăng trưởng lợi nhuận chủ yếu đến từ hoạt động tài chính (doanh thu hoạt động tài chính 43.671.539.271 VND, chủ yếu là cổ tức từ công ty con). Công ty có cấu trúc tài chính đòn bẩy cao với nợ vay lớn, dòng tiền kinh doanh âm và phụ thuộc lớn vào các giao dịch bên liên quan. Vốn chủ sở hữu tăng mạnh do phát hành cổ phiếu. Sức khỏe tài chính tổng thể có rủi ro cao về thanh khoản và quản trị, triển vọng đầu tư cần thận trọng.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('YEG_2018_parent', 'YEG', 2018, 'parent', 'Doanh nghiệp có nhiều giao dịch với các công ty con và bên liên quan, bao gồm cho vay lớn không lãi suất hoặc lãi suất thấp, có thể gây rủi ro về xung đột lợi ích và chuyển giá.', 'Nợ vay ngắn hạn được đảm bảo bằng tiền gửi ngân hàng với lãi suất 8.2%/năm, áp lực nợ vay ở mức trung bình. Công ty đã trả hết nợ dài hạn trong năm.', 'Không có hàng tồn kho vào cuối năm 2018, rủi ro tồn kho thấp.', 6, 'Tài sản và vốn chủ sở hữu tăng mạnh do phát hành cổ phiếu, nhưng doanh thu giảm. Lợi nhuận tăng từ hoạt động tài chính. Cần theo dõi các giao dịch với bên liên quan và khả năng sinh lời từ hoạt động kinh doanh cốt lõi.'),
('YEG_2015_parent', 'YEG', 2015, 'parent', 'Doanh nghiệp có giao dịch rất lớn và thường xuyên với các công ty con và cổ đông lớn (DFK VinaCapital), đặc biệt là doanh thu bán hàng/dịch vụ, mua hàng/dịch vụ, cho vay và nhận lãi. Các giao dịch này làm tăng rủi ro về tính công bằng của giá chuyển nhượng và tiềm ẩn xung đột lợi ích.', 'Nợ vay ngắn hạn tăng mạnh (từ 16,9 tỷ lên 77,5 tỷ VNĐ) và nợ dài hạn cũng tăng (từ 15 tỷ lên 45,1 tỷ VNĐ). Tài sản đảm bảo chủ yếu là tiền gửi ngân hàng, tài sản cố định, cổ phần và quyền tài sản từ dự án/hợp đồng. Áp lực trả nợ lãi là đáng kể (13,2 tỷ VNĐ/năm 2015).', 'Hàng tồn kho chủ yếu là chương trình truyền hình và hàng hóa, đã trích lập dự phòng cho hàng hóa. Chi phí xây dựng cơ bản dở dang (kênh truyền hình) lớn và tăng nhẹ, cho thấy dự án đang triển khai, chưa có dấu hiệu ứ đọng lớn.', 5, 'Công ty có sự tăng trưởng mạnh về doanh thu và lợi nhuận, nhưng đi kèm với tăng trưởng nợ vay rất cao. Dòng tiền hoạt động kinh doanh âm lớn (-47,3 tỷ VNĐ) do tăng mạnh các khoản phải thu và trả trước. Mối quan hệ kinh doanh chặt chẽ với các công ty con và cổ đông lớn tạo ra cả lợi ích (hệ sinh thái) và rủi ro (quản trị, giá chuyển nhượng). Sức khỏe tài chính phụ thuộc vào khả năng quản lý dòng tiền và đòn bẩy nợ.'),
('YEG_2016_parent', 'YEG', 2016, 'parent', 'Doanh nghiệp có giao dịch mua bán dịch vụ và nhận cho vay lớn với các công ty con, đặc biệt là khoản phải thu ngắn hạn từ khách hàng bên liên quan lên tới 77 tỷ VNĐ (76,984,082,854 VNĐ). Điều này cho thấy mức độ tập trung và phụ thuộc cao vào các công ty con, tiềm ẩn rủi ro nếu hoạt động của các công ty con gặp khó khăn.', 'Công ty có áp lực nợ vay đáng kể với tổng nợ vay ngắn hạn và dài hạn hơn 75 tỷ VNĐ. Các khoản vay ngắn hạn chiếm tỷ trọng lớn và đáo hạn trong vòng 1 năm, đòi hỏi thanh khoản liên tục. Tài sản thế chấp bao gồm nhiều loại (xe, bất động sản, cổ phiếu, hợp đồng tiền gửi, quyền đòi nợ), cho thấy mức độ cam kết tài sản cao để tiếp cận vốn vay.', 'Giá trị hàng tồn kho tăng mạnh từ 7.3 tỷ lên 22.8 tỷ VNĐ, chủ yếu do tăng mạnh hàng hóa lưu thông. Dự phòng giảm giá không đổi ở mức 477 triệu VNĐ, không tương ứng với sự tăng giá trị, có thể cần đánh giá lại mức dự phòng phù hợp.', 6, 'Tập đoàn Đại Sức Trẻ hoạt động trong lĩnh vực truyền thông, quảng cáo và giải trí. Tình hình tài chính năm 2016 cho thấy doanh thu và lợi nhuận tăng trưởng tốt (doanh thu thuần tăng 25%, lợi nhuận sau thuế tăng 60% so với năm trước). Tuy nhiên, doanh nghiệp chịu áp lực nợ vay lớn và có mối quan hệ giao dịch phức tạp, tập trung với các công ty con. Dòng tiền từ hoạt động kinh doanh dương nhưng thấp hơn nhiều so với lợi nhuận kế toán, trong khi dòng tiền từ hoạt động tài chính âm nặng do trả nợ gốc vay lớn. Triển vọng phụ thuộc vào khả năng quản lý nợ, duy trì thanh khoản và hiệu quả hoạt động của các công ty con.'),
('YEG_2016_consolidated', 'YEG', 2016, 'consolidated', 'Công ty có giao dịch với các bên liên quan bao gồm doanh thu dịch vụ, trả cổ tức và khoản cho vay 8,6 tỷ đồng cho Công ty CP Dịch vụ Thương mại Việt Nam Trực tuyến. Các giao dịch này không có lãi suất hoặc đảm bảo rõ ràng, tiềm ẩn rủi ro về tính công bằng và khả năng thu hồi.', 'Nợ vay ngắn hạn lớn (khoảng 81 tỷ đồng), chiếm tỷ trọng cao trong cơ cấu vốn, tạo áp lực thanh toán. Công ty có tài sản thế chấp là tài sản cố định và khoản phải thu khách hàng. Nợ dài hạn chủ yếu là trái phiếu với lãi suất biến động, cần theo dõi chi phí lãi vay.', 'Hàng tồn kho tăng mạnh từ 15,8 tỷ lên 48,1 tỷ đồng, chủ yếu do chi phí sản xuất kinh doanh dở dang và hàng hóa. Dự phòng giảm giá chỉ lập cho hàng hóa, có thể chưa phản ánh đầy đủ rủi ro hàng tồn kho chậm luân chuyển.', 5, 'Tập đoàn tăng trưởng doanh thu và lợi nhuận trong năm 2016, nhưng cơ cấu tài chính có đòn bẩy nợ cao, hàng tồn kho tăng nhanh và giao dịch với bên liên quan tiềm ẩn rủi ro. Cần cải thiện quản lý vốn lưu động và minh bạch giao dịch với bên liên quan.'),
('YBM_2025_consolidated', 'YBM', 2025, 'consolidated', 'Doanh nghiệp có nhiều giao dịch với các bên liên quan, bao gồm mua nguyên vật liệu, thuê dịch vụ và bù trừ công nợ ba bên với giá trị lớn (tổng cộng hơn 50 tỷ VND). Các giao dịch này có thể liên quan đến cổ đông lớn và các công ty có cùng thành viên quản lý chủ chốt, tiềm ẩn rủi ro về giá chuyển nhượng không minh bạch hoặc lợi ích nhóm.', 'Nợ vay ngắn hạn và dài hạn tổng cộng hơn 350 tỷ VND, được đảm bảo bằng nhiều tài sản như cổ phần, bất động sản, quyền khai thác đá. Công ty có khả năng trả nợ, nhưng áp lực lãi suất và đáo hạn nợ có thể ảnh hưởng đến dòng tiền.', 'Hàng tồn kho không có dự phòng giảm giá, cho thấy không có vấn đề tồn kho ứ đọng lớn. Tuy nhiên, giá trị tồn kho giảm nhẹ so với đầu năm, có thể do tiêu thụ tốt.', 6, 'Doanh nghiệp hoạt động trong ngành sản xuất bột đá CaCO3, có sự tăng trưởng doanh thu và lợi nhuận tốt. Tuy nhiên, rủi ro về giao dịch bên liên quan và nợ vay cần được giám sát. Tình hình tài chính ổn định nhưng cần cải thiện quản trị để giảm thiểu rủi ro.'),
('YBM_2025_parent', 'YBM', 2025, 'parent', 'Công ty có giao dịch mua bán, thuê dịch vụ và bù trừ công nợ với nhiều bên liên quan, bao gồm cổ đông lớn và công ty có cùng thành viên quản lý, điều này có thể tiềm ẩn rủi ro về giao dịch không minh bạch và xung đột lợi ích.', 'Công ty có nợ vay ngân hàng ngắn hạn và dài hạn lớn, lãi suất từ 3,85% đến 7,5%/năm, tạo áp lực trả nợ đáng kể. Tuy nhiên, công ty có tài sản thế chấp đảm bảo cho các khoản vay và dòng tiền kinh doanh tích cực.', 'Hàng tồn kho ở mức cao (hơn 104 tỷ VND) nhưng không trích lập dự phòng giảm giá, có thể không phản ánh đầy đủ rủi ro giảm giá hoặc chậm luân chuyển, đặc biệt trong bối cảnh biến động thị trường.', 6, 'Công ty hoạt động trong lĩnh vực sản xuất bột đá CaCO₃, với doanh thu thuần đạt 875,8 tỷ VND và lợi nhuận sau thuế tăng mạnh lên 28,6 tỷ VND. Tuy nhiên, công ty phải đối mặt với áp lực nợ vay lớn và giao dịch bên liên quan phức tạp, được phản ánh qua ý kiến kiểm toán ngoại trừ. Khả năng thanh toán nợ dựa vào dòng tiền kinh doanh và tài sản thế chấp. Triển vọng phụ thuộc vào quản lý rủi ro và thị trường khoáng sản.'),
('YBM_2022_consolidated', 'YBM', 2022, 'consolidated', 'Doanh nghiệp có nhiều giao dịch với các bên liên quan, đặc biệt cho vay không lãi suất (Bà Nguyễn Thị Nguyên 7,5 tỷ VND) và cho vay lãi suất thấp (9%/năm) cho Công ty Cổ phần Đầu tư và Phát triển Nhựa gỗ Châu Âu. Ngoài ra, doanh thu bán hàng và mua nguyên vật liệu chủ yếu phát sinh với các công ty có cùng thành viên quản lý chủ chốt, cho thấy mối quan hệ kinh doanh phụ thuộc và tiềm ẩn xung đột lợi ích.', 'Tổng nợ vay và nợ thuê tài chính khoảng 192 tỷ VND, trong đó nợ ngắn hạn chiếm 79%. Áp lực trả nợ ngắn hạn lớn, tuy nhiên công ty có dòng tiền kinh doanh dương (38 tỷ VND) và tài sản thế chấp lớn (nhà xưởng, máy móc, quyền tài sản dự án). Lãi suất vay biến động theo thị trường, có thể tăng trong tương lai.', 'Hàng tồn kho tăng mạnh 121% so với đầu năm do mua bao bì Jumbo trị giá 54,3 tỷ VND. Dự án xây dựng dở dang (mỏ TALC) chưa phát sinh thêm chi phí, tiến độ triển khai chậm.', 6, 'Doanh nghiệp hoạt động trong ngành sản xuất bột đá CaCO3, doanh thu và lợi nhuận sau thuế giảm lần lượt 13% và 33% so với năm trước. Cơ cấu tài chính đòn bẩy cao với nợ vay chiếm tỷ trọng lớn. Dòng tiền kinh doanh dương nhưng phải chi trả cổ tức và nợ gốc lớn. Rủi ro chính đến từ giao dịch bên liên quan và áp lực trả nợ ngắn hạn. Triển vọng phụ thuộc vào thị trường bất động sản và xây dựng.'),
('YBM_2021_consolidated', 'YBM', 2021, 'consolidated', 'Doanh nghiệp có mối quan hệ kinh doanh phức tạp với nhiều bên liên quan là công ty có cùng thành viên quản lý chủ chốt. Có các khoản cho vay không lãi suất, không có tài sản đảm bảo cho cá nhân liên quan. Giao dịch mua bán, ứng tiền với giá trị lớn với các công ty liên quan này cũng tiềm ẩn rủi ro về giá chuyển nhượng và tính thanh khoản.', 'Áp lực nợ vay ở mức cao, tổng nợ vay và nợ thuê tài chính cuối kỳ đạt hơn 215 tỷ VNĐ, chiếm tỷ trọng lớn trong tổng nguồn vốn. Phần lớn nợ ngắn hạn và dài hạn đều được đảm bảo bằng quyền tài sản từ các dự án và hoạt động kinh doanh chính, gây rủi ro tập trung. Chi phí lãi vay lớn ảnh hưởng đến lợi nhuận.', 'Hàng tồn kho giảm mạnh so với đầu năm, chủ yếu do giảm hàng hóa. Dự án mỏ TALC Mỹ Thuận vẫn ở giai đoạn thăm dò, chưa đi vào khai thác, là khoản đầu tư dài hạn cần theo dõi. Các chi phí xây dựng dở dang có thể chậm tiến độ.', 6, 'Công ty đạt tăng trưởng doanh thu và lợi nhuận sau thuế trong năm 2021. Tuy nhiên, đòn bẩy tài chính cao với nợ vay lớn, phụ thuộc vào các khoản vay từ ngân hàng và cá nhân. Mối quan hệ kinh doanh chằng chịt với các bên liên quan tạo ra rủi ro về quản trị và xung đột lợi ích. Dòng tiền từ hoạt động kinh doanh dương nhưng không đủ để trang trải các khoản đầu tư và trả nợ, dẫn đến tiền mặt cuối kỳ giảm mạnh. Triển vọng phụ thuộc vào khả năng quản lý nợ, khai thác hiệu quả các dự án và kiểm soát rủi ro từ các giao dịch liên quan.'),
('YBM_2020_consolidated', 'YBM', 2020, 'consolidated', 'Doanh nghiệp có giao dịch mua bán và cho vay với các bên liên quan, bao gồm công ty có cùng thành viên quản lý chủ chốt và cá nhân là giám đốc. Các giao dịch này có thể tiềm ẩn rủi ro về xung đột lợi ích nếu không được thực hiện trên cơ sở thị trường.', 'Nợ vay ngắn hạn và dài hạn ở mức cao, chủ yếu là vay ngân hàng và thuê tài chính. Tài sản thế chấp bao gồm quyền khai thác khoáng sản và tài sản hình thành từ vốn vay. Công ty có khả năng trả nợ nhưng cần theo dõi áp lực lãi suất.', 'Hàng tồn kho giảm so với đầu năm, không có dự phòng giảm giá. Chi phí xây dựng cơ bản dở dang vẫn còn, có thể là dự án đầu tư dài hạn.', 6, 'Tập đoàn hoạt động trong ngành sản xuất bột đá CaCO3, có doanh thu và lợi nhuận tăng trưởng. Tuy nhiên, nợ vay cao và giao dịch bên liên quan đáng lưu ý. Triển vọng phụ thuộc vào quản lý rủi ro và thị trường.'),
('YBM_2021_parent', 'YBM', 2021, 'parent', 'Doanh nghiệp có giao dịch đáng kể với các bên liên quan, bao gồm bán hàng (chiếm khoảng 40% doanh thu), mua hàng và cho vay. Các giao dịch này có thể gây rủi ro về giao dịch không công bằng hoặc phụ thuộc vào các bên liên quan.', 'Doanh nghiệp có đòn bẩy tài chính cao với tổng nợ vay khoảng 216 tỷ VND, tỷ lệ nợ/vốn chủ sở hữu cao. Chi phí lãi vay lớn, chiếm phần lớn lợi nhuận trước thuế. Công ty phải đối mặt với áp lực trả nợ và lãi suất浮动. Các khoản vay được đảm bảo bằng tài sản cố định và quyền tài sản.', 'Hàng tồn kho giảm mạnh từ 55.4 tỷ VND xuống 30.2 tỷ VND, cho thấy khả năng quản lý tồn kho tốt hoặc nhu cầu tăng. Không có dự phòng giảm giá tồn kho, rủi ro tồn kho thấp.', 6, 'Công ty có kết quả kinh doanh tăng trưởng với doanh thu tăng 16% so với năm trước. Tuy nhiên, lợi nhuận sau thuế giảm do chi phí tài chính và chi phí bán hàng cao. Công ty đang trong giai đoạn đầu tư mạnh với nợ vay lớn, đặc biệt là nợ thuê tài chính. Khả năng thanh toán nợ còn hạn chế. Triển vọng kinh doanh phụ thuộc vào ngành xây dựng và nhu cầu bột đá.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('YBM_2020_parent', 'YBM', 2020, 'parent', 'Công ty phát sinh nhiều giao dịch với các bên liên quan, bao gồm cho vay không lãi suất (tạm ứng cá nhân) với các phó giám đốc, giám đốc và mua bán hàng hóa với các công ty có cùng thành viên quản lý chủ chốt. Điều này tiềm ẩn rủi ro về xung đột lợi ích và quản trị doanh nghiệp.', 'Tổng nợ phải trả chiếm tỷ trọng lớn (247,461,985,424 VND trên tổng nguồn vốn 419,070,992,193 VND). Công ty có nhiều khoản vay ngân hàng và nợ thuê tài chính với tài sản thế chấp chủ yếu là quyền khai thác khoáng sản, bất động sản và xe ô tô. Áp lực trả nợ cao, đặc biệt trong bối cảnh ngành sản xuất bột đá cạnh tranh.', 'Giá trị hàng tồn kho giảm mạnh từ 84,592,325,930 VND xuống 55,397,755,644 VND, không trích lập dự phòng giảm giá. Cho thấy hàng tồn kho được tiêu thụ tốt, không có rủi ro ứ đọng lớn.', 7, 'Công ty hoạt động trong ngành sản xuất bột đá CaCO3 với doanh thu và lợi nhuận tăng trưởng. Tuy nhiên, nợ vay cao, nhiều giao dịch với bên liên quan và quản trị doanh nghiệp còn lỏng lẻo. Cần tăng cường minh bạch và giảm phụ thuộc vào nợ vay để đảm bảo bền vững.'),
('YBM_2018_consolidated', 'YBM', 2018, 'consolidated', 'Công ty có giao dịch mua bán lớn với các bên liên quan, đặc biệt là Công ty Cổ phần Nhựa Châu Âu (vừa là cổ đông lớn, vừa là đối tác mua bán chính). Mặc dù công ty cho biết chính sách giá áp dụng tương tự như với các đơn vị khác, nhưng mức độ tập trung doanh thu vào một vài bên liên quan là đáng kể, tiềm ẩn rủi ro về giao dịch không minh bạch hoặc giá chuyển nhượng không phản ánh đúng thị trường.', 'Nợ vay và thuê tài chính tăng mạnh từ 112 tỷ lên 253 tỷ VND trong năm, chủ yếu là vay ngắn hạn. Tỷ lệ nợ/vốn chủ sở hữu cao, áp lực trả nợ ngắn hạn lớn. Công ty đã dùng nhiều tài sản cố định (trị giá 60,7 tỷ VND) làm tài sản đảm bảo. Các khoản vay có lãi suất thả nổi và từ nhiều nguồn khác nhau, làm tăng rủi ro lãi suất và quản lý dòng tiền.', 'Hàng tồn kho tăng gấp 2,5 lần, từ 43 tỷ lên 107 tỷ VND, chủ yếu do nguyên vật liệu tăng mạnh. Điều này có thể phản ánh việc tích trữ nguyên liệu để sản xuất nhưng cũng tiềm ẩn rủi ro ứ đọng, giảm giá hoặc biến động giá nguyên liệu đầu vào. Không có dự phòng giảm giá hàng tồn kho.', 7, 'Công ty tăng trưởng doanh thu 45,6% và lợi nhuận gộp 34,5% trong năm 2018. Tuy nhiên, tăng trưởng này đi kèm với sự gia tăng mạnh về nợ vay và hàng tồn kho, làm suy yếu cấu trúc tài chính. Dòng tiền hoạt động kinh doanh âm (-6,87 tỷ VND) cho thấy công ty đang tiêu tiền mặt để tài trợ cho hoạt động. Công ty có mối quan hệ mật thiết với các bên liên quan, đặc biệt là cổ đông lớn Công ty Nhựa Châu Âu, đặt ra câu hỏi về tính độc lập trong kinh doanh. Triển vọng phụ thuộc vào khả năng quản lý nợ, kiểm soát tồn kho và duy trì tăng trưởng doanh thu.'),
('YBM_2019_consolidated', 'YBM', 2019, 'consolidated', 'Doanh nghiệp có nhiều giao dịch phức tạp với bên liên quan: (1) Cho vay không lãi suất 7,48 tỷ VND cho Phó Giám đốc Hoàng Anh Quân từ công ty con; (2) Tạm ứng lớn cho Phó Giám đốc Lê Hoàn (13 tỷ) và Hoàng Anh Quân (8 tỷ); (3) Bán hàng hóa cho Công ty CP Nhựa Châu Âu (112,7 tỷ) và Polyfill (82,2 tỷ) - các công ty có cùng thành viên quản lý chủ chốt; (4) Chuyển nhượng cổ phần công ty con cho Chỉ gái Chủ tịch HĐQT với giá 18,9 tỷ; (5) Vay tín chấp dài hạn 23,1 tỷ từ 3 cá nhân (Trần Quỳnh Lê, Hồ Nhật Lệ, Đặng Thị Minh Trang) với lãi suất 8%/năm nhưng trả lãi cuối kỳ.', 'Áp lực nợ vay rất lớn với tổng nợ vay và thuê tài chính khoảng 246 tỷ VND (nợ ngắn hạn 181 tỷ, nợ dài hạn 65 tỷ). Chi phí lãi vay năm 2019 là 22,2 tỷ VND, chiếm tới 185% lợi nhuận thuần từ kinh doanh (11,9 tỷ). Công ty phụ thuộc lớn vào tín dụng ngân hàng từ VietinBank và BIDV với lãi suất 7,5%-10,9%/năm. Nhiều khoản nợ thuê tài chính từ BIDV-SuMi Trust và Vietcombank. Tổng nợ phải trả/vốn chủ sở hữu = 1,9 lần cho thấy đòn bẩy tài chính cao.', 'Hàng tồn kho cuối năm 84,5 tỷ VND (giảm từ 107,4 tỷ đầu năm), bao gồm nguyên liệu 55,7 tỷ và thành phẩm 26,1 tỷ. Không có dự phòng giảm giá hàng tồn kho. Theo BCTC, tỷ lệ lãi gộp giảm 9% do chất lượng đá nguyên liệu đầu vào kém, tỷ lệ hao hụt tăng cao. Chi phí xây dựng cơ bản dở dang 6,9 tỷ liên quan đến dự án Nhà máy sản xuất hạt nhựa Taical. Có rủi ro về chất lượng nguyên liệu và tồn kho dở dang xây dựng.', 6, 'Công ty CP Khoáng sản Công nghiệp Yên Bái hoạt động trong lĩnh vực sản xuất bột đá CaCO3. Doanh thu năm 2019 tăng 36% đạt 435,9 tỷ nhưng lợi nhuận sau thuế giảm 51% xuống 9,2 tỷ do chi phí nguyên liệu tăng mạnh và tỷ lệ hao hụt cao. Điểm đáng lo ngại: (1) Kiểm toán viên đưa ra ý kiến ngoại trừ do không chứng kiến kiểm kê tiền mặt và hàng tồn kho; (2) Nhiều giao dịch với bên liên quan phức tạp, cho vay không lãi suất cho lãnh đạo; (3) Đòn bẩy tài chính cao với nợ vay lớn, chi phí lãi vay áp đảo lợi nhuận; (4) Công ty thoái vốn khỏi công ty con với lỗ 857 triệu. Công ty đang trong giai đoạn mở rộng đầu tư nhưng hiệu quả kinh doanh có xu hướng suy giảm.'),
('YBM_2018_parent', 'YBM', 2018, 'parent', 'Doanh nghiệp có giao dịch lớn với các bên liên quan là Công ty CP Nhựa Châu Âu (vừa là khách hàng mua bột đá CaCO3 lớn, vừa là nhà cung cấp nguyên vật liệu và là bên bảo lãnh cho các khoản vay) và Công ty Cổ phần Polyfill. Giao dịch này chiếm tỷ trọng đáng kể trong doanh thu và phải thu, có thể tạo ra rủi ro tập trung và phụ thuộc vào nhóm liên quan.', 'Áp lực nợ vay rất lớn với tổng nợ vay và nợ thuê tài chính ngắn hạn là 193 tỷ VND và dài hạn là 59.8 tỷ VND. Phần lớn nợ ngắn hạn đáo hạn trong vòng 1 năm, tạo áp lực thanh toán cao. Công ty phải thế chấp nhiều tài sản cố định và quyền tài sản để vay, đồng thời phụ thuộc vào bảo lãnh của Công ty CP Nhựa Châu Âu.', 'Hàng tồn kho tăng mạnh từ 43.4 tỷ lên 107.4 tỷ VND, chủ yếu do nguyên vật liệu tăng đột biến. Các dự án xây dựng dở dang đã được hoàn thành và chuyển giao vào tài sản cố định trong năm, không còn tồn kho dở dang. Tuy nhiên, mức tồn kho nguyên vật liệu cao cần được giám sát để tránh ứ đọng vốn.', 7, 'Công ty đạt tăng trưởng doanh thu và lợi nhuận mạnh trong năm 2018. Tuy nhiên, đà tăng trưởng này chủ yếu dựa vào đòn bẩy tài chính lớn, dẫn đến nợ vay tăng vọt, áp lực trả nợ ngắn hạn cao và phụ thuộc vào bảo lãnh từ bên liên quan. Công ty cũng đã niêm yết trên sàn HOSE. Cần theo dõi chặt chẽ dòng tiền và khả năng thanh toán nợ đến hạn.'),
('YEG_2019_consolidated', 'YEG', 2019, 'consolidated', 'Công ty có nhiều giao dịch với bên liên quan, bao gồm tạm ứng không lãi suất cho Chủ tịch HĐQT, Tổng Giám đốc và các thành viên HĐQT; giao dịch mua bán, chi hộ lớn với Công ty Dịch vụ Thương mại Việt Nam Trực tuyến (công ty thuộc sở hữu của cổ đông). Các giao dịch này tiềm ẩn rủi ro về xung đột lợi ích và thiếu minh bạch.', 'Nợ ngắn hạn tăng mạnh từ 124.553.120.553 đồng lên 231.935.717.260 đồng, chủ yếu do khoản vay 231.892.297.110 đồng từ Ngân hàng Shinhanbank Singapore. Áp lực trả nợ cao, đặc biệt khi công ty đang lỗ lớn trong năm 2019.', 'Hàng tồn kho giảm mạnh từ 155.278.372.829 đồng xuống 77.273.959.587 đồng và phải trích lập dự phòng giảm giá 21.557.831.991 đồng, cho thấy rủi ro về hàng hóa chậm lưu chuyển và mất giá.', 7, 'Công ty đang trải qua giai đoạn khó khăn tài chính nghiêm trọng với lỗ sau thuế 382.811.128.518 đồng trong năm 2019, do chi phí quản lý tăng vọt (dự phòng phải thu khó đòi 278.084.754.896 đồng) và doanh thu giảm. Nợ vay tăng mạnh, dòng tiền hoạt động kinh doanh âm. Công ty đang trong quá trình tái cơ cấu, bán công ty con ScaleLab và mua lại cổ phiếu quỹ. Triển vọng đầu tư tiêu cực trong ngắn hạn.'),
('YBM_2019_parent', 'YBM', 2019, 'parent', 'Công ty có nhiều giao dịch lớn với các bên liên quan, bao gồm tạm ứng lớn cho ban lãnh đạo và chuyển nhượng cổ phần, cho thấy rủi ro về xung đột lợi ích và quản trị công ty.', 'Nợ vay cao với lãi suất đáng kể, được đảm bảo bằng tài sản. Áp lực trả nợ tồn tại nhưng công ty có khả năng thanh toán.', 'Hàng tồn kho giảm so với năm trước và không có dự phòng giảm giá, cho thấy rủi ro tồn kho thấp.', 6, 'Công ty có doanh thu tăng nhưng biên lợi nhuận gộp giảm. Có nhiều giao dịch với bên liên quan và nợ vay cao, cần giám sát chặt chẽ.'),
('YEG_2015_consolidated', 'YEG', 2015, 'consolidated', 'Doanh nghiệp có nhiều giao dịch với bên liên quan, bao gồm cho vay không lãi suất hoặc lãi suất thấp cho cổ đông và quản lý, mua bán dịch vụ với công ty con. Số dư phải thu từ các cá nhân quản lý lớn, tiềm ẩn rủi ro về xung đột lợi ích và lạm dụng tài sản.', 'Nợ vay ngắn hạn và dài hạn cao, tỷ lệ nợ trên tài sản lớn. Công ty thế chấp nhiều tài sản, bao gồm cổ phần và quyền tài sản, gây áp lực thanh toán. Lãi suất biến động có thể ảnh hưởng đến chi phí tài chính.', 'Hàng tồn kho bao gồm chi phí sản xuất dở dang và chương trình truyền hình, có thể bị lỗi thời hoặc chậm lưu chuyển. Dự phòng giảm giá chỉ áp dụng cho hàng hóa, không áp dụng cho các mục khác, tiềm ẩn rủi ro giá trị.', 7, 'Công ty tăng trưởng doanh thu mạnh nhưng lợi nhuận giảm do chi phí tài chính và bán hàng cao. Nợ vay lớn và giao dịch bên liên quan phức tạp đặt ra rủi ro quản trị. Tuy nhiên, tài sản đảm bảo và dòng tiền từ hoạt động kinh doanh cho thấy khả năng thanh toán. Triển vọng đầu tư phụ thuộc vào việc kiểm soát chi phí và quản lý nợ.'),
('YBM_2022_parent', 'YBM', 2022, 'parent', 'Công ty có nhiều giao dịch với các bên liên quan, bao gồm mua bán hàng hóa và cho vay. Cần chú ý đến các giao dịch cho vay không có tài sản đảm bảo với lãi suất thấp.', 'Nợ vay ngắn hạn và dài hạn khá lớn, có tài sản đảm bảo. Công ty có khả năng trả nợ nhưng áp lực lãi suất và trả nợ gốc là đáng kể.', 'Hàng tồn kho tăng mạnh do mua nguyên vật liệu lớn. Không có dự phòng giảm giá, rủi ro thấp nhưng cần theo dõi khả năng tiêu thụ.', 6, 'Công ty hoạt động trong ngành sản xuất bột đá CaCO3, doanh thu giảm nhẹ so với năm trước. Lợi nhuận sau thuế giảm. Nợ vay cao và nhiều giao dịch với bên liên quan. Triển vọng trung bình, cần cải thiện quản trị và kiểm soát nợ.'),
('YBC_2024_consolidated', 'YBC', 2024, 'consolidated', 'Công ty không có giao dịch bất thường với các bên liên quan. Không có công nợ với các thành viên quản lý chủ chốt và các cá nhân có liên quan.', 'Nợ ngắn hạn vượt quá tổng tài sản ngắn hạn 122.062.672.040 đồng, tạo áp lực thanh khoản. Công ty có tài sản thế chấp lớn và được ngân hàng hỗ trợ.', 'Hàng tồn kho chủ yếu là nguyên liệu và thành phẩm, không có thông tin về rủi ro tồn kho.', 3, 'Công ty ghi nhận lợi nhuận sau thuế tăng 95% trong năm 2024, nhưng nợ ngắn hạn cao. Khả năng hoạt động liên tục được hỗ trợ bởi ngân hàng và cải thiện kinh doanh.'),
('YBM_2017_parent', 'YBM', 2017, 'parent', 'Công ty có giao dịch bên liên quan phức tạp với Công ty Cổ phần Nhựa Châu Âu (cổ đông lớn, cùng thành viên quản lý chủ chốt). Giá trị bán hàng cho Nhựa Châu Âu chiếm tỷ trọng lớn (122 tỷ/220 tỷ doanh thu ~55%). Các khoản phải thu từ Nhựa Châu Âu lên đến 18 tỷ VND. Công ty con (Thiết bị điện và Khoáng sản Yên Bái, TALC Việt Nam) được mua trong năm 2017 với tổng vốn đầu tư 33.75 tỷ VND. Có hiện tượng tập trung giao dịch và phụ thuộc vào bên liên quan chính.', 'Tổng nợ vay và nợ thuê tài chính đạt 111.96 tỷ VND, tăng mạnh từ 35.97 tỷ đầu năm. Nợ ngắn hạn chiếm 98.85 tỷ VND (~88% tổng nợ), tạo áp lực trả nợ lớn. Công ty vay từ nhiều nguồn (BIDV, Vietinbank, Chailease, Vietcombank Finance) với lãi suất từ 4.5% đến 8.78%/năm. Nhiều khoản vay được bảo lãnh bởi Công ty Cổ phần Nhựa Châu Âu và được đảm bảo bằng tài sản cố định (3.29 tỷ VND), quyền khai thác mỏ và dự án. Áp lực tài chính đáng kể do chi phí lãi vay 4.82 tỷ VND/năm.', 'Hàng tồn kho tăng mạnh từ 8.95 tỷ lên 43.38 tỷ VND (tăng 387%), phản ánh hoạt động mở rộng sản xuất. Nguyên vật liệu chiếm 25 tỷ VND, thành phẩm 15.6 tỷ VND. Chi phí xây dựng cơ bản dở dang 13 tỷ VND (Giai đoạn 3 dự án Nhà máy). Rủi ro ứ đọng vốn do đầu tư lớn vào tồn kho và dự án xây dựng. Không có dự phòng giảm giá hàng tồn kho.', 6, 'Công ty Cổ phần Khoáng sản Công nghiệp Yên Bái có tốc độ tăng trưởng mạnh trong năm 2017 với doanh thu thuần 220.1 tỷ VND và tỷ suất lợi nhuận gộp 41.3%. Tuy nhiên, dòng tiền hoạt động kinh doanh âm 31.5 tỷ VND do mở rộng mạnh (tồn kho tăng, phải thu tăng). Công ty đang trong giai đoạn đầu tư mở rộng lớn với tổng tài sản tăng từ 87.8 tỷ lên 265.3 tỷ VND. Công ty được hưởng ưu đãi thuế TNDN (miễn thuế 2 năm đầu, giảm 50% trong 4 năm tiếp theo). Rủi ro chính bao gồm: (1) Phụ thuộc lớn vào giao dịch với Công ty Cổ phần Nhựa Châu Âu, (2) Đòn bẩy tài chính cao với nợ vay 112 tỷ VND, (3) Dòng tiền hoạt động kinh doanh âm, (4) Hàng tồn kho và dự án xây dựng dở dang lớn. Công ty đang trong quá trình đăng ký công ty đại chúng.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('YBC_2020_consolidated', 'YBC', 2020, 'consolidated', 'Công ty không có giao dịch đáng kể với các bên liên quan ngoài lương cho ban lãnh đạo. Không phát hiện giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn với các bên liên quan.', 'Áp lực nợ vay rất cao với tổng nợ phải trả (658,47 tỷ VND) vượt xa vốn chủ sở hữu (105,44 tỷ VND). Nợ ngắn hạn (617,21 tỷ VND) vượt tổng tài sản ngắn hạn (363,95 tỷ VND) tạo rủi ro thanh khoản nghiêm trọng. Tài sản cố định đã được thế chấp phần lớn để đảm bảo cho các khoản vay.', 'Hàng tồn kho giảm từ 222,25 tỷ xuống 190,78 tỷ VND nhưng vẫn ở mức cao. Chi phí xây dựng cơ bản dở dang giảm mạnh từ 44,93 tỷ xuống 16,34 tỷ VND, cho thấy tiến độ triển khai các dự án xây dựng.', 8, 'Doanh nghiệp có kết quả kinh doanh có lãi nhưng khả năng hoạt động liên tục bị nghi ngờ do khoản lỗ lũy kế lớn và nợ ngắn hạn vượt tài sản ngắn hạn. Công ty phụ thuộc lớn vào vốn vay ngân hàng với tài sản thế chấp. Rủi ro thanh khoản là mối đe dọa chính, dù công ty vẫn được các ngân hàng hỗ trợ cho vay.'),
('YBC_2022_consolidated', 'YBC', 2022, 'consolidated', 'Công ty không có công nợ với các thành viên quản lý chủ chốt và các bên liên quan tại thời điểm cuối năm. Tuy nhiên, có khoản đầu tư góp vốn vào Công ty Cổ phần Xi măng Yên Bình (tỷ lệ 1,67%) và đã trích lập dự phòng cho khoản đầu tư này. Rủi ro giao dịch bên liên quan ở mức thấp do không phát sinh các giao dịch bất thường hay mua bán chênh lệch lớn.', 'Áp lực nợ vay rất cao. Tổng nợ phải trả (702 tỷ) lớn hơn nhiều vốn chủ sở hữu (115 tỷ), nợ ngắn hạn (547 tỷ) vượt quá tổng tài sản ngắn hạn (361 tỷ). Công ty có khoản lỗ lũy kế 20,5 tỷ. Phần lớn nợ vay được thế chấp bằng tài sản cố định và quyền khai thác khoáng sản. Công ty phụ thuộc lớn vào hạn mức tín dụng từ hai ngân hàng chính (BIDV, Agribank) và các khoản vay cá nhân dài hạn. Khả năng thanh toán ngắn hạn đang bị áp lực nặng nề.', 'Giá trị hàng tồn kho cuối năm là 158,8 tỷ, giảm so với đầu năm (174,2 tỷ), chủ yếu là nguyên liệu vật liệu (144,5 tỷ). Có tồn kho dở dang trong sản xuất. Chi phí xây dựng cơ bản dở dang (47,5 tỷ) với nhiều dự án nâng cấp, cải tạo máy móc thiết bị, cho thấy công ty đang trong giai đoạn đầu tư mở rộng. Rủi ro tồn kho dở dang và dự án chậm tiến độ có thể xảy ra nếu nguồn vốn bị gián đoạn.', 7, 'Công ty hoạt động trong ngành xi măng và khoáng sản, có doanh thu tăng trưởng tốt (năm 2022 đạt 857,6 tỷ, tăng từ 760,5 tỷ) và có lợi nhuận sau thuế 7,5 tỷ. Tuy nhiên, tình hình tài chính đang gặp nhiều khó khăn: lỗ lũy kế lớn, nợ ngắn hạn vượt quá tài sản ngắn hạn nghiêm trọng, gây nghi ngờ về khả năng hoạt động liên tục. Công ty đang trong giai đoạn đầu tư mạnh vào mở rộng sản xuất, dẫn đến nợ vay tăng cao và áp lực tài chính. Sức khỏe tài chính ở mức rủi ro cao, triển vọng đầu tư phụ thuộc vào khả năng quản lý dòng tiền, trả nợ và triển khai dự án đầu tư hiệu quả.'),
('YBC_2021_consolidated', 'YBC', 2021, 'consolidated', 'Giao dịch với bên liên quan thấp. Theo thuyết minh VIII.1, Công ty không có công nợ với các thành viên quản lý chủ chốt và các bên liên quan khác tại thời điểm kết thúc năm. Có khoản vay Clinker 1,76 tỷ từ Công ty CP Xi măng Yên Bình (Công ty mà Công ty góp vốn 1,67%) trong phải trả ngắn hạn khác, nhưng giá trị nhỏ và mang tính chất giao dịch thương mại bình thường. Không phát hiện giao dịch bất thường đáng ngờ với các bên liên quan.', 'Áp lực nợ vay RẤT LỚN. Tổng nợ phải trả 687,2 tỷ VND gấp 6,4 lần vốn chủ sở hữu (107,5 tỷ). Nợ vay và nợ thuê tài chính ngắn hạn 281,9 tỷ và dài hạn 77,5 tỷ, tổng cộng 359,4 tỷ. Chi phí lãi vay năm 2021 lên đến 29,6 tỷ VND, chiếm phần lớn lợi nhuận gộp (52,1 tỷ). Nợ ngắn hạn vượt tài sản ngắn hạn 190,6 tỷ cho thấy áp lực thanh khoản nghiêm trọng. Tuy nhiên, tài sản cố định có nguyên giá và giá trị còn lại lần lượt 475,5 tỷ và 166,1 tỷ đã được thế chấp đảm bảo cho các khoản vay trung hạn tại BIDV và Agribank. Công ty vẫn được ngân hàng tiếp tục cho vay, phản ánh niềm tin từ phía ngân hàng.', 'Rủi ro tồn kho ở mức TRUNG BÌNH. Hàng tồn kho giảm từ 190,8 tỷ xuống 174,2 tỷ VND, cho thấy quản lý tồn kho cải thiện. Tuy nhiên, chi phí XDCBDD tăng mạnh từ 16,3 tỷ lên 48,9 tỷ (+200%), phản ánh hoạt động đầu tư mở rộng quy mô lớn (dây chuyền lò nung GĐ3 hơn 31 tỷ). Cần giám sát tiến độ và hiệu quả của các dự án đầu tư này. Chi phí sản xuất dở dang giảm mạnh từ 5,9 tỷ xuống 2 tỷ cho thấy hoạt động sản xuất ổn định.', 6, 'Công ty Cổ phần Xi măng và Khoáng sản Yên Bái đang trong giai đoạn PHỤC HỒI và MỞ RỘNG. Năm 2021, Công ty đạt doanh thu thuần 760,6 tỷ VND, lợi nhuận sau thuế 2,07 tỷ VND (tăng từ 1,60 tỷ năm 2020). Điểm tích cực: Công ty có lãi liên tục, dòng tiền từ hoạt động kinh doanh dương 27,9 tỷ (so với -16,8 tỷ năm trước), được ngân hàng lớn tiếp tục tài trợ. Điểm rủi ro: (1) Khoản lỗ lũy kế 28,1 tỷ chiếm 23,8% vốn chủ sở hữu; (2) Nợ ngắn hạn vượt tài sản ngắn hạn 190,6 tỷ; (3) Tỷ lệ đòn bẩy nợ rất cao; (4) Chi phí lãi vay chiếm tỷ trọng lớn trong lợi nhuận gộp. Công ty đang đẩy mạnh đầu tư xây dựng dây chuyền mới (XDCBDD tăng 200%) nhằm nâng cao năng lực sản xuất. Triển vọng trung hạn phụ thuộc vào khả năng quản lý dòng tiền, kiểm soát chi phí lãi vay và thành công của các dự án đầu tư mở rộng. Điểm rủi ro quản trị 6/10 phản ánh tình hình tài chính căng thẳng nhưng vẫn có lộ trình cải thiện.'),
('YBC_2017_consolidated', 'YBC', 2017, 'consolidated', 'Công ty có giao dịch mua bán hàng hóa, dịch vụ với Công ty TNHH Thương Mại Dịch Vụ Vận Tải Tây Bắc - công ty có liên quan đến thành viên HĐQT. Giá trị giao dịch lớn (mua hàng hơn 25 tỷ, bán hàng gần 500 triệu) và có bù trừ công nợ. Cần kiểm soát chặt chẽ để tránh xung đột lợi ích và đảm bảo giá giao dịch là thị trường.', 'Áp lực nợ vay rất lớn với tổng nợ vay ngắn hạn 254,5 tỷ và dài hạn 73,7 tỷ. Nợ ngắn hạn vượt quá tài sản ngắn hạn 251,6 tỷ cho thấy rủi ro thanh khoản nghiêm trọng. Tuy nhiên, công ty vẫn được các ngân hàng lớn cho vay với tài sản thế chấp là quyền khai thác khoáng sản và nhiều TSCĐ. Chi phí lãi vay năm 2017 là 30,2 tỷ, chiếm tỷ trọng lớn trong chi phí tài chính.', 'Hàng tồn kho tăng từ 132,5 tỷ lên 158,5 tỷ, chủ yếu là nguyên vật liệu tăng 25,8 tỷ. Chi phí xây dựng cơ bản dở dang tăng mạnh từ 21,1 tỷ lên 67,3 tỷ cho thấy công ty đang tích cực đầu tư mở rộng. Rủi ro tồn kho ở mức trung bình khi sản phẩm xi măng có nhu cầu thị trường ổn định.', 7, 'Công ty có quy mô trung bình với doanh thu 490,8 tỷ, lợi nhuận sau thuế 3,1 tỷ (đã có lãi trở lại sau lỗ lũy kế lớn). Điểm đáng lo ngại nhất là khoản lỗ lũy kế 37,3 tỷ và nợ ngắn hạn vượt quá tài sản ngắn hạn. Tuy nhiên, công ty có lợi thế về nguồn nguyên liệu đá vôi tại chỗ, được ngân hàng tiếp tục tài trợ và đang mở rộng sản xuất. Triển vọng trung hạn phụ thuộc vào khả năng cải thiện biên lợi nhuận gộp (hiện tại 10,6%) và kiểm soát chi phí tài chính.'),
('YBC_2019_consolidated', 'YBC', 2019, 'consolidated', 'Giao dịch với Công ty TNHH Thương mại Dịch vụ Vận tải Tây Bắc (liên quan đến ông Phạm Việt Thương, Ủy viên HĐQT) có giá trị phát sinh trong năm nhưng không nêu rõ lãi suất hay điều kiện đặc biệt. Giá trị phải thu và phải trả với bên này khá lớn, cần đánh giá tính minh bạch và điều kiện thị trường.', 'Nợ vay rất lớn (gần 304 tỷ VND cuối năm), chiếm tỷ trọng cao trong tổng nguồn vốn. Nợ ngắn hạn vượt quá tài sản ngắn hạn, áp lực trả nợ lớn. Công ty phụ thuộc nhiều vào vay ngân hàng (BIDV, Agribank) với lãi suất thả nổi, rủi ro lãi suất. Tài sản thế chấp chủ yếu là TSCĐ và quyền khai thác khoáng sản.', 'Hàng tồn kho lớn (222 tỷ VND), chủ yếu là nguyên vật liệu và chi phí sản xuất dở dang. Chi phí xây dựng cơ bản dở dang tăng mạnh, có thể do đầu tư mở rộng. Cần theo dõi tiến độ và hiệu quả các dự án này để tránh ứ đọng vốn.', 5, 'Công ty có quy mô tài sản và doanh thu tăng, song lợi nhuận sau thuế giảm do chi phí tài chính (lãi vay) rất lớn. Tình hình tài chính có dấu hiệu rủi ro thanh khoản nghiêm trọng (lỗ lũy kế, nợ ngắn hạn vượt tài sản ngắn hạn), tuy nhiên hoạt động kinh doanh cốt lõi vẫn có lãi và có chiều hướng tăng trưởng. Khả năng hoạt động liên tục phụ thuộc vào việc tiếp tục được cấp tín dụng từ các ngân hàng. Điểm rủi ro quản trị ở mức trung bình do có giao dịch với bên liên quan nhưng chưa phát hiện bất thường rõ rệt.'),
('YBC_2018_consolidated', 'YBC', 2018, 'consolidated', 'Công ty có giao dịch mua bán hàng hóa/dịch vụ thường xuyên với Công ty TNHH Thương Mại Dịch Vụ Vận Tải Tây Bắc do người liên quan quản lý. Giá trị giao dịch lớn (hơn 14 tỷ VNĐ trong năm 2018). Cần kiểm soát mức giá và điều kiện giao dịch công bằng.', 'Công ty có áp lực nợ vay lớn, tổng nợ vay ngắn và dài hạn đạt hơn 302 tỷ VNĐ. Dòng tiền từ hoạt động kinh doanh không đủ bù đắp toàn bộ nghĩa vụ trả nợ, phụ thuộc vào việc tiếp tục vay mới. Phần lớn tài sản cố định đã được thế chấp cho các khoản vay ngân hàng.', 'Hàng tồn kho tăng mạnh 39.5% so với đầu năm, chủ yếu do nguyên vật liệu và chi phí sản xuất dở dang. Điều này phản ánh hoạt động đầu tư mở rộng sản xuất nhưng cũng tiềm ẩn rủi ro ứ đọng nếu nhu cầu thị trường không tăng tương ứng.', 6, 'Công ty đang trong giai đoạn đầu tư mở rộng mạnh mẽ, cải thiện sản lượng và doanh thu. Tuy nhiên, gánh nặng tài chính từ lãi vay rất lớn, lỗ lũy kế vẫn cao và phụ thuộc vào nguồn vốn vay. Khả năng hoạt động liên tục được đảm bảo nhờ sự hỗ trợ từ ngân hàng và hướng kinh doanh tích cực. Rủi ro thanh khoản và rủi ro nợ vay là đáng kể.'),
('XPH_2024_consolidated', 'XPH', 2024, 'consolidated', 'Doanh nghiệp có giao dịch lớn với các bên liên quan (thuộc Tập đoàn Hóa chất Việt Nam). Rủi ro đáng chú ý là khoản phải thu lớn (trên 13 tỷ VND) từ Công ty TNHH Thương mại Dịch vụ và Đầu tư Á Châu (không phải bên liên quan theo BCTC) đã phải trích lập dự phòng 100% và đang trong quá trình kiện tụng. Các giao dịch mua/bán hàng với bên liên quan (cùng công ty mẹ) có vẻ diễn ra thường xuyên nhưng không nêu rõ điều kiện giá.', 'Công ty không có nợ vay ngân hàng (dài hạn và ngắn hạn). Các khoản nợ chủ yếu là phải trả người bán ngắn hạn và các khoản phải nộp nhà nước. Áp lực nợ vay thấp, thanh khoản (tiền mặt và tương đương tiền) giảm so với đầu kỳ nhưng vẫn đủ để trang trải các khoản nợ ngắn hạn.', 'Rủi ro tồn kho cao. Hàng tồn kho có giá trị lớn (trên 21.5 tỷ VND), trong đó dự phòng giảm giá hàng tồn kho tăng mạnh từ 4.46 tỷ lên 5.5 tỷ VND, tập trung vào nguyên vật liệu (hết hạn, hỏng) và thành phẩm. Hàng tồn kho ứ động, kém phẩm chất được xác định là 5.5 tỷ VND, cho thấy vấn đề về chất lượng và khả năng tiêu thụ.', 6, 'Tình hình kinh doanh gặp nhiều khó khăn, doanh thu giảm so với kế hoạch, chi phí cao dẫn đến lỗ ròng 7.17 tỷ VND trong năm 2024 (đã giảm lỗ so với năm 2023). Tuy nhiên, công ty không có nợ vay tài chính, giảm đáng kể chi phí bán hàng và quản lý. Điểm sáng là khoản đầu tư lớn vào dự án bất động sản (Xavinco) và hoạt động cho vay/gửi tiền có lãi. Sức khỏe tài chính yếu do lỗ lũy kế lớn (gần 80.9 tỷ VND), triển vọng phụ thuộc vào khả năng cải thiện kinh doanh cốt lõi và kết quả từ khoản đầu tư bất động sản.'),
('XPH_2023_consolidated', 'XPH', 2023, 'consolidated', 'Công ty có phát sinh doanh thu bán hàng và mua hàng với các bên liên quan thuộc Tập đoàn Hóa chất Việt Nam. Tổng doanh thu từ các bên liên quan năm 2023 là 1,69 tỷ VND và tổng mua hàng là 2,12 tỷ VND. Mức giao dịch này không lớn so với tổng doanh thu và giá vốn, nhưng cần lưu ý tính minh bạch của giá chuyển nhượng. Không phát hiện giao dịch bất thường rõ ràng như cho vay không lãi suất hay chênh lệch giá lớn.', 'Công ty không có nợ vay ngân hàng (không ghi nhận chi phí lãi vay). Nợ phải trả chủ yếu là phải trả người bán và chi phí phải trả ngắn hạn với tổng giá trị khoảng 4,15 tỷ VND tại ngày 31/12/2023, chiếm tỷ trọng nhỏ so với tổng tài sản. Áp lực nợ thấp, khả năng thanh toán đảm bảo bằng dòng tiền hoạt động kinh doanh và tiền gửi ngân hàng.', 'Hàng tồn kho có dự phòng giảm giá 4,46 tỷ VND, cho thấy một phần hàng tồn kho bị ứ đọng, kém chất lượng hoặc mất khả năng tiêu thụ. Giá trị hàng tồn kho ghi sổ sau dự phòng là 17,75 tỷ VND, chiếm tỷ trọng đáng kể trong tài sản ngắn hạn. Rủi ro tồn kho ở mức trung bình do dự phòng đã được trích lập thận trọng.', 5, 'Công ty lỗ liên tục trong hai năm 2022 và 2023 (lỗ lũy kế hơn 73,69 tỷ VND), doanh thu sụt giảm mạnh năm 2023. Nguyên nhân chính là do trích lập dự phòng nợ phải thu khó đòi và giảm giá hàng tồn kho lớn. Công ty không có nợ vay tài chính, giảm áp lực tài chính. Tuy nhiên, hoạt động kinh doanh cốt lõi suy yếu, tồn kho ứ đọng. Đầu tư dài hạn vào Công ty CP Bất động sản Xavinco có giá trị lớn nhưng chưa mang lại lợi nhuận. Triển vọng đầu tư tiêu cực trong ngắn hạn.'),
('XPH_2025_consolidated', 'XPH', 2025, 'consolidated', 'Công ty có nhiều giao dịch mua bán với các bên liên quan thuộc Tập đoàn Hóa chất Việt Nam với giá trị lớn, có thể tạo rủi ro về giá chuyển nhượng không theo giá thị trường. Tuy nhiên, không có bằng chứng rõ ràng về giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Nợ ngắn hạn chủ yếu là phải trả nhà cung cấp, không có nợ vay lãi suất. Áp lực nợ thấp, công ty có đủ tài sản ngắn hạn như tiền gửi và đầu tư để thanh toán. Tài sản thế chấp không đáng kể.', 'Hàng tồn kho có dự phòng giảm giá 4.74 tỷ VND, chiếm khoảng 23% giá trị tồn kho, cho thấy rủi ro về hàng tồn kho cũ hoặc khó tiêu thụ. Công ty cần cải thiện quản lý tồn kho để giảm dự phòng.', 3, 'Công ty đã chuyển từ lỗ sang lãi trong năm 2025 với lợi nhuận nhỏ 36.8 triệu VND. Doanh thu tăng mạnh 2.5 lần so với 2024 nhờ kinh doanh thương mại, nhưng chi phí cũng tăng. Công ty nhận được cổ tức lớn từ Công ty Bất động sản Xavinco. Tuy nhiên, còn nhiều thách thức trong tiêu thụ sản phẩm, quản lý hàng tồn kho và giao dịch với bên liên quan. Sức khỏe tài chính cải thiện nhưng triển vọng đầu tư còn thận trọng.'),
('XPH_2020_consolidated', 'XPH', 2020, 'consolidated', 'Thuyết minh giao dịch với các bên liên quan chỉ trình bày thù lao HĐQT, BKS (175,5 triệu) và thu nhập Ban Giám đốc (321,4 triệu). Không có thông tin chi tiết về giao dịch mua bán, cho vay với các bên liên quan khác. Công ty là doanh nghiệp nhà nước cổ phần hóa với Tập đoàn Hóa chất Việt Nam sở hữu 80% vốn. Đầu tư góp vốn 71,25 tỷ vào Công ty CP Bất động sản Xavinco cần lưu ý do hoạt động kinh doanh cốt lõi là sản xuất xà phòng.', 'Công ty có tình hình tài chính lành mạnh: nợ vay ngắn hạn về 0 tại thời điểm cuối năm (đầu năm 2,98 tỷ). Chỉ có 100 triệu phải trả dài hạn khác là đặt cọc. Tiền mặt và tương đương tiền đạt 7,75 tỷ, đầu tư tài chính ngắn hạn 19,5 tỷ (tiền gửi có kỳ hạn). Hệ số nợ/vốn chủ sở hữu rất thấp, áp lực trả nợ không đáng kể.', 'Tồn kho tăng vọt từ 7,43 tỷ lên 23,83 tỷ đồng (tăng 220%), trong đó nguyên vật liệu tăng từ 4,36 tỷ lên 13,69 tỷ và thành phẩm tăng từ 3,73 tỷ lên 10,04 tỷ. Dự phòng giảm giá giảm từ 709 triệu xuống 318 triệu. Hàng tồn kho ứ đọng, kém phẩm chất 318,5 triệu. Mức tăng tồn kho lớn cần được theo dõi sát để đánh giá khả năng tiêu thụ và rủi ro giảm giá.', 5, 'Công ty Xà phòng Hà Nội đã phục hồi từ lỗ 5,86 tỷ năm 2019 sang lãi 41,9 triệu năm 2020 nhờ tăng sản lượng tiêu thụ 77%. Biên lợi nhuận gộp đạt 23,36% (11,38 tỷ/48,72 tỷ doanh thu thuần). Công ty có vị thế tài chính an toàn với nợ vay gần như bằng 0 và tiền mặt dồi dào. Tuy nhiên, doanh thu hoạt động thương mại giảm 83%, tồn kho tăng 220% cần được giám sát. Đầu tư 71,25 tỷ vào bất động sản (Xavinco) chiếm tỷ trọng lớn so với vốn chủ sở hữu 193,5 tỷ. Công ty vẫn có lợi nhuận lũy kế âm 31,89 tỷ, chưa có kế hoạch chia cổ tức.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('XPH_2021_consolidated', 'XPH', 2021, 'consolidated', 'Công ty có giao dịch với các bên liên quan (cùng công ty mẹ) với tổng doanh thu 345 triệu VND, chiếm tỷ trọng nhỏ trong tổng doanh thu. Có khoản phải thu với Công ty CP Phân bón và Hóa chất Cần Thơ 221 triệu VND. Không phát hiện giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn, rủi ro ở mức thấp.', 'Công ty không có nợ vay ngân hàng, chỉ có nợ phải trả ngắn hạn và dài hạn. Nợ ngắn hạn chủ yếu là phải trả người bán và các khoản phải nộp khác. Công ty có dòng tiền hoạt động kinh doanh âm nhưng có tiền gửi ngân hàng đáo hạn. Áp lực nợ không cao.', 'Hàng tồn kho tăng, có trích lập dự phòng giảm giá. Kiểm toán viên nêu vấn đề chênh lệch giữa sổ sách và kiểm kê thực tế (1.627 triệu VND), cho thấy rủi ro về tính chính xác của tồn kho.', 8, 'Công ty lỗ nặng năm 2021 (lỗ 15.262 triệu VND) do giá vốn tăng mạnh, chi phí bán hàng và quản lý tăng cao, trích lập dự phòng phải thu khó đòi lớn. Kiểm toán viên từ chối đưa ra ý kiến do nhiều vấn đề: công nợ không đối chiếu, chênh lệch tồn kho, TSCĐ và chi phí trả trước không xác định được. Kiểm soát nội bộ có nhiều yếu kém. Triển vọng tài chính tiêu cực.'),
('XPH_2022_consolidated', 'XPH', 2022, 'consolidated', 'Có giao dịch với các bên liên quan bao gồm bán hàng, mua hàng và chi phí thù lao cho ban lãnh đạo. Khoản phải thu từ Công ty TNHH Đào tạo và Truyền thông Á Châu có nguy cơ khó đòi cao với số tiền ứng trước 4.296 triệu đồng và tiền hàng chưa thanh toán 8.752 triệu đồng. Giao dịch thù lao cho HĐQT và ban kiểm soát là chi phí hành chính thông thường.', 'Nợ phải trả chủ yếu là ngắn hạn với tổng nợ khoảng 3.185 tỷ đồng, không có nợ vay tài chính dài hạn. Công ty có khả năng thanh toán từ dòng tiền hoạt động và đầu tư tài chính, áp lực nợ thấp.', 'Hàng tồn kho có dự phòng giảm giá 2.243 tỷ đồng cho thành phẩm, tăng mạnh so với 280 triệu đồng đầu năm, cho thấy rủi ro giảm giá hàng tồn kho. Nguyên liệu vật liệu có giá trị lớn nhưng không có dự phòng.', 5, 'Công ty đang lỗ 6.885 tỷ đồng năm 2022 do trích lập dự phòng nợ phải thu khó đòi và hàng tồn kho, doanh thu giảm so với năm trước. Ý kiến kiểm toán ngoại trừ do vấn đề phải thu từ Công ty Á Châu, và có điều chỉnh hồi tố các số liệu năm 2021. Tuy nhiên, không có nợ vay tài chính và có dòng tiền đầu tư dương từ lãi tiền gửi và cổ tức. Quản trị có rủi ro trung bình do các vấn đề kế toán và giao dịch bên liên quan.'),
('XPH_2017_consolidated', 'XPH', 2017, 'consolidated', 'Công ty có quan hệ và giao dịch với các bên liên quan thuộc cùng Tập đoàn Hóa chất Việt Nam và một công ty đầu tư dài hạn (Xavinco). Giao dịch đáng chú ý nhất là nhận cổ tức 8.3 tỷ VND từ Xavinco trong năm 2017, một khoản thu nhập tài chính lớn. Không có bằng chứng về giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Công ty gần như không có nợ vay tài chính (cả ngắn hạn và dài hạn đều bằng 0). Nợ phải trả chủ yếu là các khoản nợ thương mại và thuế phát sinh trong hoạt động kinh doanh thông thường, không có áp lực trả nợ lãi vay. Tình hình tài chính rất an toàn về mặt đòn bẩy.', 'Hàng tồn kho đã trích lập dự phòng giảm giá 256.554.020 VND do hàng hóa ứ đọng lâu, kém, mất phẩm chất. Các dự án xây dựng dở dang (Nhà máy Mê Linh, Văn phòng Nguyễn Trãi, Dây chuyền nhựa) vẫn đang trong quá trình đầu tư, giá trị chưa được quyết toán cuối cùng.', 4, 'Công ty có sức khỏe tài cơ bản tốt với cấu trúc vốn an toàn (gần như không có nợ vay), sở hữu lượng lớn đầu tư tài chính và tiền gửi ngân hang sinh lãi. Tuy nhiên, hoạt động kinh doanh cốt lõi (sản xuất kinh doanh hóa chất, chất tẩy rửa) đang gặp khó khăn lớn do mất hợp đồng gia công chính với Unilever, dẫn đến doanh thu sụt giảm mạnh. Công ty đang dựa vào thu nhập tài chính (tiền lãi, cổ tức) để duy trì lợi nhuận. Điểm rủi ro trung bình, chủ yếu đến từ hoạt động kinh doanh thu hẹp và các khoản đầu tư dài hạn vào bất động sản (Xavinco) chưa rõ hiệu quả cuối cùng.'),
('XPH_2019_consolidated', 'XPH', 2019, 'consolidated', 'Giao dịch với các bên liên quan diễn ra với số tiền lớn, nhưng không có dấu hiệu bất thường rõ ràng về lãi suất hoặc chênh lệch giá. Tuy nhiên, cần theo dõi mối quan hệ giữa công ty và các đối tác này.', 'Nợ vay ngắn hạn ở mức vừa phải (khoảng 2.977 tỷ VNĐ) và không có nợ dài hạn. Công ty có lượng tiền mặt và đầu tư ngắn hạn dồi dào, giúp giảm áp lực thanh toán. Rủi ro nợ vay thấp.', 'Hàng tồn kho có dự phòng giảm giá đáng kể, đặc biệt thành phẩm với dự phòng hơn 591 tỷ VNĐ, cho thấy rủi ro ứ đọng và mất phẩm chất. Công ty cần cải thiện quản lý tồn kho.', 5, 'Công ty ghi nhận tăng trưởng doanh thu mạnh trong năm 2019 nhưng vẫn lỗ do chi phí cố định cao và dự phòng tồn kho lớn. Cơ cấu tài sản an toàn với nợ vay thấp và tiền mặt nhiều. Tuy nhiên, hiệu quả kinh doanh chưa cao và cần tập trung vào kiểm soát chi phí và tối ưu hóa tồn kho.'),
('XPH_2018_consolidated', 'XPH', 2018, 'consolidated', '无明显异常关联交易，主要交易为董事和高管薪酬，符合规定。', '公司债务以应付账款为主，无银行借款，债务风险较低。', '存货存在跌价准备，表明部分原材料或成品可能滞销；在建工程多年未变，可能存在停滞风险。', 3, '公司2018年经营亏损，但债务水平较低，现金流依赖投资活动；财务风险可控，但经营有待改善。'),
('XPH_2015_consolidated', 'XPH', 2015, 'consolidated', 'Giao dịch với bên liên quan chủ yếu là mua bán hàng hóa thương mại với các công ty cùng tập đoàn và công ty đầu tư, không có dấu hiệu bất thường như cho vay không lãi suất hay giao dịch giá chênh lệch lớn. Số dư phải thu và phải trả với các bên liên quan không đáng kể so với quy mô tài sản.', 'Công ty không có nợ vay ngân hàng (vay ngắn hạn = 0), nợ phải trả chủ yếu là nợ thương mại ngắn hạn với nhiều nhà cung cấp. Áp lực trả nợ thấp, tài sản thế chấp không có. Tuy nhiên, công ty có quỹ khen thưởng phúc lợi và các khoản phải trả khác, nhưng không gây áp lực lớn.', 'Hàng tồn kho giảm mạnh từ 24.5 tỷ VNĐ xuống 3.2 tỷ VNĐ do đã thanh lý toàn bộ hàng tồn kho ứ đọng, kém phẩm chất và hoàn nhập dự phòng. Rủi ro tồn kho thấp, không có dự án xây dựng dở dang lớn bị ứ đọng.', 3, 'Công ty lỗ nặng trong năm 2015 (lỗ sau thuế 9.2 tỷ VNĐ) do doanh thu giảm mạnh 57% so với năm trước. Lợi nhuận gộp dương nhưng không đủ bù chi phí bán hàng và quản lý. Công ty có khoản đầu tư dài hạn 71.25 tỷ VNĐ vào Công ty BĐS Xavinco nhưng chưa mang lại lợi nhuận. Điểm mạnh là công ty không nợ vay và có lượng tiền mặt lớn (45.3 tỷ VNĐ). Tuy nhiên, hoạt động kinh doanh chính suy giảm, triển vọng phụ thuộc vào việc thoái vốn của Tập đoàn Hóa chất Việt Nam và hiệu quả của khoản đầu tư bất động sản.'),
('XMP_2025_consolidated', 'XMP', 2025, 'consolidated', 'Công ty có nhiều giao dịch với bên liên quan bao gồm mua bán hàng hóa, cho vay, chia cổ tức, thuê văn phòng và cho thuê xe. Các giao dịch này có giá trị đáng kể nhưng không có dấu hiệu bất thường rõ ràng.', 'Nợ ngắn hạn vượt tài sản ngắn hạn, gây áp lực thanh toán. Công ty phụ thuộc vào hoạt động kinh doanh và huy động vốn để thanh toán nợ. Tài sản thế chấp chủ yếu là toàn bộ dự án thủy điện.', 'Hàng tồn kho chủ yếu là nguyên liệu và công cụ, giá trị nhỏ so với tổng tài sản, rủi ro tồn kho thấp.', 7, 'Công ty hoạt động trong lĩnh vực thủy điện, có lợi nhuận tăng trưởng mạnh nhưng gặp thách thức về thanh khoản. Tỷ suất lợi nhuận gộp cao, nhưng nợ vay lớn dẫn đến chi phí lãi vay đáng kể. Khả năng hoạt động liên tục phụ thuộc vào kết quả kinh doanh và khả năng huy động vốn.'),
('XMP_2024_consolidated', 'XMP', 2024, 'consolidated', 'Công ty có mạng lưới giao dịch bên liên quan phức tạp với nhiều công ty con của công ty mẹ và các cá nhân trong ban lãnh đạo. Đáng chú ý: (1) Công ty vay tiền từ Phó Tổng Giám đốc Phạm Tiến Luật (2,2 tỷ), Chủ tịch HĐQT Trịnh Nguyên Khánh (604 triệu), và Thành viên HĐQT Nguyễn Thanh Phương (2 tỷ) với lãi suất 8,9%/năm, trong khi có thể vay ngân hàng với điều kiện tốt hơn; (2) Mua hàng hóa dịch vụ trị giá 3,5 tỷ từ Công ty CP Cơ điện VCP và Công ty CP Xây dựng và Năng lượng VCP (công ty mẹ); (3) Chi phí thuê văn phòng 324 triệu/năm từ công ty mẹ; (4) Các giao dịch này chưa có dấu hiệu bất thường rõ ràng nhưng cần được giám sát chặt chẽ.', 'Áp lực nợ vay rất lớn với tổng nợ vay khoảng 204,7 tỷ VND (chiếm 53% tổng tài sản). Nợ ngắn hạn 64,3 tỷ VND vượt xa tiền mặt hiện có (1,8 tỷ), tạo rủi ro thanh khoản nghiêm trọng. Dài hạn đến hạn trả 27,8 tỷ VND cộng thêm nợ ngắn hạn tạo tổng nghĩa vụ ngắn hạn cao. Tài sản cố định và quyền sử dụng đất đã được thế chấp toàn bộ cho khoản vay ngân hàng (SHB). Tuy nhiên, Công ty đã giảm nợ vay từ 227,3 tỷ xuống 204,7 tỷ VND trong năm và dòng tiền hoạt động kinh doanh dương mạnh (40,1 tỷ VND) hỗ trợ khả năng trả nợ.', 'Rủi ro tồn kho thấp. Hàng tồn kho chủ yếu là nguyên liệu, vật liệu (2,04 tỷ) và công cụ, dụng cụ (48 triệu) phục vụ sản xuất điện, không có dự án xây dựng dở dang. Giá trị tồn kho tăng nhẹ 8,6% so với đầu năm, phù hợp với hoạt động sản xuất kinh doanh. Không có thông tin về dự phòng giảm giá tồn kho trong năm.', 6, 'Công ty Thủy điện Xuân Minh là doanh nghiệp có hoạt động kinh doanh cốt lõi hiệu quả với biên lợi nhuận gộp cao (58,4%). Năm 2024 ghi nhận kết quả kinh doanh ấn tượng với lợi nhuận sau thuế tăng 261% so với năm trước nhờ thủy văn thuận lợi và giảm mạnh chi phí lãi vay. Tuy nhiên, Công ty đối mặt với thách thức thanh khoản ngắn hạn nghiêm trọng khi nợ ngắn hạn vượt tài sản ngắn hạn 58,8 tỷ VND. Tổng nợ vay 204,7 tỷ VND (53% tổng tài sản) là gánh nặng lớn. Công ty đang trong giai đoạn ưu đãi thuế (10% thuế suất, giảm 50% thuế) giúp tối ưu lợi nhuận. Dòng tiền hoạt động kinh doanh mạnh (40,1 tỷ VND) là điểm tích cực, cho thấy khả năng tạo tiền từ hoạt động sản xuất kinh doanh. Ban lãnh đạo tin tưởng vào khả năng hoạt động liên tục dựa trên kế hoạch gia hạn vay và dòng tiền dự kiến. Triển vọng đầu tư trung hạn phụ thuộc lớn vào điều kiện thủy văn và khả năng quản lý nợ.'),
('XMP_2022_consolidated', 'XMP', 2022, 'consolidated', 'Doanh nghiệp có nhiều giao dịch với các bên liên quan, bao gồm mua hàng hóa dịch vụ, chi phí thuê văn phòng, và cho vay lãi suất thấp. Các giao dịch này có thể gây rủi ro về xung đột lợi ích và giá cả không công bằng.', 'Nợ vay cao, đặc biệt nợ ngắn hạn vượt quá tài sản ngắn hạn, gây áp lực thanh khoản. Có khoản nợ dài hạn đến hạn trả trong ngắn hạn. Công ty đã có biện pháp nhưng vẫn còn yếu tố không chắc chắn về hoạt động liên tục.', 'Hàng tồn kho chủ yếu là nguyên liệu, vật liệu và công cụ, dụng cụ, mức tồn kho không quá lớn nên rủi ro thấp.', 7, 'Công ty hoạt động trong lĩnh vực thủy điện với doanh thu ổn định, lợi nhuận tăng. Tuy nhiên, áp lực nợ vay và giao dịch bên liên quan là điểm cần lưu ý. Triển vọng phụ thuộc vào khả năng quản lý nợ và dòng tiền.'),
('XMP_2020_consolidated', 'XMP', 2020, 'consolidated', 'Công ty có giao dịch thường xuyên với các bên liên quan, đặc biệt là công ty mẹ Công ty CP Xây dựng và Năng lượng VCP, bao gồm mua hàng, vay và trả nợ. Số dư phải trả lớn với công ty mẹ (hơn 6 tỷ đồng trả người bán và 9.18 tỷ đồng cổ tức) cho thấy sự phụ thuộc vào nguồn vốn từ công ty mẹ. Tuy nhiên, không có dấu hiệu giao dịch bất thường về giá hay điều kiện.', 'Công ty có nợ vay lớn, chủ yếu là dài hạn từ ngân hàng SHB, với tài sản thế chấp là toàn bộ dự án thủy điện. Chi phí lãi vay cao (26.1 tỷ đồng năm 2020) làm giảm lợi nhuận. Công ty vẫn thanh toán nợ đúng hạn, nhưng áp lực tài chính lớn do tài sản ngắn hạn thấp hơn nợ ngắn hạn.', 'Hàng tồn kho chỉ gồm nguyên liệu vật liệu và công cụ dụng cụ với giá trị nhỏ (656.7 triệu đồng), không có dự phòng giảm giá. Rủi ro tồn kho thấp, không có dấu hiệu ứ đọng.', 5, 'Công ty hoạt động trong lĩnh vực thủy điện, doanh thu và lợi nhuận giảm trong năm 2020. Cơ cấu tài chính mất cân đối với nợ vay lớn, nhưng được hỗ trợ bởi công ty mẹ. Công ty được hưởng ưu đãi thuế, giúp giảm chi phí thuế. Tuy nhiên, triển vọng phụ thuộc vào sản lượng điện và khả năng quản lý nợ. Nên theo dõi sát giao dịch với bên liên quan và dòng tiền.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('XMD_2025_consolidated', 'XMD', 2025, 'consolidated', 'Doanh nghiệp có mối quan hệ kinh doanh chặt chẽ với Công ty mẹ (Công ty Cổ phần Đầu tư và Xây dựng Xuân Mai) và các công ty có cùng công ty mẹ. Tổng giao dịch mua bán với bên liên quan chiếm tỷ trọng rất lớn trong doanh thu và chi phí. Cụ thể, doanh thu bán hàng cho Công ty mẹ chiếm khoảng 57% tổng doanh thu thuần, và chi phí mua hàng từ Công ty mẹ chiếm khoảng 66% giá vốn. Số dư phải thu từ Công ty mẹ cuối năm là 28.4 tỷ VNĐ, phải trả cho Công ty mẹ là 54.9 tỷ VNĐ. Mối quan hệ giao dịch tập trung này tiềm ẩn rủi ro về giá chuyển nhượng và phụ thuộc vào bên liên quan. Tuy nhiên, chưa có bằng chứng về giao dịch bất thường rõ ràng như cho vay không lãi suất hay mua bán chênh lệch bất hợp lý.', 'Tổng nợ vay ngắn hạn cuối năm 2025 là 4.298 tỷ VNĐ, tăng nhẹ so với đầu năm. Công ty có 3 khoản vay chính từ Vietcombank và BIDV chi nhánh Vĩnh Phúc. Khoản vay dài hạn đã đáo hạn và chuyển thành nợ ngắn hạn. Các khoản vay được đảm bảo bằng tài sản trên đất, nhà xưởng và máy móc thiết bị. Chi phí lãi vay năm 2025 giảm đáng kể còn 362 triệu VNĐ so với 863 triệu VNĐ năm trước, cho thấy áp lực lãi vay đã giảm. Tuy nhiên, tỷ lệ nợ phải trả/vốn chủ sở hữu vẫn ở mức cao (87 tỷ/46.6 tỷ = 1.87 lần), đòi hỏi quản lý dòng tiền chặt chẽ.', 'Hàng tồn kho tăng mạnh từ 18.8 tỷ VNĐ đầu năm lên 44.4 tỷ VNĐ cuối năm, chủ yếu do thành phẩm tăng từ 7.6 tỷ lên 31.9 tỷ VNĐ. Điều này phản ánh hoạt động sản xuất kinh doanh mở rộng, nhưng cũng đặt ra rủi ro nếu nhu cầu thị trường giảm hoặc giá nguyên liệu đầu vào biến động. Không có dự phòng giảm giá hàng tồn kho, cho thấy công ty đánh giá hàng tồn kho không bị giảm giá tại thời điểm lập báo cáo. Chi phí sản xuất dở dang giảm từ 1.39 tỷ xuống 0.54 tỷ VNĐ.', 5, 'Công ty Cổ phần Xuân Mai - Đạo Tú hoạt động trong lĩnh vực sản xuất vật liệu xây dựng và xây lắp, có doanh thu thuần năm 2025 đạt 201.8 tỷ VNĐ (tăng 45.8% so với năm trước). Lợi nhuận sau thuế đạt 4.1 tỷ VNĐ, tăng 27.9%. Công ty có tỷ suất lợi nhuận gộp ở mức 7.37%, biên lợi nhuận mỏng đặc thù ngành xây dựng. Công ty chịu sự phụ thuộc lớn vào Công ty mẹ và các công ty liên quan trong hệ sinh thái Xuân Mai. Đòn bẩy tài chính ở mức trung bình khá, nợ vay chủ yếu là ngắn hạn. Dòng tiền hoạt động kinh doanh dương 5.7 tỷ VNĐ nhưng giảm mạnh so với năm trước (16.2 tỷ). Công ty còn lỗ lũy kế 2.6 tỷ VNĐ và có số lỗ được chuyển thuế từ các năm trước khoảng 959 triệu VNĐ. Tổng thể, công ty đang trong giai đoạn tăng trưởng nhưng cần cải thiện biên lợi nhuận và giảm dần sự phụ thuộc vào các bên liên quan.'),
('XMP_2021_consolidated', 'XMP', 2021, 'consolidated', 'Công ty có nhiều giao dịch với các bên liên quan, bao gồm mua bán hàng hóa, cho vay và trả cổ tức. Các giao dịch này có thể tiềm ẩn rủi ro về giá cả không công bằng hoặc xung đột lợi ích, đặc biệt với công ty mẹ.', 'Nợ vay cao với tổng nợ phải trả là 281,431,907,284 VND, và tài sản ngắn hạn thấp hơn nợ ngắn hạn, gây áp lực thanh toán. Công ty phụ thuộc vào huy động vốn từ tổ chức tín dụng và cổ đông.', 'Hàng tồn kho chủ yếu là nguyên liệu và công cụ, với giá trị tương đối thấp và không có dự phòng giảm giá, nên rủi ro tồn kho thấp.', 7, 'Công ty hoạt động trong lĩnh vực thủy điện với doanh thu ổn định và tăng trưởng, nhưng gánh nặng nợ vay cao và thanh khoản eo hẹp. Triển vọng phụ thuộc vào khả năng quản lý nợ và dòng tiền từ hoạt động kinh doanh.'),
('XMD_2022_consolidated', 'XMD', 2022, 'consolidated', 'Doanh nghiệp có nhiều giao dịch mua bán, thuê dịch vụ với các bên liên quan thuộc cùng công ty mẹ, với giá trị lớn. Tuy nhiên, không có thông tin về lãi suất ưu đãi hay điều kiện bất thường.', 'Nợ vay ngắn hạn từ hai ngân hàng thương mại, tổng cộng 25 tỷ VND, chiếm tỷ trọng nhỏ trong tổng tài sản. Công ty có khả năng thanh toán từ dòng tiền kinh doanh.', 'Hàng tồn kho tăng mạnh từ 21.8 tỷ lên 33.1 tỷ VND, chủ yếu là nguyên liệu và thành phẩm. Cần giám sát rủi ro tồn đọng do biến động thị trường xây dựng.', 5, 'Công ty đã phục hồi kinh doanh với lợi nhuận sau thuế 3 tỷ VND năm 2022 sau lỗ 5.9 tỷ năm trước. Tuy nhiên, dòng tiền từ hoạt động kinh doanh âm, nợ phải trả tăng, và hàng tồn kho tăng cao. Cần cải thiện quản lý vốn lưu động và theo dõi rủi ro từ giao dịch bên liên quan.'),
('XMD_2023_consolidated', 'XMD', 2023, 'consolidated', 'Công ty có giao dịch đáng kể với các bên liên quan, đặc biệt là công ty mẹ và các công ty cùng công ty mẹ, với doanh thu bán hàng và mua hàng hóa dịch vụ lớn. Điều này có thể ảnh hưởng đến tính công bằng của giá cả và tạo rủi ro về lợi ích nhóm.', 'Nợ vay chủ yếu từ ngân hàng với tài sản thế chấp là bất động sản và máy móc. Áp lực nợ ngắn hạn cao, lãi vay tăng so với năm trước. Khả năng thanh toán phụ thuộc vào dòng tiền từ hoạt động kinh doanh.', 'Hàng tồn kho giảm so với đầu năm, nhưng vẫn còn nguyên liệu và thành phẩm. Dự án xây dựng dở dang không có dấu hiệu ứ đọng lớn.', 6, 'Công ty đang gặp khó khăn trong kinh doanh với lợi nhuận sau thuế âm (-2,256,408,685 VND), doanh thu giảm. Nợ vay cao và chi phí lãi vay tăng. Tuy nhiên, tài sản thế chấp đủ để đảm bảo các khoản vay. Cần theo dõi hiệu quả hoạt động, quản lý nợ và mối quan hệ với các bên liên quan.'),
('XMD_2020_consolidated', 'XMD', 2020, 'consolidated', 'Doanh thu từ các bên liên quan chiếm tỷ trọng lớn (54.515.826.551 / 62.422.765.595 = 87,3%), chủ yếu phụ thuộc vào Công ty mẹ - Công ty Cổ phần Đầu tư và Xây dựng Xuân Mai. Phải thu từ các bên liên quan là 29.323.419.104 VND chiếm 76,5% tổng phải thu ngắn hạn. Công ty có lãi chậm thanh toán lớn từ Công ty mẹ (694.845.628 VND). Tuy nhiên, các giao dịch này là giao dịch thương mại bình thường trong chuỗi cung ứng của Tập đoàn Xuân Mai.', 'Nợ vay ngắn hạn giảm từ 38.674.503.814 VND xuống 27.282.409.239 VND. Các khoản vay đều có kỳ hạn 12 tháng và được đảm bảo bằng tài sản cố định (đất đai, nhà xưởng, máy móc). Doanh thu sụt giảm 65,4% so với năm trước, lỗ ròng gần 5 tỷ VND đặt áp lực lên khả năng trả nợ. Công ty vẫn còn tài sản thế chấp đáng kể nhưng dòng tiền từ hoạt động kinh doanh bị suy giảm mạnh.', 'Hàng tồn kho tăng từ 19.945.455.355 VND lên 23.077.441.975 VND trong bối cảnh doanh thu sụt giảm mạnh, cho thấy khả năng ứ đọng hàng tồn kho. Công ty không trích lập dự phòng giảm giá hàng tồn kho. Chi phí xây dựng dở dang 1.166.274.529 VND là dự án cải tạo ván khuôn mới phát sinh, cần theo dõi tiến độ.', 6, 'Công ty Cổ phần Xuân Mai - Đạo Tú có năm 2020 kết quả kinh doanh kém với doanh thu giảm 65,4% và lỗ ròng 4.998.032.954 VND (so với lãi 4.217.523.630 VND năm 2019) do ảnh hưởng COVID-19 đến hoạt động xây dựng của Công ty mẹ. Công ty có mức độ phụ thuộc cao vào các bên liên quan trong Tập đoàn Xuân Mai. Nợ ngắn hạn vẫn ở mức cao, dòng tiền hoạt động kinh doanh dương nhờ thu hồi công nợ lớn. Kiểm toán viên đưa ra ý kiến chấp nhận toàn phần và không có nghi ngờ về hoạt động liên tục. Triển vọng phụ thuộc vào sự phục hồi của ngành xây dựng và hoạt động của Công ty mẹ.'),
('XMD_2021_consolidated', 'XMD', 2021, 'consolidated', 'Công ty có nhiều giao dịch với các bên liên quan, đặc biệt là công ty mẹ Công ty Cổ phần Đầu tư và Xây dựng Xuân Mai, nhưng không có bằng chứng về giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Công ty chủ yếu vay ngắn hạn từ hai ngân hàng lớn, được đảm bảo bằng tài sản cố định. Áp lực nợ vay có thể kiểm soát được do tài sản thế chấp đủ và không có nợ dài hạn.', 'Hàng tồn kho bao gồm nguyên liệu, dở dang và thành phẩm, không có dự phòng giảm giá. Tuy nhiên, do lỗ liên tục, tồn kho có thể bị ứ đọng nếu nhu cầu giảm do ảnh hưởng của COVID-19.', 6, 'Công ty liên tục lỗ trong hai năm 2020 và 2021, chủ yếu do ảnh hưởng của COVID-19 và phụ thuộc vào công ty mẹ. Nợ vay ngắn hạn cao nhưng có tài sản đảm bảo. Triển vọng phụ thuộc vào sự phục hồi của ngành xây dựng và hoạt động của công ty mẹ.'),
('XMD_2019_consolidated', 'XMD', 2019, 'consolidated', 'Doanh nghiệp có giao dịch mua bán hàng hóa, dịch vụ lớn với công ty mẹ và các công ty cùng hệ thống, đặc biệt Công ty Cổ phần Đầu tư và Xây dựng Xuân Mai chiếm tỷ trọng doanh thu và công nợ phải thu/trả lớn. Các giao dịch này cần được đánh giá tính công bằng về giá cả, đặc biệt khoản cho vay và lãi tiền cho vay với Công ty Cổ phần Xây lắp Xuân Mai (cùng hệ thống).', 'Nợ vay ngắn hạn tập trung tại 03 ngân hàng thương mại với tổng dư nợ cuối kỳ hơn 38,6 tỷ VNĐ, tăng mạnh so với đầu năm. Các khoản vay được đảm bảo bằng tài sản cố định chính (đất đai, nhà xưởng, máy móc) và bảo lãnh từ công ty mẹ. Áp lực trả nợ trong 12 tháng tới là đáng kể, đòi hỏi dòng tiền kinh doanh phải duy trì ổn định.', 'Hàng tồn kho giảm từ 23,1 tỷ VNĐ xuống 19,9 tỷ VNĐ, không trích lập dự phòng. Cơ cấu tồn kho bao gồm nguyên liệu, thành phẩm và chi phí sản xuất dở dang. Chi phí sản xuất dở dang (1,46 tỷ VNĐ) có thể tiềm ẩn rủi ro nếu quá trình sản xuất bị đình trệ hoặc sản phẩm không tiêu thụ được.', 5, 'Công ty có hoạt động kinh doanh chính trong sản xuất cấu kiện bê tông và xây lắp. Năm 2019, doanh thu thuần tăng nhẹ, lợi nhuận sau thuế tăng trưởng tốt (43%). Tuy nhiên, doanh nghiệp phụ thuộc lớn vào công ty mẹ (chiếm hơn 65% doanh thu và tỷ trọng lớn trong công nợ). Nợ vay ngắn hạn tăng mạnh, tập trung tài sản thế chấp là các tài sản cố định cốt lõi. Dòng tiền từ hoạt động kinh doanh năm 2019 âm, cần theo dõi khả năng thanh toán nợ đến hạn.'),
('XMD_2017_consolidated', 'XMD', 2017, 'consolidated', 'Doanh nghiệp có giao dịch rất lớn với Công ty mẹ - Công ty Cổ phần Đầu tư và Xây dựng Xuân Mai: phải thu khách hàng chiếm 75,8 tỷ VNĐ (chiếm ~94% tổng phải thu ngắn hạn của khách hàng), người mua trả trước 18,7 tỷ VNĐ, mua hàng hóa 76,1 tỷ VNĐ. Công ty cũng cho vay Công ty TNHH MTV Đạo Tú - Thanh Phát (3,1 tỷ) và Công ty mẹ (10,75 tỷ) đã thu hồi trong năm. Doanh thu từ Công ty mẹ chiếm 72% tổng doanh thu, cho thấy phụ thuộc lớn vào bên liên quan. Các giao dịch này có thể ảnh hưởng đến tính độc lập về thương mại của doanh nghiệp.', 'Tổng nợ vay cuối kỳ khoảng 41,2 tỷ VNĐ, giảm so với đầu năm 43,8 tỷ. Nợ ngắn hạn chiếm phần lớn (40,9 tỷ). Công ty vay từ 3 ngân hàng lớn và có tài sản thế chấp là quyền sử dụng đất, nhà xưởng, máy móc thiết bị, trạm trộn bê tông và xe ô tô. Nợ vay dài hạn chỉ 300 triệu (vay mua ô tô). Áp lực nợ ngắn hạn cao, dòng tiền từ hoạt động kinh doanh năm 2017 âm 6,66 tỷ (so với dương 18,6 tỷ năm trước) cho thấy khả năng trả nợ từ hoạt động sản xuất kinh doanh suy giảm đáng kể.', 'Hàng tồn kho tăng mạnh từ 25,3 tỷ lên 39,5 tỷ VNĐ (+56%), trong đó chi phí SXKD dở dang tăng từ 5 tỷ lên 16 tỷ VNĐ. Dự án đầu tư XDCB dở dang tăng từ 3,1 tỷ lên 4,1 tỷ VNĐ với nhiều dự án cải tạo nâng cấp. Không có dự phòng giảm giá hàng tồn kho. Việc tồn kho dở dang tăng mạnh cần được theo dõi sát để tránh ứ đọng.', 6, 'Công ty Cổ phần Xuân Mai - Đạo Tú hoạt động trong lĩnh vực sản xuất vật liệu xây dựng và xây lắp, với doanh thu 192 tỷ VNĐ năm 2017 (tăng 19,5% so với năm trước) và lợi nhuận sau thuế 3,5 tỷ VNĐ. Tuy nhiên, công ty phụ thuộc lớn vào Công ty mẹ (72% doanh thu, tỷ lệ sở hữu 86%). Dòng tiền hoạt động kinh doanh âm 6,66 tỷ (so với +18,6 tỷ năm trước) là dấu hiệu đáng lo ngại. Hàng tồn kho và phải thu tăng mạnh cho thấy vốn lưu động bị chiếm dụng nhiều. Kiểm toán viên đưa ra ý kiến chấp nhận toàn phần, không có vấn đề về hoạt động liên tục. Công ty đã chi trả cổ tức 3,2 tỷ VNĐ trong năm 2017.'),
('XMD_2018_consolidated', 'XMD', 2018, 'consolidated', 'Công ty có mức độ phụ thuộc rất lớn vào công ty mẹ là Công ty CP Đầu tư và Xây dựng Xuân Mai (XMC). Doanh thu từ bên liên quan chiếm khoảng 91,4% tổng doanh thu (162,3 tỷ/177,7 tỷ VND), trong đó riêng XMC chiếm 90,9%. Phải thu khách hàng từ XMC chiếm tỷ trọng rất lớn (66,5 tỷ/68,9 tỷ VND). Phải trả người bán cho XMC cũng ở mức cao (20,7 tỷ VND). Công ty cho Công ty CP Xây lắp Xuân Mai vay 1,5 tỷ VND không rõ lãi suất. Các giao dịch mua bán, cho vay, thuê dịch vụ với các công ty cùng hệ sinh thái Xuân Mai tạo thành mạng lưới giao dịch phức tạp, tiềm ẩn rủi ro chuyển giá và xung đột lợi ích.', 'Nợ vay ngắn hạn cuối kỳ là 26,6 tỷ VND, giảm đáng kể so với đầu năm (41,2 tỷ VND) cho thấy công ty đã tích cực trả nợ. Nợ dài hạn = 0 (khoản vay 300 triệu VND đáo hạn đã được trả). Tổng nợ phải trả (78,8 tỷ VND) lớn hơn vốn chủ sở hữu (52,1 tỷ VND), tỷ lệ nợ/vốn khoảng 1,51. Các khoản vay đều được đảm bảo bằng tài sản thế chấp (đất đai, nhà xưởng, máy móc, xe ô tô) và bảo lãnh từ công ty mẹ. Chi phí lãi vay năm 2018 là 2,67 tỷ VND. Áp lực nợ vay ở mức trung bình, dòng tiền hoạt động kinh doanh dương mạnh (25,3 tỷ VND) hỗ trợ khả năng trả nợ.', 'Hàng tồn kho cuối năm giảm mạnh từ 39,5 tỷ xuống 23,1 tỷ VND, cho thấy hàng hóa được tiêu thụ tốt. Không có dự phòng giảm giá hàng tồn kho. Chi phí SXKD dở dang giảm mạnh từ 16 tỷ xuống 3,2 tỷ VND. Các dự án đầu tư xây dựng cơ bản dở dang (tổng 4,1 tỷ VND đầu năm) đã được hoàn thành toàn bộ và chuyển vào TSCĐ, không còn khoản dở dang cuối năm. Rủi ro tồn kho thấp, hàng hóa luân chuyển nhanh.', 7, 'Công ty CP Xuân Mai - Đạo Tú hoạt động trong lĩnh vực sản xuất vật liệu xây dựng và xây lắp, là công ty con (sở hữu 86%) của Công ty CP Đầu tư và Xây dựng Xuân Mai. Năm 2018, doanh thu thuần giảm 7,6% từ 192,3 tỷ xuống 177,7 tỷ VND; lợi nhuận sau thuế giảm 17,3% từ 3,5 tỷ xuống 2,9 tỷ VND. Tuy nhiên, dòng tiền hoạt động kinh doanh cải thiện mạnh từ -6,7 tỷ lên +25,3 tỷ VND nhờ giảm đáng kể tồn kho và phải thu. Công ty đã trả nợ gốc vay 129,7 tỷ VND và giảm tồn kho 16,4 tỷ VND. Điểm rủi ro chính là mức độ phụ thuộc cực lớn vào công ty mẹ (>90% doanh thu, phần lớn phải thu và phải trả), cấu trúc giao dịch nội bộ phức tạp với nhiều công ty trong hệ sinh thái Xuân Mai. Kiểm toán viên đưa ra ý kiến chấp nhận toàn phần, không có vấn đề về hoạt động liên tục. Công ty duy trì khả năng sinh lời nhưng biên lợi nhuận gộp chỉ ~6,95%, áp lực từ chi phí lãi vay và chi phí bán hàng tăng.'),
('XMC_2025_parent', 'XMC', 2025, 'parent', 'Công ty có mạng lưới giao dịch bên liên quan phức tạp và quy mô lớn với các công ty con, công ty liên kết, bao gồm mua bán hàng hóa, dịch vụ, cho vay, góp vốn. Tổng giá trị giao dịch lên đến hàng nghìn tỷ đồng. Tuy nhiên, các giao dịch này chủ yếu phục vụ cho hoạt động sản xuất kinh doanh cốt lõi và được ghi nhận có lãi suất (ví dụ: cho vay 6.0%/năm, 5.2%/năm). Không phát hiện giao dịch bất thường rõ ràng như mua bán chênh lệch lớn bất hợp lý hay cho vay không lãi suất. Rủi ro tập trung ở việc quản lý dòng tiền và công nợ trong nội bộ tập đoàn.', 'Áp lực nợ vay ở mức cao với tổng nợ phải trả hơn 2,300 tỷ VNĐ, chiếm 72% tổng tài sản. Nợ vay ngắn hạn (853,5 tỷ) và dài hạn (279,4 tỷ) lớn. Công ty có tài sản thế chấp đáng kể là bất động sản đầu tư và tài sản cố định. Dòng tiền từ hoạt động kinh doanh dương mạnh (348 tỷ) và tiền mặt cuối năm tăng mạnh (277 tỷ) cho thấy khả năng thanh toán tạm ổn, nhưng đòn bẩy tài chính cao tạo rủi ro về lãi suất và khả năng trả nợ nếu kinh doanh suy giảm.', 'Hàng tồn kho chủ yếu là chi phí sản xuất kinh doanh dở dang (617 tỷ) và hàng hóa bất động sản (181,7 tỷ). Dự phòng giảm giá hàng tồn kho nhỏ (107 triệu) cho thấy ban lãnh đạo đánh giá giá trị thuần có thể thực hiện được không thấp hơn giá gốc. Rủi ro tồn kho ở mức trung bình, liên quan đến tiến độ triển khai các dự án xây dựng và khả năng tiêu thụ bất động sản.', 6, 'Công ty Cổ phần Đầu tư và Xây dựng Xuân Mai có nền tảng kinh doanh đa ngành (xây dựng, sản xuất, bất động sản) với quy mô tài sản lớn. Tăng trưởng doanh thu ấn tượng (+18%) và lợi nhuận sau thuế tăng mạnh (+489%). Tuy nhiên, công ty hoạt động dựa trên đòn bẩy tài chính cao, nợ phải trả lớn, đặc biệt là nợ vay. Mạng lưới giao dịch nội bộ tập đoàn phức tạp nhưng chưa thấy bất thường lớn. Dòng tiền kinh doanh tốt giúp cải thiện thanh khoản. Triển vọng phụ thuộc vào khả năng quản lý nợ, triển khai dự án và thị trường bất động sản.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('XMC_2025_consolidated', 'XMC', 2025, 'consolidated', 'Công ty có giao dịch đáng kể với Công ty TNHH Xuân Mai - Nam Hà Nội (công ty liên kết) với khoản góp vốn 225 tỷ đồng và khoản vay 201,2 tỷ đồng không có tài sản bảo đảm với lãi suất 5,2%/năm. Ngoài ra, có các khoản phải thu lớn từ các công ty liên kết khác (Bê tông Xuân Mai Miền Nam, Xuân Mai Đà Nẵng) với tổng cộng hơn 42 tỷ đồng, trong đó các khoản phải thu cho vay 11,5 tỷ đồng đã trích lập dự phòng 100%. Giao dịch phức tạp giữa các bên liên quan tập trung vào cho vay, góp vốn và mua bán bất động sản nội bộ.', 'Tổng nợ vay và nợ thuê tài chính tăng mạnh 89,56% từ 1.100 tỷ lên 1.329 tỷ đồng, phản ánh hoạt động mở rộng quy mô. Nợ ngắn hạn chiếm 67,7% tổng nợ vay (899,9 tỷ), tạo áp lực đáo hạn lớn. Tài sản thế chấp bao gồm bất động sản đầu tư (311 tỷ), tài sản cố định (87,6 tỷ) và quyền tài sản từ dự án. Công ty vay từ công ty liên kết Xuân Mai - Nam Hà Nội 201,2 tỷ không có tài sản bảo đảm là điểm đáng lưu ý.', 'Hàng tồn kho giảm từ 1.122 tỷ xuống 980 tỷ (-12,6%) nhờ bán bất động sản và chuyển sang bất động sản đầu tư. Chi phí sản xuất kinh doanh dở dang chiếm 70,7% tồn kho (692,9 tỷ), chủ yếu là hợp đồng xây dựng. Dự phòng giảm giá hàng tồn kho giảm mạnh từ 2,2 tỷ xuống 0,7 tỷ. Các dự án xây dựng cơ bản dở dang tăng từ 12,6 tỷ lên 25,8 tỷ do đầu tư mới dây chuyền sản xuất tấm tường.', 5, 'Công ty Xuân Mai đạt kết quả kinh doanh tích cực năm 2025: doanh thu 2.008 tỷ (+26%), lợi nhuận sau thuế 26,5 tỷ (+262%), EPS 346 đồng. Điểm mạnh: biên lợi nhuận gộp 9,29%, dòng tiền hoạt động kinh doanh dương 243 tỷ, tỷ lệ nợ vay/vốn chủ sở hữu ở mức 1,46x. Điểm rủi ro: nợ vay tăng mạnh 89,56%, dự phòng phải thu khó đòi lớn 409,6 tỷ, tỷ lệ nợ xấu cao, giao dịch nội bộ phức tạp với công ty liên kết. Công ty đã chuyển nhượng dự án Yên Bình lãi 100 tỷ cải thiện kết quả. Cần theo dõi khả năng thu hồi nợ từ các công ty liên kết và áp lực trả nợ ngắn hạn.'),
('XMC_2024_consolidated', 'XMC', 2024, 'consolidated', 'Công ty có nhiều giao dịch phức tạp với bên liên quan: (1) Cho vay không lãi suất 0% cho Công ty CPĐT&XD Polytec Việt Nam (650 triệu VNĐ) - bất thường; (2) Các khoản phải thu từ ban lãnh đạo cá nhân 43.5 tỷ VNĐ đã trích lập dự phòng 100% - rủi ro thu hồi cao; (3) Cho vay nội bộ tập đoàn cho các công ty liên kết như Công ty CP Bê tông Xuân Mai Miền Nam (11 tỷ) và Công ty CP Xuân Mai Đà Nẵng (500 triệu) đều có dự phòng 100% cho thấy khả năng thu hồi thấp; (4) Công ty mẹ bảo lãnh nợ cho nhiều công ty con tại BIDV, tạo nghĩa vụ nợ tiềm ẩn; (5) Quy mô giao dịch mua bán với Công ty CP Xuân Mai Thanh Hóa nhỏ nhưng là công ty liên kết.', 'Tổng nợ vay 1,100 tỷ VNĐ (nợ ngắn hạn 789 tỷ, nợ dài hạn 311 tỷ) so với vốn chủ sở hữu 888 tỷ - tỷ lệ nợ/vốn chủ sở hữu ~1.24x. Chi phí lãi vay năm 2024 là 70.6 tỷ VNĐ (năm trước 117.2 tỷ) - đã giảm đáng kể do cơ cấu lại nợ. Nợ ngắn hạn chiếm tỷ trọng lớn nhưng Công ty đã chủ động chuyển đổi sang nợ dài hạn (tăng từ 0.8 tỷ lên 311.5 tỷ). Lãi suất vay dao động từ 7.3%-9.5%/năm. Tài sản thế chấp bao gồm văn phòng công ty, bất động sản đầu tư, máy móc thiết bị và quyền tài sản từ dự án. Áp lực trả nợ ngắn hạn vẫn cao với 789 tỷ đến hạn trong 12 tháng.', 'Hàng tồn kho bất động sản trị giá 480 tỷ VNĐ với dự phòng chỉ 1.58 tỷ (0.33% giá trị) - mức dự phòng thấp so với quy mô, cần theo dõi khả năng thanh khoản trên thị trường bất động sản. Chi phí hợp đồng xây dựng dở dang 585 tỷ cho thấy nhiều dự án đang triển khai. Hàng tồn kho giảm từ 1,238 tỷ xuống 1,123 tỷ (-9.3%) cho thấy công ty đã tiêu thụ được một phần, nhưng vẫn ở mức cao. Nguyên vật liệu giảm từ 50.9 tỷ xuống 39.0 tỷ - có thể do giảm hoạt động sản xuất.', 6, 'Công ty CPĐT&XD Xuân Mai đang trong giai đoạn khó khăn: doanh thu giảm 27% (từ 2,188 tỷ xuống 1,590 tỷ), lợi nhuận sau thuế giảm 83% (từ 42.3 tỷ xuống 7.3 tỷ). Chi phí lãi vay vẫn ở mức cao 70.6 tỷ dù đã giảm so với năm trước. Công ty có tỷ suất lợi nhuận gộp thấp 8.88%, cho thấy biên lợi nhuận mỏng trong hoạt động xây dựng. Dòng tiền hoạt động kinh doanh dương mạnh 356.9 tỷ nhờ thu hồi phải thu và giảm tồn kho. Công ty đã cơ cấu nợ thành công - giảm nợ ngắn hạn 773 tỷ và tăng nợ dài hạn 305 tỷ. Tuy nhiên, tồn kho bất động sản lớn (480 tỷ), nhiều khoản phải thu khó đòi từ bên liên quan, và tỷ lệ đòn bẩy cao là những rủi ro đáng lo ngại. Ban lãnh đạo có thay đổi đáng kể trong năm 2024. Triển vọng phụ thuộc vào khả năng tiêu thụ bất động sản và cải thiện biên lợi nhuận xây dựng.'),
('XMD_2024_consolidated', 'XMD', 2024, 'consolidated', 'Giao dịch với các bên liên quan bao gồm mua bán hàng hóa và dịch vụ với Công ty mẹ và các công ty liên kết. Giá trị giao dịch lớn, nhưng không có dấu hiệu bất thường như cho vay không lãi suất hay chênh lệch giá đáng kể.', 'Nợ vay giảm mạnh so với năm trước, nhưng vẫn còn tài sản thế chấp. Áp lực nợ vay giảm, nhưng cần theo dõi khả năng thanh toán.', 'Hàng tồn kho tăng nhẹ, không có dự phòng giảm giá. Rủi ro tồn kho ở mức trung bình, đặc biệt với chi phí sản xuất dở dang.', 5, 'Công ty có sự cải thiện về lợi nhuận sau thuế doanh thu tăng và nợ vay giảm. Tuy nhiên, vẫn còn rủi ro từ giao dịch bên liên quan và tồn kho. Sức khỏe tài chính trung bình, triển vọng ổn định nếu quản lý tốt.'),
('XMC_2022_parent', 'XMC', 2022, 'parent', 'Công ty có nhiều giao dịch với các công ty con và công ty liên kết, bao gồm mua bán hàng hóa, dịch vụ, tài sản, cho vay và nhận cổ tức. Các giao dịch này là cần thiết cho hoạt động sản xuất kinh doanh của tập đoàn và được thực hiện theo giá thị trường hoặc thỏa thuận. Không có bằng chứng rõ ràng về giao dịch bất thường như cho vay không lãi suất hoặc mua bán chênh lệch lớn bất hợp lý với mục đích tư lợi.', 'Tổng nợ vay và nợ thuê tài chính cuối kỳ đạt ~1,777 tỷ VNĐ, tăng nhẹ so với đầu năm. Công ty chủ yếu vay ngân hàng (BIDV, LienVietPostBank, BacABank) và một phần từ công ty con, cá nhân. Các khoản vay lớn thường có tài sản đảm bảo là bất động sản, tài sản cố định hoặc cổ phiếu, giảm thiểu rủi ro. Tuy nhiên, áp lực trả nợ gốc và lãi trong bối cảnh kinh doanh có biến động là cần được theo dõi.', 'Hàng tồn kho cuối kỳ tăng mạnh (~464 tỷ VNĐ) so với đầu năm (~111 tỷ VNĐ), chủ yếu là hàng hóa, phản ánh hoạt động kinh doanh bất động sản. Không trích lập dự phòng giảm giá. Các dự án xây dựng dở dang có giá trị nhỏ (~17 tỷ VNĐ) và đang trong quá trình triển khai, rủi ro ứ đọng không cao.', 3, 'Công ty hoạt động trong lĩnh vực xây dựng và bất động sản, có kết quả kinh doanh năm 2022 tăng trưởng tốt (lợi nhuận sau thuế 65,4 tỷ VNĐ). Cấu trúc tài chính có đòn bẩy nợ vay cao nhưng được kiểm soát bằng tài sản thế chấp. Dòng tiền từ hoạt động kinh doanh dương nhưng thấp hơn nhiều so với lợi nhuận kế toán. Rủi ro chính nằm ở biến động thị trường bất động sản và áp lực nợ vay. Công ty có mạng lưới công ty con, liên kết rộng, là lợi thế nhưng cũng tiềm ẩn rủi ro liên quan phức tạp.'),
('XMC_2023_consolidated', 'XMC', 2023, 'consolidated', 'Doanh nghiệp có nhiều giao dịch với công ty con, bao gồm doanh thu bán hàng, mua nguyên vật liệu, cho vay với lãi suất thấp (4-4,5%/năm) không có tài sản đảm bảo, điều này có thể tiềm ẩn rủi ro về giá chuyển nhượng không theo giá thị trường hoặc quản lý dòng tiền nội bộ không hiệu quả.', 'Áp lực nợ vay lớn, chủ yếu là ngắn hạn với tổng nợ vay hơn 1.435 tỷ VNĐ, tỷ lệ nợ/vốn chủ sở hữu cao. Công ty có tài sản thế chấp cho một số khoản vay ngân hàng nhưng nhiều khoản vay không có tài sản đảm bảo. Khả năng thanh toán phụ thuộc vào dòng tiền kinh doanh và thu hồi công nợ.', 'Hàng tồn kho tăng mạnh từ 463 tỷ lên 1.009 tỷ VNĐ, chủ yếu do tăng hàng hóa bất động sản. Dự phòng giảm giá 3,8 tỷ VNĐ cho hàng hóa bất động sản cho thấy rủi ro tồn kho nếu thị trường bất động sản khó khăn.', 5, 'Doanh nghiệp hoạt động trong lĩnh vực xây dựng và bất động sản, có doanh thu tăng trưởng nhưng lợi nhuận sau thuế giảm. Nợ vay ngắn hạn cao gây áp lực thanh khoản. Hàng tồn kho lớn, đặc biệt là bất động sản, tiềm ẩn rủi ro nếu thị trường chậm lại. Giao dịch với bên liên quan diễn ra thường xuyên nhưng chưa có dấu hiệu bất thường nghiêm trọng. Cần theo dõi sát tiến độ thu hồi công nợ và quản lý dòng tiền.'),
('XMC_2022_consolidated', 'XMC', 2022, 'consolidated', 'Công ty có nhiều giao dịch với các công ty liên kết (cổ đông lớn 20,01% là Công ty TNHH Khải Hưng cho vay 100 tỷ đồng). Các khoản phải thu từ khách hàng là công ty liên kết lên đến 41,4 tỷ đồng, khoản cho vay các công ty liên kết 11,5 tỷ đồng (trong đó đã trích dự phòng 15,2 tỷ đồng). Giao dịch mua bán nội bộ tập đoàn phát sinh doanh thu 2,9 tỷ đồng từ Công ty CP Xuân Mai Thanh Hóa. Tuy nhiên, tổng quy mô giao dịch với bên liên quan so với tổng tài sản và doanh thu không ở mức quá bất thường, không có dấu hiệu giao dịch giá chuyển nhượng bất hợp lý rõ ràng.', 'Tổng nợ vay và nợ thuê tài chính là 1.952,9 tỷ VNĐ, trong đó nợ ngắn hạn chiếm 91% (1.776,9 tỷ VNĐ), tạo áp lực đáo hạn lớn. Dòng tiền hoạt động kinh doanh thuần năm 2022 chỉ đạt 74,8 tỷ VNĐ, thấp hơn nhiều so với nghĩa vụ trả nợ gốc (1.826,5 tỷ VNĐ). Công ty phải liên tục tái cấp vốn (tiền thu từ đi vay 1.801 tỷ VNĐ). Tuy nhiên, nợ đã giảm nhẹ so với năm trước (từ 1.981,8 tỷ xuống 1.952,9 tỷ). Tài sản thế chấp chính là TSCĐ hữu hình (nguyên giá 275,5 tỷ, giá trị còn lại 121,3 tỷ) và BĐSĐT (nguyên giá 108,8 tỷ, giá trị còn lại 94,4 tỷ) tại BIDV và các ngân hàng lớn.', 'Tồn kho tăng mạnh từ 385,3 tỷ lên 733,8 tỷ VNĐ (+90,4%), chủ yếu do chi phí sản xuất kinh doanh dở dang tăng từ 324,1 tỷ lên 663,0 tỷ VNĐ, phản ánh quy mô hợp đồng xây dựng đang triển khai lớn. Dự phòng giảm giá hàng tồn kho chỉ 202,9 triệu VNĐ (rất nhỏ so với tổng giá trị), cho thấy công ty đánh giá hàng tồn kho có khả năng thu hồi cao. Tuy nhiên, việc tồn kho dở dang chiếm tỷ trọng lớn đặt rủi ro nếu các dự án bị chậm tiến độ hoặc khách hàng hủy hợp đồng.', 5, 'Công ty CP Đầu tư và Xây dựng Xuân Mai có doanh thu thuần tăng 22% đạt 1.967,1 tỷ VNĐ, lợi nhuận sau thuế Công ty mẹ đạt 65,8 tỷ VNĐ (tương đương năm trước). Biên lợi nhuận gộp đạt 10,28% - ở mức trung bình cho ngành xây dựng. Điểm đáng lo ngại chính là tỷ lệ đòn bẩy cao với nợ vay chiếm 46,1% tổng tài sản, trong đó nợ ngắn hạn chiếm tỷ trọng lớn (91% nợ vay), tạo áp lực thanh khoản đáng kể. Công ty phụ thuộc lớn vào tín dụng ngân hàng BIDV và có hệ sinh thái công ty con/liên kết phức tạp (8 công ty con, 5+ công ty liên kết) với nhiều giao dịch nội bộ. Tài sản thế chấp là TSCĐ và BĐSĐT tại các ngân hàng lớn. Điểm tích cực là doanh thu tăng trưởng tốt, nợ đã giảm nhẹ, và công ty có dòng tiền từ hoạt động đầu tư (thu hồi đầu tư, lãi cho vay). Triển vọng phụ thuộc vào khả năng quản lý dòng tiền và tiến độ các dự án bất động sản, xây dựng đang triển khai.'),
('XMC_2021_consolidated', 'XMC', 2021, 'consolidated', 'Các giao dịch với bên liên quan bao gồm bán hàng, mua dịch vụ, thu hồi đầu tư và chuyển trả tiền vay với các công ty liên kết. Giá trị giao dịch lớn, đặc biệt khoản thu hồi đầu tư 71,1 tỷ VNĐ và chuyển trả tiền vay 71,1 tỷ VNĐ. Tuy nhiên, không có dấu hiệu giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Công ty có nợ vay ngắn hạn và dài hạn lớn với tổng cộng khoảng 1.981 tỷ VNĐ cuối năm 2021. Nợ ngắn hạn chiếm tỷ trọng cao (khoảng 1.712 tỷ VNĐ), tạo áp lực thanh toán. Các khoản vay được đảm bảo bằng nhiều tài sản như văn phòng, máy móc, cổ phần công ty con. Lãi suất dao động từ 6,7% đến 12,65%/năm. Công ty có khả năng thanh toán từ dòng tiền hoạt động kinh doanh nhưng cần quản lý tốt áp lực nợ.', 'Hàng tồn kho giảm từ 659 tỷ VNĐ đầu năm xuống 385 tỷ VNĐ cuối năm, với dự phòng giảm giá nhỏ (203 triệu VNĐ). Chi phí sản xuất kinh doanh dở dang chiếm tỷ trọng lớn (324 tỷ VNĐ), cần theo dõi tiến độ hoàn thành để tránh ứ đọng. Dự án xây dựng dở dang (6,5 tỷ VNĐ) không có dự phòng, nhưng quy mô nhỏ.', 5, 'Công ty hoạt động trong lĩnh vực xây dựng và bất động sản, với doanh thu thuần năm 2021 đạt 1.612 tỷ VNĐ, lợi nhuận gộp 155 tỷ VNĐ (tỷ suất 9,65%). Nợ vay cao, đặc biệt nợ ngắn hạn, gây áp lực thanh khoản. Tuy nhiên, dòng tiền từ hoạt động kinh doanh dương (353 tỷ VNĐ) và tài sản đảm bảo đầy đủ. Rủi ro quản trị ở mức trung bình do giao dịch với bên liên quan phức tạp nhưng không bất thường. Triển vọng phụ thuộc vào khả năng thu hồi công nợ và quản lý nợ hiệu quả.'),
('XMC_2020_consolidated', 'XMC', 2020, 'consolidated', 'Công ty có nhiều giao dịch với các bên liên quan là công ty liên kết. Đáng lưu ý: Cho vay Công ty CP Tư vấn và Dịch vụ Kỹ thuật điện (liên kết) 71,1 tỷ VNĐ; Doanh thu bán hàng với Công ty CP Xuân Mai Thanh Hóa (liên kết) 251,75 tỷ VNĐ; Nhiều khoản phải thu từ các công ty liên kết với tổng giá trị lớn. Công ty CP Đầu tư Xây dựng Xuân Mai Sài Gòn đã mua lại 20 triệu cổ phần từ Công ty mẹ với giá trị chuyển nhượng 600 tỷ VNĐ, tạo lãi 400 tỷ VNĐ cho doanh thu hoạt động tài chính năm nay.', 'Tổng nợ vay là 2.419,6 tỷ VNĐ, trong đó nợ ngắn hạn 1.852,6 tỷ VNĐ chiếm tỷ trọng lớn. Chi phí lãi vay năm nay là 152,7 tỷ VNĐ. Công ty có trái phiếu 451,65 tỷ VNĐ đáo hạn năm 2021 với lãi suất 10%/năm, được đảm bảo bằng dự án Rose Town. Nhiều khoản vay ngân hàng được thế chấp bằng tài sản hình thành từ vốn vay và bất động sản. Áp lực trả nợ ngắn hạn cao.', 'Chi phí sản xuất kinh doanh dở dang chiếm tỷ trọng lớn trong hàng tồn kho (553,1 tỷ VNĐ). Giá trị hàng tồn kho giảm từ 740 tỷ xuống 659 tỷ VNĐ. Dự phòng giảm giá hàng tồn kho chỉ 203,5 triệu VNĐ. Tài sản dở dang dài hạn giảm mạnh từ 205,9 tỷ xuống 9,4 tỷ VNĐ, cho thấy các dự án đầu tư xây dựng đã được hoàn thành chuyển giao.', 5, 'Công ty CP Đầu tư và Xây dựng Xuân Mai có doanh thu thuần giảm từ 2.981 tỷ xuống 2.140 tỷ VNĐ (-28%). Tuy nhiên, lợi nhuận sau thuế của Công ty mẹ tăng nhẹ từ 113,8 tỷ lên 127 tỷ VNĐ nhờ doanh thu hoạt động tài chính lớn (483,5 tỷ VNĐ) từ việc thoái vốn tại công ty liên kết. Biên lợi nhuận gộp cải thiện từ 11,37% lên 6,71%. Dự phòng phải thu khó đòi tăng mạnh từ 92,7 tỷ lên 310,2 tỷ VNĐ. Công ty có cơ cấu nợ phức tạp với nhiều khoản vay ngân hàng và trái phiếu, áp lực trả nợ ngắn hạn cao.'),
('XMC_2020_parent', 'XMC', 2020, 'parent', 'Công ty có giao dịch lớn với các công ty con và liên kết, bao gồm mua bán hàng hóa, dịch vụ và cho vay. Các giao dịch này có giá trị đáng kể nhưng không có bằng chứng rõ ràng về giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn. Tuy nhiên, quy mô giao dịch lớn có thể tạo rủi ro tập trung nếu có bất thường.', 'Công ty có mức nợ vay cao với tổng nợ phải trả chiếm tỷ trọng lớn trong tổng tài sản. Nợ ngắn hạn và dài hạn đều đáng kể, với nhiều khoản vay có tài sản thế chấp. Áp lực trả nợ lãi vay lớn, chi phí lãi vay năm 2020 là 121,507,706,570 VND. Công ty có đủ tài sản thế chấp nhưng rủi ro thanh khoản nếu dòng tiền kinh doanh không đảm bảo.', 'Hàng tồn kho tăng mạnh từ 171,502,572,942 VND đầu năm lên 374,804,638,051 VND cuối năm, chủ yếu do chi phí sản xuất kinh doanh dở dang tăng. Dự án xây dựng dở dang giảm đáng kể từ 205,900,395,787 VND xuống 5,687,132,909 VND, cho thấy tiến độ triển khai tốt. Tuy nhiên, sự gia tăng hàng tồn kho có thể là rủi ro nếu nhu cầu giảm.', 6, 'Công ty có sức khỏe tài chính ổn định với lợi nhuận sau thuế tăng từ 111,742,427,779 VND năm 2019 lên 134,507,238,373 VND năm 2020. Tuy nhiên, tỷ lệ nợ cao và giao dịch liên quan lớn đòi hỏi quản lý rủi ro chặt chẽ. Triển vọng đầu tư phụ thuộc vào khả năng quản lý nợ và tối ưu hóa chuỗi cung ứng.'),
('XMC_2019_consolidated', 'XMC', 2019, 'consolidated', 'Công ty có nhiều giao dịch với các công ty liên kết, đặc biệt là Công ty CP Đầu tư xây dựng Xuân Mai Sài Gòn với doanh số mua bán hàng hóa và dịch vụ hơn 1.000 tỷ đồng, cho vay không có thông tin lãi suất cụ thể. Lỗ từ đầu tư vào công ty liên kết gần 2 tỷ đồng. Các giao dịch này cần được giám sát chặt chẽ để đảm bảo tính minh bạch và giá thị trường.', 'Tổng nợ phải trả gần 4.479 tỷ đồng, trong đó nợ vay và nợ thuê tài chính chiếm 2.659 tỷ đồng. Áp lực trả nợ ngắn hạn lớn (1.484 tỷ đồng). Công ty sử dụng nhiều tài sản thế chấp là bất động sản, máy móc và cổ phần công ty con để đảm bảo các khoản vay. Khả năng thanh toán phụ thuộc vào dòng tiền kinh doanh và thu hồi công nợ.', 'Hàng tồn kho và dự án xây dựng dở dang có giá trị lớn (tổng cộng gần 950 tỷ đồng), chủ yếu là chi phí sản xuất kinh doanh dở dang và dự án xây dựng cơ bản dở dang. Dự phòng giảm giá hàng tồn kho chỉ 203 triệu đồng, mức rất thấp so với giá trị. Rủi ro ứ đọng tồn kho và dự án nếu thị trường bất động sản và xây dựng chậm lại.', 5, 'Công ty hoạt động trong lĩnh vực xây dựng và bất động sản, có kết quả kinh doanh tăng trưởng với doanh thu thuần đạt 2.981 tỷ đồng và lợi nhuận sau thuế 119 tỷ đồng. Tuy nhiên, đòn bẩy tài chính cao, nợ vay lớn gây áp lực thanh khoản. Dòng tiền từ hoạt động kinh doanh âm (-916 tỷ đồng) do phải thu tăng mạnh. Hàng tồn kho và tài sản dở dang lớn tiềm ẩn rủi ro. Công ty có mạng lưới công ty con và liên kết rộng, cần quản trị tốt các giao dịch nội bộ. Triển vọng phụ thuộc vào khả năng thu hồi công nợ, quản lý dòng tiền và diễn biến thị trường bất động sản.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('XMC_2018_consolidated', 'XMC', 2018, 'consolidated', 'Công ty có nhiều giao dịch với các công ty liên kết, bao gồm góp vốn, mua bán hàng hóa dịch vụ. Các giao dịch này được trình bày minh bạch trong báo cáo tài chính, tuy nhiên cần theo dõi tính công bằng về giá và điều kiện thanh toán.', 'Nợ vay của công ty ở mức cao với tổng nợ vay hơn 2.000 tỷ đồng, chủ yếu là vay ngân hàng và phát hành trái phiếu. Công ty có tài sản đảm bảo và dòng tiền từ hoạt động kinh doanh để trả nợ, nhưng áp lực thanh toán vẫn đáng kể.', 'Hàng tồn kho giảm so với đầu năm nhưng vẫn ở mức cao (626 tỷ đồng). Dự án xây dựng dở dang tăng mạnh (từ 15,7 tỷ lên 59,1 tỷ), cần theo dõi tiến độ và khả năng thu hồi vốn.', 6, 'Công ty có kết quả kinh doanh tăng trưởng, lợi nhuận sau thuế đạt 98,3 tỷ đồng. Tuy nhiên, nợ vay cao và áp lực thanh toán là rủi ro chính. Công ty có tài sản đảm bảo và dòng tiền hoạt động kinh doanh tốt. Triển vọng trung bình, phụ thuộc vào khả năng quản lý nợ và tiến độ các dự án xây dựng.'),
('XMC_2018_parent', 'XMC', 2018, 'parent', 'Công ty có mạng lưới giao dịch lớn với các công ty con và liên kết, bao gồm mua bán hàng hóa, cho vay, trả cổ tức. Các giao dịch này là phổ biến trong tập đoàn xây dựng, nhưng cần theo dõi chặt chẽ để đảm bảo tính công bằng và minh bạch, đặc biệt là các khoản cho vay nội bộ với lãi suất ưu đãi (ví dụ: Công ty CP Cơ điện Xuân Mai vay với lãi suất 3,5%/năm). Không phát hiện giao dịch bất thường rõ ràng.', 'Tổng nợ vay cuối năm 2018 khoảng 1.887 tỷ VND, trong đó nợ dài hạn chiếm phần lớn (1.169 tỷ VND). Áp lực nợ vay cao, đặc biệt là trái phiếu đáo hạn năm 2021 với lãi suất 10%/năm. Công ty đã thế chấp nhiều tài sản cố định và bất động sản đầu tư để đảm bảo cho các khoản vay. Dòng tiền từ hoạt động kinh doanh mạnh (412 tỷ VND) hỗ trợ khả năng trả nợ.', 'Hàng tồn kho giảm mạnh từ 666 tỷ xuống 296 tỷ VND, chủ yếu do giảm chi phí sản xuất kinh doanh dở dang (từ 665 tỷ xuống 280 tỷ). Điều này cho thấy các dự án đã được hoàn thành và bàn giao, giảm rủi ro tồn kho ứ đọng. Tuy nhiên, chi phí xây dựng cơ bản dở dang tăng từ 2,3 tỷ lên 43,9 tỷ VND, phản ánh đầu tư vào dây chuyền sản xuất mới.', 4, 'Công ty hoạt động trong lĩnh vực xây dựng và bất động sản với kết quả kinh doanh tăng trưởng tốt (doanh thu thuần tăng 12,8%, lợi nhuận sau thuế tăng 36%). Tuy nhiên, công ty có cơ cấu tài chính đòn bẩy cao với nợ vay lớn, đặc biệt là trái phiếu lãi suất cao. Mạng lưới công ty con và liên kết phức tạp đòi hỏi quản trị chặt chẽ. Dòng tiền kinh doanh mạnh là điểm tích cực. Triển vọng phụ thuộc vào khả năng quản lý nợ và triển khai các dự án bất động sản.'),
('YBC_2023_consolidated', 'YBC', 2023, 'consolidated', 'Không có thông tin về giao dịch bên liên quan được công bố trong báo cáo tài chính.', 'Công ty có nợ ngắn hạn cao (724.901.595.538 VNĐ), vượt quá tài sản ngắn hạn (557.697.089.026 VNĐ), tạo áp lực thanh toán. Tuy nhiên, Công ty vẫn được các ngân hàng cho vay (BIDV CN Yên Bái, Agribank CN Yên Bình) và kinh doanh có lãi, hỗ trợ hoạt động liên tục.', 'Hàng tồn kho (193.514.801.424 VNĐ) và chi phí xây dựng cơ bản dở dang (117.552.674.726 VNĐ) tăng so với đầu năm, có thể ảnh hưởng đến dòng tiền và hiệu quả sử dụng vốn.', 5, 'Công ty gặp rủi ro tài chính do lỗ lũy kế và nợ ngắn hạn cao, nhưng vẫn duy trì tăng trưởng doanh thu và lợi nhuận. Được ngân hàng hỗ trợ vốn, song cần cải thiện quản lý nợ và dòng tiền để đảm bảo hoạt động liên tục bền vững.'),
('XMC_2017_consolidated', 'XMC', 2017, 'consolidated', 'Doanh nghiệp có nhiều giao dịch với các công ty liên kết, bao gồm cho vay, mua bán hàng hóa và góp vốn. Các khoản cho vay không được đề cập rõ lãi suất, có thể gây rủi ro về giá chuyển nhượng không công bằng và ảnh hưởng đến lợi nhuận. Tuy nhiên, các giao dịch này đã được trình bày trong báo cáo, cho thấy mức độ minh bạch nhất định.', 'Nợ vay của công ty ở mức cao với tổng nợ vay trên 2.000 tỷ VNĐ, trong đó nợ ngắn hạn chiếm phần lớn. Chi phí lãi vay năm 2017 là 98.210.098.937 VNĐ, tạo áp lực thanh toán đáng kể. Nhiều khoản vay được đảm bảo bằng tài sản, làm giảm rủi ro tín dụng nhưng tăng rủi ro tài sản bị tịch thu nếu không trả nợ.', 'Hàng tồn kho bao gồm chi phí sản xuất dở dang lớn (hơn 813 tỷ VNĐ), chủ yếu liên quan đến các dự án bất động sản. Nếu dự án bị chậm tiến độ hoặc thị trường suy giảm, giá trị tồn kho có thể bị giảm, dẫn đến trích lập dự phòng. Tuy nhiên, công ty đã trích lập dự phòng cho một phần hàng tồn kho.', 6, 'Công ty có doanh thu và lợi nhuận tăng trưởng trong năm 2017, nhưng nợ vay cao và giao dịch với bên liên quan phức tạp. Khả năng thanh toán nợ ngắn hạn cần được theo dõi. Về quản trị, có sự thay đổi nhân sự cấp cao trong năm, và các giao dịch với công ty liên kết có thể tiềm ẩn xung đột lợi ích. Điểm rủi ro quản trị ở mức trung bình, cần cải thiện tính minh bạch và kiểm soát giao dịch nội bộ.'),
('XMC_2017_parent', 'XMC', 2017, 'parent', 'Doanh nghiệp có mạng lưới giao dịch phức tạp và lớn với các công ty con và liên kết, bao gồm mua bán hàng hóa/dịch vụ, cho vay, góp vốn và thanh lý tài sản. Đặc biệt, có khoản cho vay Công ty CP Cơ điện Xuân Mai với lãi suất chỉ 1%/năm, thấp hơn nhiều so với lãi suất thị trường, có thể tiềm ẩn rủi ro về giá chuyển nhượng không phản ánh đúng giá trị thị trường hoặc lợi ích kinh tế không được tối ưu cho cổ đông thiểu số.', 'Doanh nghiệp có đòn bẩy tài chính rất cao với tổng nợ vay và nợ thuê tài chính lên đến hơn 1,914 tỷ VND, chiếm tỷ trọng lớn trong tổng tài sản. Chi phí lãi vay chiếm phần lớn chi phí tài chính (88.9 tỷ VND năm 2017), tạo áp lực lớn lên dòng tiền hoạt động. Tuy nhiên, phần lớn nợ vay có tài sản đảm bảo (bất động sản, quyền phát sinh từ dự án) và doanh nghiệp duy trì được khả năng trả nợ. Nợ trái phiếu đáo hạn năm 2021 là một điểm cần lưu ý.', 'Hàng tồn kho chủ yếu là chi phí sản xuất kinh doanh dở dang, liên quan trực tiếp đến việc triển khai các dự án bất động sản (chung cư, khu đô thị). Giá trị tồn kho lớn và không có dự phòng giảm giá, tiềm ẩn rủi ro nếu dự án bị chậm tiến độ, thị trường bất động sản suy giảm hoặc chi phí phát sinh vượt dự toán.', 6, 'Doanh nghiệp hoạt động chủ yếu trong lĩnh vực xây dựng và kinh doanh bất động sản, ghi nhận tăng trưởng doanh thu và lợi nhuận năm 2017. Tuy nhiên, tình hình tài chính tiềm ẩn nhiều rủi ro: (1) Đòn bẩy tài chính cao, phụ thuộc lớn vào vốn vay và trái phiếu; (2) Mạng lưới giao dịch với bên liên quan phức tạp, có các khoản vay ưu đãi lãi suất thấp; (3) Hàng tồn kho lớn là chi phí dở dang, phụ thuộc vào tiến độ dự án. Điểm mạnh là doanh nghiệp có tài sản đảm bảo tốt cho các khoản vay và duy trì được dòng tiền từ hoạt động kinh doanh. Triển vọng phụ thuộc vào khả năng quản lý nợ, tiến độ triển khai dự án và biến động của thị trường bất động sản.'),
('XMC_2016_parent', 'XMC', 2016, 'parent', 'Công ty có giao dịch mua bán hàng hóa và dịch vụ lớn với các công ty con, tổng mua vào 949 tỷ và bán ra 452 tỷ. Đầu tư vào 2 công ty liên kết (Bê tông Xuân Mai Miền Nam và Xuân Mai Đà Nẵng) bị lỗ nặng với dự phòng giảm giá 64.9 tỷ, chiếm tỷ trọng lớn trong tổng đầu tư. Công ty cũng cho vay các công ty con và liên kết với tổng dư nợ cho vay nội bộ khoảng 90 tỷ. Giao dịch nội bộ lớn có thể ảnh hưởng đến tính minh bạch tài chính.', 'Tổng nợ vay và nợ thuê tài chính là 1,684 tỷ VNĐ, trong đó nợ ngắn hạn 870 tỷ và nợ dài hạn 813 tỷ. Tỷ lệ nợ/vốn chủ sở hữu rất cao (6.98 lần). Chi phí lãi vay năm 2016 là 84.3 tỷ VNĐ. Một số tài sản cố định hữu hình (nguyên giá 38.1 tỷ) đã được thế chấp cho vay ngân hàng. Áp lực trả nợ ngắn hạn lớn, cần theo dõi khả năng tái cơ cấu nợ.', 'Hàng tồn kho có giá trị 850.7 tỷ, phần lớn là chi phí sản xuất kinh doanh dở dang (849.2 tỷ). Tài sản dở dang dài hạn 67.4 tỷ bao gồm dự án chung cư và dây chuyền sản xuất. Công ty đánh giá thận trọng nhưng không trích lập dự phòng, cho thấy có rủi ro nếu các dự án không được triển khai hoặc chuyển nhượng thành công.', 7, 'Công ty Xuân Mai có doanh thu tăng trưởng mạnh 37.9% so với năm trước, đạt 2,434 tỷ. Biên lợi nhuận gộp 9.57%. Lợi nhuận sau thuế 47.3 tỷ, tăng 54.2%. Tuy nhiên, công ty có tỷ lệ đòn bẩy tài chính rất cao với nợ vay gấp gần 7 lần vốn chủ sở hữu. Chi phí lãi vay chiếm tỷ trọng lớn trong cơ cấu chi phí. Giao dịch với bên liên quan phức tạp, đầu tư vào công ty liên kết lỗ nặng. Hàng tồn kho dở dang lớn, chưa trích lập dự phòng. Rủi ro thanh khoản đáng lo ngại do nợ ngắn hạn lớn. Triển vọng phụ thuộc vào khả năng thu hồi công nợ, triển khai dự án bất động sản và quản lý dòng tiền.'),
('XLV_2025_consolidated', 'XLV', 2025, 'consolidated', 'Công ty có giao dịch cho vay không lãi suất với công ty liên kết và tạm ứng cho các thành viên quản lý, cho thấy rủi ro về giao dịch bên liên quan có thể ảnh hưởng đến lợi ích công ty.', 'Nợ vay chủ yếu là ngắn hạn và không có lãi suất từ bên liên quan, áp lực nợ vay thấp, nhưng phụ thuộc vào nguồn vốn từ công ty liên kết.', 'Hàng tồn kho bao gồm chi phí sản xuất kinh doanh dở dang lớn, có thể bị ứ đọng nếu các dự án xây dựng chậm tiến độ hoặc gặp khó khăn.', 6, 'Công ty có kết quả kinh doanh ổn định với lợi nhuận sau thuế tăng trưởng, nhưng phụ thuộc vào giao dịch bên liên quan và có lượng hàng tồn kho dở dang lớn, cần theo dõi tiến độ dự án và quản trị rủi ro.'),
('YBM_2017_consolidated', 'YBM', 2017, 'consolidated', 'Doanh nghiệp có giao dịch thương mại lớn với Công ty Cổ phần Nhựa Châu Âu (bán hàng, mua nguyên liệu), công ty này cũng là cổ đông lớn và bảo lãnh cho các khoản vay. Các giao dịch này có vẻ bình thường, không có dấu hiệu bất thường rõ ràng về giá hay lãi suất. Tuy nhiên, mức độ tập trung vào một bên liên quan là đáng lưu ý.', 'Áp lực nợ vay tương đối cao, tổng nợ vay và thuê tài chính lên tới hơn 1119 tỷ VNĐ. Công ty phụ thuộc lớn vào nguồn vốn vay ngân hàng và thuê tài chính để tài trợ cho hoạt động đầu tư, xây dựng. Tuy nhiên, dòng tiền từ hoạt động kinh doanh trong năm là âm (-31.524.494.480 VND), cho thấy áp lực thanh toán ngắn hạn. Nhiều khoản vay và thuê tài chính được đảm bảo bằng quyền khai thác khoáng sản, vốn góp của bên liên quan và tài sản hình thành từ dự án.', 'Tồn kho tăng mạnh từ 8.949 tỷ lên 43.381 tỷ VNĐ, chủ yếu do nguyên vật liệu và thành phẩm. Dự án xây dựng dở dang (XDCB dở dang) cũng tăng đáng kể (21.613 tỷ). Rủi ro tồn kho thấp vì chưa trích lập dự phòng giảm giá. Các dự án xây dựng dở dang đang trong giai đoạn triển khai đầu tư mạnh (Giai đoạn 3) nên chưa có dấu hiệu ứ đọng, nhưng cần giám sát tiến độ và hiệu quả.', 5, 'Công ty đang trong giai đoạn tăng trưởng mạnh về quy mô với doanh thu năm 2017 đạt 220 tỷ, lợi nhuận gộp biên cao (~41.3%). Tuy nhiên, tăng trưởng này được tài trợ chủ yếu bằng nợ vay, dẫn đến rủi ro đòn bẩy tài chính cao. Dòng tiền hoạt động kinh doanh âm do đầu tư mạnh vào hàng tồn kho và các khoản phải thu. Công ty có mối quan hệ thương mại lớn với cổ đông lớn (Nhựa Châu Âu). Các dự án đầu tư xây dựng (Nhà máy giai đoạn 3, khai thác mỏ mới) đang triển khai, hứa hẹn tăng trưởng tương lai nhưng đòi hỏi nguồn vốn lớn và quản lý hiệu quả. Doanh nghiệp đang được hưởng ưu đãi thuế TNDN. Triển vọng phụ thuộc vào khả năng quản lý nợ, tiến độ dự án và duy trì quan hệ khách hàng.'),
('XMC_2016_consolidated', 'XMC', 2016, 'consolidated', 'Công ty có nhiều giao dịch với các công ty liên kết: doanh thu bán hàng cho Đô thị Sơn An 63.1 tỷ, mua hàng từ Bê tông Xuân Mai Miền Nam 8.2 tỷ. Cho vay Bê tông Xuân Mai Miền Nam 11 tỷ và Xuân Mai Đà Nẵng 500 triệu. Phải thu khách hàng là các công ty liên kết lên tới 39.4 tỷ. Đầu tư vào công ty liên kết có dự phòng giảm giá lớn (Bê tông Xuân Mai Miền Nam 40.4 tỷ, Xuân Mai Đà Nẵng 24.5 tỷ). Tuy nhiên, các giao dịch này nằm trong hoạt động kinh doanh thông thường của doanh nghiệp xây dựng và bất động sản, chưa phát hiện dấu hiệu giao dịch bất thường rõ ràng.', 'Tổng nợ vay và nợ thuê tài chính là 1,259 tỷ VNĐ, trong đó nợ ngắn hạn chiếm 1,027 tỷ (82%). Tỷ lệ nợ phải trả/vốn chủ sở hữu xấp xỉ 6.3:1, đòn bẩy tài chính rất cao. Chi phí lãi vay năm 2016 là 96.6 tỷ VNĐ. Nhiều khoản vay được đảm bảo bằng tài sản cố định, bất động sản đầu tư và quyền phát triển dự án. Có trái phiếu 492.9 tỷ đáo hạn năm 2021. Áp lực trả nợ ngắn hạn lớn, dòng tiền hoạt động kinh doanh thuần 184.6 tỷ chưa đủ bù đắp toàn bộ nghĩa vụ nợ.', 'Hàng tồn kho 1,007 tỷ VNĐ, chủ yếu là chi phí sản xuất kinh doanh dở dang (922 tỷ, chiếm 91.5%) liên quan đến các dự án bất động sản. Ngoài ra có tài sản dở dang dài hạn 70.9 tỷ bao gồm dự án Nhà 11T2, 19T2 Chung cư và chi phí chung các khu. Ban lãnh đạo đánh giá thận trọng và tin tưởng không cần trích lập dự phòng. Rủi ro tồn kho phụ thuộc lớn vào khả năng tiêu thụ sản phẩm bất động sản và tiến độ triển khai dự án.', 4, 'Công ty Cổ phần Đầu tư và Xây dựng Xuân Mai có kết quả kinh doanh tăng trưởng mạnh năm 2016: doanh thu thuần tăng 31% đạt 2,169 tỷ VNĐ, lợi nhuận sau thuế Công ty mẹ tăng 51% đạt 69.8 tỷ VNĐ, LNST/CPS tăng từ 1,402 lên 2,327 đồng. Tuy nhiên, công ty có đòn bẩy tài chính rất cao (nợ phải trả 2,705 tỷ vs vốn chủ sở hữu 427 tỷ), tỷ lệ nợ ngắn hạn/lợi nhuận gộp cao tạo áp lực thanh khoản. Hàng tồn kho dở dang chiếm tỷ trọng lớn, cần theo dõi khả năng tiêu thụ. Công ty có hệ sinh thái 7 công ty con và 3 công ty liên kết, giao dịch nội bộ phức tạp. Điểm tích cực là dòng tiền hoạt động kinh doanh chuyển từ âm 649 tỷ (2015) sang dương 185 tỷ (2016). Triển vọng trung bình, cần theo dõi tiến độ dự án bất động sản và khả năng quản lý dòng tiền trả nợ.'),
('XLV_2023_consolidated', 'XLV', 2023, 'consolidated', 'Doanh nghiệp có giao dịch tạm ứng lớn với các thành viên quản lý chủ chốt, với tổng tạm ứng năm nay hơn 12 tỷ đồng, cần đánh giá rủi ro về khả năng thu hồi và tính minh bạch của giao dịch.', 'Công ty đã trả hết nợ vay ngắn hạn, giảm áp lực nợ. Tuy nhiên, các khoản phải trả người bán vẫn còn ở mức cao (24.6 tỷ đồng), cần theo dõi khả năng thanh toán.', 'Hàng tồn kho chủ yếu là chi phí xây dựng dở dang (hơn 11.6 tỷ đồng), bao gồm nhiều dự án xây dựng. Rủi ro là các dự án có thể bị chậm tiến độ hoặc khó chuyển hóa thành doanh thu.', 5, 'Doanh thu và lợi nhuận giảm mạnh so với năm trước, cho thấy hiệu quả kinh doanh giảm. Công ty đã cải thiện cấu trúc vốn bằng cách trả nợ vay. Tuy nhiên, rủi ro từ tồn kho dở dang và giao dịch với bên liên quan cần được kiểm soát.');
PRAGMA foreign_keys = ON;
